// 🌌 GALAXIES — Arènes de mise (winner-takes-all)
// Chaque galaxie a une mise unique fixe. Plus elle est prestigieuse,
// plus l'enjeu est élevé. Le gagnant rafle la mise de l'adversaire.
// ════════════════════════════════════════════════════════
const GALAXIES = [
  { id:"voie_lactee", name:"Voie Lactée",  stake:10,   color:"#8ab4ff", glow:"#4a9eff",
    desc:"L'arène des novices. Faites vos premières armes." },
  { id:"andromede",   name:"Andromède",    stake:50,   color:"#b18aff", glow:"#7c4dff",
    desc:"Pour les joueurs aguerris en quête de défi." },
  { id:"sombrero",    name:"Sombrero",     stake:150,  color:"#ffc864", glow:"#ff9d2f",
    desc:"Galaxie élégante aux enjeux relevés." },
  { id:"tourbillon",  name:"Tourbillon",   stake:500,  color:"#5affc8", glow:"#00d4aa",
    desc:"Le maelström des experts. Gros risque, gros gain." },
  { id:"cigare",      name:"Cigare",       stake:1500, color:"#ff6b9d", glow:"#ff2d6f",
    desc:"L'antre de l'élite. Réservée aux légendes stellaires." },
];
const getGalaxy = (id) => GALAXIES.find(g=>g.id===id) || GALAXIES[0];

// ════════════════════════════════════════════════════════
// 🪐 PLANÈTES — Paliers de prestige (gravitent autour de l'avatar)
// Débloquées en atteignant des seuils d'étoiles cumulées gagnées.
// ════════════════════════════════════════════════════════
const PLANETS = [
  { id:"mercure", name:"Mercure", threshold:0,     color:"#b0a89a", size:5 },
  { id:"venus",   name:"Vénus",   threshold:250,   color:"#e8c87a", size:6 },
  { id:"terre",   name:"Terre",   threshold:750,   color:"#4a9eff", size:6.5 },
  { id:"mars",    name:"Mars",    threshold:1500,  color:"#e0613a", size:6 },
  { id:"jupiter", name:"Jupiter", threshold:3500,  color:"#d8a26a", size:9 },
  { id:"saturne", name:"Saturne", threshold:7000,  color:"#e8d49a", size:8, ring:true },
  { id:"uranus",  name:"Uranus",  threshold:13000, color:"#7ad0e0", size:7 },
  { id:"neptune", name:"Neptune", threshold:25000, color:"#3a6ad8", size:7 },
];
// Étoiles cumulées gagnées (lifetime) → planètes débloquées
const getUnlockedPlanets = (lifetimeStars) =>
  PLANETS.filter(p => (lifetimeStars||0) >= p.threshold);
const getCurrentPlanet = (lifetimeStars) => {
  const u = getUnlockedPlanets(lifetimeStars);
  return u[u.length-1] || PLANETS[0];
};
const getNextPlanet = (lifetimeStars) =>
  PLANETS.find(p => (lifetimeStars||0) < p.threshold) || null;

// ════════════════════════════════════════════════════════
// 👤 AVATARS — Débloqués en franchissant les planètes
// ════════════════════════════════════════════════════════
const AVATARS = [
  { id:"explorateur", name:"Explorateur", planet:"mercure", emoji:"🧑‍🚀", color:"#8ab4ff" },
  { id:"pilote",      name:"Pilote",      planet:"venus",   emoji:"👨‍✈️", color:"#e8c87a" },
  { id:"navigatrice", name:"Navigatrice", planet:"terre",   emoji:"👩‍🚀", color:"#4a9eff" },
  { id:"commandant",  name:"Commandant",  planet:"mars",    emoji:"🫡",   color:"#e0613a" },
  { id:"savant",      name:"Savant",      planet:"jupiter", emoji:"🧑‍🔬", color:"#d8a26a" },
  { id:"amiral",      name:"Amiral",      planet:"saturne", emoji:"⭐",   color:"#e8d49a" },
  { id:"oracle",      name:"Oracle",      planet:"uranus",  emoji:"🔮",   color:"#7ad0e0" },
  { id:"legende",     name:"Légende",     planet:"neptune", emoji:"👑",   color:"#3a6ad8" },
];
const getUnlockedAvatars = (lifetimeStars) => {
  const planets = getUnlockedPlanets(lifetimeStars).map(p=>p.id);
  return AVATARS.filter(a => planets.includes(a.planet));
};

