// Résoudre un texte traduit ; repli sur le français puis sur l'id
const tEcon = (category, id, lang) => {
  const cat = ECON_I18N[category];
  if (!cat || !cat[id]) return id;
  return cat[id][lang] || cat[id].fr || id;
};
const galaxyName  = (id, lang) => tEcon("galaxyName", id, lang);
const galaxyDesc  = (id, lang) => tEcon("galaxyDesc", id, lang);
const planetName  = (id, lang) => tEcon("planetName", id, lang);
const avatarName  = (id, lang) => tEcon("avatarName", id, lang);
const econUI = (key, lang) => { const u=ECON_I18N.ui[key]; return u?(u[lang]||u.fr):key; };

