// Traduit un libellé FR vers la langue active ; repli sur le FR original
const tUI = (frText, lang) => {
  if (lang === "fr" || !lang) return frText;
  const entry = UI_I18N[frText];
  return entry ? (entry[lang] || frText) : frText;
};

const SEASON_KEY = "dosco_season_v1";
const SEASON_WEEK_MS = 7 * 24 * 60 * 60 * 1000;

const getSeasonData = () => {
  try {
    const raw = localStorage.getItem(SEASON_KEY);
    if (!raw) return null;
    return JSON.parse(raw);
  } catch { return null; }
};

// ── DÉTECTION AUTOMATIQUE DU PAYS ──
// Déduit le pays du joueur à l'inscription, sans demande explicite, à partir de la
// locale et du fuseau horaire du navigateur (heuristique fiable hors-ligne ; en
// production, le serveur peut l'affiner via géo-IP).
const COUNTRY_NAMES = {
  CI:"Côte d'Ivoire", FR:"France", SN:"Sénégal", CM:"Cameroun", MA:"Maroc",
  DZ:"Algérie", TN:"Tunisie", BE:"Belgique", CH:"Suisse", CA:"Canada",
  US:"États-Unis", GB:"Royaume-Uni", ES:"Espagne", PT:"Portugal", BR:"Brésil",
  DE:"Allemagne", IT:"Italie", NG:"Nigeria", GH:"Ghana", ML:"Mali",
  BF:"Burkina Faso", BJ:"Bénin", TG:"Togo", GA:"Gabon", CD:"RD Congo",
  CG:"Congo", NE:"Niger", GN:"Guinée", MX:"Mexique", AR:"Argentine", SA:"Arabie Saoudite",
  EG:"Égypte", AE:"Émirats", JP:"Japon", CN:"Chine", IN:"Inde", RU:"Russie",
};
const COUNTRY_FLAGS = {
  CI:"🇨🇮",FR:"🇫🇷",SN:"🇸🇳",CM:"🇨🇲",MA:"🇲🇦",DZ:"🇩🇿",TN:"🇹🇳",BE:"🇧🇪",CH:"🇨🇭",CA:"🇨🇦",
  US:"🇺🇸",GB:"🇬🇧",ES:"🇪🇸",PT:"🇵🇹",BR:"🇧🇷",DE:"🇩🇪",IT:"🇮🇹",NG:"🇳🇬",GH:"🇬🇭",ML:"🇲🇱",
  BF:"🇧🇫",BJ:"🇧🇯",TG:"🇹🇬",GA:"🇬🇦",CD:"🇨🇩",CG:"🇨🇬",NE:"🇳🇪",GN:"🇬🇳",MX:"🇲🇽",AR:"🇦🇷",
  SA:"🇸🇦",EG:"🇪🇬",AE:"🇦🇪",JP:"🇯🇵",CN:"🇨🇳",IN:"🇮🇳",RU:"🇷🇺",XX:"🏳️",
};
const TZ_COUNTRY = {
  "Africa/Abidjan":"CI","Africa/Dakar":"SN","Africa/Douala":"CM","Africa/Casablanca":"MA",
  "Africa/Algiers":"DZ","Africa/Tunis":"TN","Africa/Lagos":"NG","Africa/Accra":"GH",
  "Africa/Bamako":"ML","Africa/Ouagadougou":"BF","Africa/Porto-Novo":"BJ","Africa/Lome":"TG",
  "Africa/Libreville":"GA","Africa/Kinshasa":"CD","Africa/Brazzaville":"CG","Africa/Niamey":"NE",
  "Africa/Conakry":"GN","Africa/Cairo":"EG","Europe/Paris":"FR","Europe/Brussels":"BE",
  "Europe/Zurich":"CH","Europe/Madrid":"ES","Europe/Lisbon":"PT","Europe/Berlin":"DE",
  "Europe/Rome":"IT","Europe/London":"GB","Europe/Moscow":"RU","America/New_York":"US",
  "America/Toronto":"CA","America/Sao_Paulo":"BR","America/Mexico_City":"MX",
  "America/Argentina/Buenos_Aires":"AR","Asia/Riyadh":"SA","Asia/Dubai":"AE",
  "Asia/Tokyo":"JP","Asia/Shanghai":"CN","Asia/Kolkata":"IN",
};
const detectCountry = () => {
  try {
    const tz = Intl.DateTimeFormat().resolvedOptions().timeZone;
    if (tz && TZ_COUNTRY[tz]) return TZ_COUNTRY[tz];
    const loc = (navigator.language || "en-XX");
    const region = loc.split("-")[1];
    if (region && COUNTRY_NAMES[region.toUpperCase()]) return region.toUpperCase();
    // Repli sur la langue → pays par défaut
    const lang = loc.split("-")[0].toLowerCase();
    const byLang = { fr:"FR", en:"US", es:"ES", pt:"BR", ar:"SA" };
    return byLang[lang] || "XX";
  } catch { return "XX"; }
};
const countryName = (code) => COUNTRY_NAMES[code] || "International";
const countryFlag = (code) => COUNTRY_FLAGS[code] || "🏳️";


const initSeason = () => {
  const now = Date.now();
  const data = {
    weekStart: now,
    pts: 100,            // Points de CLASSEMENT (reset hebdo, aucune valeur monétaire)
    stars: 100,          // ÉTOILES de mise (achat + mises gagnées) — JAMAIS reset
    lifetimeStars: 100,  // Cumul d'étoiles gagnées (ne descend jamais) → débloque les planètes
    avatar: "explorateur",
    country: detectCountry(),   // pays détecté automatiquement à l'inscription
    wins: 0, losses: 0, winStreak: 0, bestStreak: 0,
    totalGames: 0,
    // Compteurs pour les succès (achievements)
    infiltrationWins: 0,   // victoires par infiltration
    eliminationWins: 0,    // victoires par élimination
    fastWins: 0,           // victoires en moins de 15 coups
    aiSupernovaWins: 0,    // victoires contre l'IA Supernova+
    history: [],
  };
  localStorage.setItem(SEASON_KEY, JSON.stringify(data));
  return data;
};

const getSeason = () => {
  let data = getSeasonData();
  if (!data) return initSeason();
  // Migration des champs (anciennes sauvegardes)
  if (data.stars === undefined) data.stars = data.pts || 100;
  if (data.totalGames === undefined) data.totalGames = (data.wins||0)+(data.losses||0);
  if (data.lifetimeStars === undefined) data.lifetimeStars = data.stars || 100;
  if (data.avatar === undefined) data.avatar = "explorateur";
  if (data.country === undefined) data.country = detectCountry();
  if (data.infiltrationWins === undefined) data.infiltrationWins = 0;
  if (data.eliminationWins === undefined) data.eliminationWins = 0;
  if (data.fastWins === undefined) data.fastWins = 0;
  if (data.aiSupernovaWins === undefined) data.aiSupernovaWins = 0;
  // Vérifier si la semaine est écoulée → reset DU CLASSEMENT uniquement
  if (Date.now() - data.weekStart > SEASON_WEEK_MS) {
    const oldPts = data.pts;
    const keptStars = data.stars;  // les étoiles sont conservées
    data = { ...initSeason(), stars: keptStars,
      history: [{date:Date.now(),result:"reset",pts:oldPts,vs:"SAISON"}] };
  }
  return data;
};

const updateSeason = (won, vsName="ADVERSAIRE", aiMode=false, winType="infiltration", stakeResult=0, meta={}) => {
  const data = getSeason();
  // ── POINTS DE CLASSEMENT ──
  // Les deux chemins de victoire (élimination et infiltration) sont STRICTEMENT
  // ÉQUIVALENTS : aucun bonus ×2. Le gain est déterminé uniquement par la mise de la
  // galaxie. Les parties contre l'IA ne comptent JAMAIS dans le classement.
  const ranked = !aiMode; // seules les parties humaines (en ligne) sont classées
  // Points de classement = mise de la galaxie (gain si victoire, perte si défaite)
  const stakeMagnitude = Math.abs(stakeResult) || 0;
  const basePts = ranked ? (won ? stakeMagnitude : -Math.ceil(stakeMagnitude/2)) : 0;
  const bonusStreak = ranked && won && data.winStreak >= 4 ? Math.ceil(stakeMagnitude*0.2) : 0;
  const totalPts = basePts + bonusStreak;
  if (ranked) data.pts = Math.max(0, data.pts + totalPts);

  // ── ÉTOILES DE MISE : variation = résultat de la mise (winner-takes-all) ──
  if (stakeResult !== 0) {
    data.stars = Math.max(0, (data.stars || 0) + stakeResult);
    if (stakeResult > 0) data.lifetimeStars = (data.lifetimeStars || 0) + stakeResult;
  }
  // Statistiques de parties : seules les parties classées (humaines) comptent
  if (ranked) {
    data.totalGames = (data.totalGames || 0) + 1;
    if (won) {
      data.wins++; data.winStreak++; data.bestStreak = Math.max(data.bestStreak, data.winStreak);
      if (winType === "infiltration") data.infiltrationWins = (data.infiltrationWins||0) + 1;
      if (winType === "elimination")  data.eliminationWins  = (data.eliminationWins||0) + 1;
      if (meta.moves && meta.moves < 15) data.fastWins = (data.fastWins||0) + 1;
    } else { data.losses++; data.winStreak = 0; }
    data.history = [{date:Date.now(),result:won?"win":"loss",pts:totalPts,stars:stakeResult,vs:vsName,type:winType}, ...data.history.slice(0,19)];
  } else {
    // Parties contre l'IA : on suit séparément, hors classement
    data.aiGames = (data.aiGames||0) + 1;
    if (won && aiMode && (meta.aiDiff === "n6" || meta.aiDiff === "n7")) data.aiSupernovaWins = (data.aiSupernovaWins||0) + 1;
  }
  localStorage.setItem(SEASON_KEY, JSON.stringify(data));
  analytics.track("game_end",{result:won?"win":"loss",vs:vsName,pts:totalPts,stakeResult,winType,ranked});
  return { pts: totalPts, stars: stakeResult, bonusStreak, total: data.pts, totalStars: data.stars, ranked };
};

// Créditer/débiter des étoiles de mise directement (résultat d'une partie en galaxie)
const applyStakeResult = (delta) => {
  const data = getSeason();
  data.stars = Math.max(0, (data.stars || 0) + delta);
  if (delta > 0) data.lifetimeStars = (data.lifetimeStars || 0) + delta;
  localStorage.setItem(SEASON_KEY, JSON.stringify(data));
  return { stars: data.stars, lifetimeStars: data.lifetimeStars };
};

// Changer l'avatar (si débloqué)
const setAvatar = (avatarId) => {
  const data = getSeason();
  data.avatar = avatarId;
  localStorage.setItem(SEASON_KEY, JSON.stringify(data));
  return data;
};

const timeUntilReset = () => {
  const data = getSeasonData();
  if (!data) return 0;
  const remaining = SEASON_WEEK_MS - (Date.now() - data.weekStart);
  const d = Math.floor(remaining / 86400000);
  const h = Math.floor((remaining % 86400000) / 3600000);
  const m = Math.floor((remaining % 3600000) / 60000);
  return `${d}j ${h}h ${m}m`;
};


// ════════════════════════════════════════════════════════
// 🔐 SYSTÈME D'AUTHENTIFICATION PERSISTANT
// Simule Supabase/Firebase Auth avec localStorage
// En production : remplacer par supabase.auth.signIn()
// ════════════════════════════════════════════════════════
const AUTH_KEY = "dosco_auth_v1";
const USERS_KEY = "dosco_users_v1";

const authDB = {
  getUsers: () => { try { return JSON.parse(localStorage.getItem(USERS_KEY)||"{}"); } catch{return{};} },
  saveUsers: (u) => { try { localStorage.setItem(USERS_KEY, JSON.stringify(u)); } catch{} },
  getSession: () => { try { return JSON.parse(localStorage.getItem(AUTH_KEY)||"null"); } catch{return null;} },
  saveSession: (s) => { try { localStorage.setItem(AUTH_KEY, JSON.stringify(s)); } catch{} },
  clearSession: () => { try { localStorage.removeItem(AUTH_KEY); } catch{} },
};

const authRegister = (name, email, password) => {
  const users = authDB.getUsers();
  const uname = (name||"").trim();
  const unameKey = "@" + uname.toLowerCase();
  if (email && users[email]) return { error: "Email déjà utilisé." };
  if (uname && users[unameKey]) return { error: "Ce pseudo est déjà pris." };
  const uid = "usr_" + Date.now() + "_" + Math.random().toString(36).slice(2,6);
  const user = { uid, name: uname.toUpperCase().slice(0,14), email: email||"", createdAt: Date.now(),
    pts: 100, wins: 0, losses: 0, winStreak: 0, bestStreak: 0, xp: 0,
    skinId: "classic", themeId: "cosmos", isGuest: !password };
  const record = { uid, passwordHash: btoa(password||""), name: user.name, email: email||"" };
  // Indexer par email ET par pseudo pour permettre la connexion avec l'un ou l'autre
  if (email) users[email] = record;
  if (uname) users[unameKey] = record;
  authDB.saveUsers(users);
  const session = { ...user, token: btoa(uid + Date.now()) };
  authDB.saveSession(session);
  return { user: session };
};

// Connexion par email OU pseudo + mot de passe
const authLogin = (identifier, password) => {
  const users = authDB.getUsers();
  const id = (identifier||"").trim();
  // Chercher par email direct, sinon par pseudo (clé @pseudo en minuscules)
  let record = users[id] || users["@" + id.toLowerCase()];
  if (!record) return { error: "Compte introuvable. Vérifiez le pseudo/email." };
  if (record.passwordHash !== btoa(password||"")) return { error: "Mot de passe incorrect." };
  const uid = record.uid;
  const seasonData = (() => { try { return JSON.parse(localStorage.getItem("dosco_season_" + uid)||"null"); } catch{return null;} })();
  const nm = record.name || (record.email? record.email.split("@")[0].toUpperCase() : id.toUpperCase());
  const user = seasonData ? { uid, email: record.email||"", name: seasonData.name||nm,
    pts: seasonData.pts||100, wins: seasonData.wins||0, losses: seasonData.losses||0,
    winStreak: seasonData.winStreak||0, bestStreak: seasonData.bestStreak||0 }
    : { uid, email: record.email||"", name: nm, pts:100, wins:0, losses:0, winStreak:0, bestStreak:0 };
  const session = { ...user, token: btoa(uid + Date.now()) };
  authDB.saveSession(session);
  return { user: session };
};

// Connexion via fournisseur OAuth (Google / Facebook). En production, le jeton OAuth
// est vérifié côté serveur ; ici on crée/retrouve un compte lié au fournisseur.
const authOAuthLogin = (provider, profile) => {
  const users = authDB.getUsers();
  // En l'absence d'un vrai SDK OAuth (HTML autonome), on génère une identité STABLE
  // par fournisseur et par appareil, persistée localement : la reconnexion via le même
  // bouton retrouve le même compte. En production mobile, le profil vérifié du
  // fournisseur (email réel) remplacera cette identité.
  const devKey = "dosco_oauth_" + provider;
  let email = (profile && profile.email) ? profile.email : null;
  if (!email) {
    try { email = localStorage.getItem(devKey); } catch {}
    if (!email) {
      email = provider + "_" + Math.random().toString(36).slice(2,8) + "@dosco.app";
      try { localStorage.setItem(devKey, email); } catch {}
    }
  }
  const dispName = (profile && profile.name) ? profile.name
    : (provider==="google"?"GOOGLE_":"FB_") + email.split("@")[0].split("_").pop().toUpperCase().slice(0,8);
  let record = users[email];
  if (!record) {
    const uid = "usr_" + Date.now() + "_" + Math.random().toString(36).slice(2,6);
    record = { uid, passwordHash: "", name: dispName.toUpperCase().slice(0,14), email, provider };
    users[email] = record;
    users["@" + record.name.toLowerCase()] = record;
    authDB.saveUsers(users);
  }
  const uid = record.uid;
  const seasonData = (() => { try { return JSON.parse(localStorage.getItem("dosco_season_" + uid)||"null"); } catch{return null;} })();
  const user = { uid, email, name: (seasonData&&seasonData.name)||record.name,
    pts: seasonData?.pts??100, wins: seasonData?.wins??0, losses: seasonData?.losses??0,
    winStreak: seasonData?.winStreak??0, bestStreak: seasonData?.bestStreak??0, provider, country: seasonData?.country||detectCountry() };
  const session = { ...user, token: btoa(uid + Date.now()) };
  authDB.saveSession(session);
  return { user: session };
};

const authGuestLogin = () => {
  const name = "GUEST_" + Math.random().toString(36).slice(2,6).toUpperCase();
  return authRegister(name, "", "");
};

const authLogout = () => { authDB.clearSession(); };

// Persister les stats saison liées à l'uid
const saveUserStats = (uid, data) => {
  try { localStorage.setItem("dosco_season_" + uid, JSON.stringify(data)); } catch{}
};

