// 💳 SYSTÈME IAP (In-App Purchase)
// Simule Google Play Billing / Apple IAP
// En production : expo-in-app-purchases + backend validation
// ════════════════════════════════════════════════════════
const IAP_PRODUCTS = {
  "dosco.starter":   { id:"dosco.starter",   stars:100, bonus:0,   price:0.99,  label:"Starter"     },
  "dosco.explorer":  { id:"dosco.explorer",  stars:300, bonus:50,  price:1.99,  label:"Explorateur"  },
  "dosco.champion":  { id:"dosco.champion",  stars:700, bonus:150, price:3.99,  label:"Champion"     },
  "dosco.legend":    { id:"dosco.legend",    stars:1500,bonus:500, price:7.99,  label:"Légende"      },
  "dosco.pass":      { id:"dosco.pass",      stars:200, bonus:0,   price:2.99,  label:"Passe Saison" },
};

const IAP_RECEIPTS_KEY = "dosco_receipts_v1";

// ── Vérification d'âge & consentement (conformité COPPA/RGPD) ──
const FIRST_RUN_KEY = "dosco_tutorial_seen_v1";
const hasSeenTutorial = () => { try { return localStorage.getItem(FIRST_RUN_KEY)==="1"; } catch(e) { return false; } };
const markTutorialSeen = () => { try { localStorage.setItem(FIRST_RUN_KEY,"1"); } catch(e) {} };
const SAVED_GAME_KEY = "dosco_saved_game_v1";
// Sauvegarde de la partie en cours (reprise après fermeture)
const saveGameState = (state) => {
  try { localStorage.setItem(SAVED_GAME_KEY, JSON.stringify({...state, savedAt: Date.now()})); } catch(e) {}
};
const loadGameState = () => {
  try { return JSON.parse(localStorage.getItem(SAVED_GAME_KEY) || "null"); } catch(e) { return null; }
};
const clearGameState = () => {
  try { localStorage.removeItem(SAVED_GAME_KEY); } catch(e) {}
};

const CONSENT_KEY = "dosco_consent_v1";
const getConsent = () => {
  try { return JSON.parse(localStorage.getItem(CONSENT_KEY) || "null"); }
  catch(e) { return null; }
};
const setConsent = (data) => {
  try { localStorage.setItem(CONSENT_KEY, JSON.stringify({...data, ts: Date.now()})); } catch(e) {}
};

const _persistReceipt = (receipt) => {
  try {
    const receipts = JSON.parse(localStorage.getItem("dosco_receipts_v1") || "[]");
    receipts.push(receipt);
    localStorage.setItem("dosco_receipts_v1", JSON.stringify(receipts));
  } catch(e) {}
};

// ── Pont IAP natif (Capacitor / RevenueCat) ──
// Détecte si on tourne dans une app native avec plugin de billing
const isNativeApp = () => {
  try { return !!(window.Capacitor && window.Capacitor.isNativePlatform && window.Capacitor.isNativePlatform()); }
  catch(e) { return false; }
};

// Restauration des achats (OBLIGATOIRE pour Apple/Google)
const iapRestorePurchases = async (userUid) => {
  if (isNativeApp() && window.CdvPurchase) {
    try {
      const store = window.CdvPurchase.store;
      await store.restorePurchases();
      return { success: true, restored: true };
    } catch(e) { return { error: "Restauration échouée" }; }
  }
  // Fallback : recharger les reçus locaux
  try {
    const receipts = JSON.parse(localStorage.getItem("dosco_receipts_v1") || "[]");
    return { success: true, receipts, restored: receipts.length > 0 };
  } catch(e) { return { success: true, receipts: [], restored: false }; }
};

const iapPurchase = async (productId, userUid) => {
  const product = IAP_PRODUCTS[productId];
  if (!product) return { error: "Produit introuvable" };

  // ── Voie NATIVE (App Store / Google Play Billing) ──
  if (isNativeApp() && window.CdvPurchase) {
    try {
      const store = window.CdvPurchase.store;
      const offer = store.get(productId)?.getOffer();
      if (!offer) return { error: "Produit indisponible sur le store" };
      const order = await store.order(offer);
      if (order && order.isError) return { error: order.message || "Achat refusé" };
      // La validation du reçu se fait côté serveur via RevenueCat/votre backend
      const receipt = {
        receiptId: "native_" + Date.now(), productId, userUid,
        starsGranted: product.stars + product.bonus, price: product.price,
        platform: window.Capacitor.getPlatform(), ts: Date.now(),
      };
      _persistReceipt(receipt);
      return { success: true, receipt };
    } catch(e) {
      if (String(e).includes("cancel")) return { error: "Achat annulé" };
      return { error: "Erreur de paiement" };
    }
  }

  // ── Voie WEB (démo / aperçu navigateur uniquement) ──

  // Simuler latence réseau + validation
  await new Promise(r => setTimeout(r, 1200 + Math.random()*800));

  // Simuler 95% succès (5% annulation utilisateur)
  if (Math.random() < 0.05) return { error: "Achat annulé" };

  const receipt = {
    receiptId: "rcpt_" + Date.now(),
    productId,
    userUid,
    starsGranted: product.stars + product.bonus,
    price: product.price,
    ts: Date.now(),
  };

  // Sauvegarder le reçu
  try {
    const receipts = JSON.parse(localStorage.getItem(IAP_RECEIPTS_KEY)||"[]");
    receipts.unshift(receipt);
    localStorage.setItem(IAP_RECEIPTS_KEY, JSON.stringify(receipts.slice(0,50)));
  } catch {}

  // Créditer les ÉTOILES (monnaie permanente — pas les points de classement)
  const season = getSeason();
  season.stars = (season.stars||0) + receipt.starsGranted;
  localStorage.setItem("dosco_season_v1", JSON.stringify(season));

  return { success: true, receipt };
};

const iapGetReceipts = () => {
  try { return JSON.parse(localStorage.getItem(IAP_RECEIPTS_KEY)||"[]"); } catch { return []; }
};

// ════════════════════════════════════════════════════════
// 🔔 SYSTÈME DE NOTIFICATIONS PUSH (simulé)
// En production : expo-notifications + Expo Push API
// ════════════════════════════════════════════════════════
const NOTIF_KEY = "dosco_notifs_v1";
const NOTIF_PREFS_KEY = "dosco_notif_prefs_v1";

const notifSystem = {
  getPrefs: () => {
    try { return JSON.parse(localStorage.getItem(NOTIF_PREFS_KEY)||"null") || 
      { enabled:true, daily:true, tournament:true, challenge:true, streak:true }; }
    catch { return { enabled:true, daily:true, tournament:true, challenge:true, streak:true }; }
  },
  savePrefs: (p) => { try { localStorage.setItem(NOTIF_PREFS_KEY, JSON.stringify(p)); } catch{} },
  getAll: () => { try { return JSON.parse(localStorage.getItem(NOTIF_KEY)||"[]"); } catch{return[];} },
  add: (notif) => {
    try {
      const notifs = notifSystem.getAll();
      notifs.unshift({ id:"n_"+Date.now(), ...notif, ts:Date.now(), read:false });
      localStorage.setItem(NOTIF_KEY, JSON.stringify(notifs.slice(0,30)));
      // En prod : expo-notifications.scheduleNotificationAsync(...)
    } catch {}
  },
  markRead: (id) => {
    try {
      const notifs = notifSystem.getAll().map(n => n.id===id ? {...n,read:true} : n);
      localStorage.setItem(NOTIF_KEY, JSON.stringify(notifs));
    } catch {}
  },
  markAllRead: () => {
    try {
      const notifs = notifSystem.getAll().map(n => ({...n,read:true}));
      localStorage.setItem(NOTIF_KEY, JSON.stringify(notifs));
    } catch {}
  },
  unreadCount: () => notifSystem.getAll().filter(n=>!n.read).length,
};

// ════════════════════════════════════════════════════════
// 📅 RÉCOMPENSE DE CONNEXION QUOTIDIENNE
// ════════════════════════════════════════════════════════
const DAILY_KEY = "dosco_weekly_v1";
const DAILY_REWARD = 20; // étoiles de mise offertes / semaine (filet anti-frustration)

// Identifiant d'année-semaine ISO (ex. "2026-W25") pour comparer les semaines
const isoWeekId = (d=new Date()) => {
  const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
  const day = date.getUTCDay() || 7;            // lundi=1 … dimanche=7
  date.setUTCDate(date.getUTCDate() + 4 - day); // jeudi de la semaine courante
  const yearStart = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
  const week = Math.ceil((((date - yearStart) / 86400000) + 1) / 7);
  return `${date.getUTCFullYear()}-W${String(week).padStart(2,"0")}`;
};

const checkDailyReward = () => {
  try {
    const raw = localStorage.getItem(DAILY_KEY);
    const data = raw ? JSON.parse(raw) : null;
    const thisWeek = isoWeekId();
    if (data && data.lastWeek === thisWeek) return { alreadyClaimed: true, streak: data.streak||1 };
    const lastWeek = isoWeekId(new Date(Date.now()-7*86400000));
    const streak = (data && data.lastWeek === lastWeek) ? (data.streak||0)+1 : 1;
    // Le cadeau grandit avec la série hebdomadaire : 20 + 10 par semaine consécutive (plafonné à 100)
    const weeklyAmount = Math.min(DAILY_REWARD + (streak-1)*10, 100);
    const newData = { lastWeek: thisWeek, streak, totalClaimed: (data?.totalClaimed||0)+weeklyAmount };
    localStorage.setItem(DAILY_KEY, JSON.stringify(newData));
    // Créditer les étoiles de mise (permet de continuer à jouer en galaxie)
    const season = getSeason();
    season.stars = (season.stars||0) + weeklyAmount;
    season.lifetimeStars = (season.lifetimeStars||0) + weeklyAmount;
    localStorage.setItem("dosco_season_v1", JSON.stringify(season));
    if (streak >= 2) {
      notifSystem.add({ type:"streak", title:"Série hebdomadaire !",
        body:`${streak} semaines d'affilée — +${weeklyAmount} étoiles !`, icon:"🔥" });
    }
    return { alreadyClaimed: false, reward: weeklyAmount, streak, newTotal: newData.totalClaimed };
  } catch { return { alreadyClaimed: true, streak:1 }; }
};

const getDailyData = () => {
  try { return JSON.parse(localStorage.getItem(DAILY_KEY)||"null"); } catch { return null; }
};

// ════════════════════════════════════════════════════════
// 📊 ANALYTICS LÉGER (Privacy-first, local)
// En production : Mixpanel.track() ou Amplitude.track()
// ════════════════════════════════════════════════════════
const ANALYTICS_KEY = "dosco_analytics_v1";

const analytics = {
  track: (event, props={}) => {
    try {
      const events = JSON.parse(localStorage.getItem(ANALYTICS_KEY)||"[]");
      events.unshift({ event, props, ts: Date.now() });
      localStorage.setItem(ANALYTICS_KEY, JSON.stringify(events.slice(0,200)));
      // En prod : mixpanel.track(event, props); ou amplitude.track(event, props);
      /* analytics event tracked */
    } catch {}
  },
  getEvents: () => { try { return JSON.parse(localStorage.getItem(ANALYTICS_KEY)||"[]"); } catch{return[];} },
  // Métriques calculées
  getMetrics: () => {
    const events = analytics.getEvents();
    const sessions = events.filter(e=>e.event==="session_start").length;
    const purchases = events.filter(e=>e.event==="purchase_complete");
    const revenue = purchases.reduce((s,e)=>s+(e.props.price||0),0);
    const games = events.filter(e=>e.event==="game_end").length;
    const wins = events.filter(e=>e.event==="game_end"&&e.props.result==="win").length;
    return { sessions, purchases: purchases.length, revenue: revenue.toFixed(2), games, winRate: games?Math.round(wins/games*100):0 };
  },
};


