// Sons pré-encodés en WAV base64 (aucun réseau requis)
const SOUND_DATA = {
  click: "data:audio/wav;base64,",
  select: "data:audio/wav;base64,",
  move: "data:audio/wav;base64,",
  capture: "data:audio/wav;base64,",
  error: "data:audio/wav;base64,",
  victory: "data:audio/wav;base64,",
  draw: "data:audio/wav;base64,",
  alert: "data:audio/wav;base64,",
  battlestart: "data:audio/wav;base64,",
  connect: "data:audio/wav;base64,",
  trace: "data:audio/wav;base64,",
};

// Cache des éléments audio
const _audioCache = {};
const _playSound = (name, vol=0.35) => {
  try {
    // Réutiliser ou créer l'élément audio
    if (!_audioCache[name]) {
      const a = new Audio(SOUND_DATA[name]);
      a.preload = "auto";
      _audioCache[name] = a;
    }
    const el = _audioCache[name];
    // Cloner pour permettre chevauchement
    const clone = el.cloneNode();
    clone.volume = Math.min(1, Math.max(0, vol));
    clone.play().catch(()=>{});
  } catch(e) {}
};

// Interface compatible avec l'ancien audio.*
const audio = {
  initialized:false, playing:false, vol:0.55, ctx:null,
  init(){this.initialized=true;}, resume(){this.initialized=true;},
  setVolume(v){this.vol=Math.max(0,Math.min(1,v));}, startAmbient(){}, stopAmbient(){},
  sfxClick(){_playSound("click",0.3*this.vol);}, sfxSelect(){_playSound("select",0.35*this.vol);},
  sfxMove(){_playSound("move",0.35*this.vol);}, sfxCapture(){_playSound("capture",0.45*this.vol);},
  sfxError(){_playSound("error",0.4*this.vol);}, sfxVictory(){_playSound("victory",0.5*this.vol);},
  sfxDraw(){_playSound("draw",0.35*this.vol);}, sfxAlert(){_playSound("alert",0.4*this.vol);},
  sfxBattleStart(){_playSound("battlestart",0.5*this.vol);}, sfxConnect(){_playSound("connect",0.35*this.vol);},
  sfxTrace(){_playSound("trace",0.2*this.vol);},
};

