// 🎵 DOSCO ORIGINAL SOUNDTRACK — Bande Originale v2
//
// 1. "Cosmos Awakening" (24s) — Menu · 118 BPM · Am harmonique
//    Intro pad → Arpège → Mélodie → Build → Chorus épique → Outro
//
// 2. "Event Horizon"    (20s) — Combat · 140 BPM · Electro Industrial
//    Tension → Drop brutal → Solo lead → 2e Drop + stabs
//
// 3. "Supernova"        (12s) — Victoire · 128 BPM · La Majeur
//    Sweep spectaculaire → Explosion harmonique → Climax + tierce
//
// 4. "Into The Void"    (12s) — Défaite · Cinématique
//    Cordes désaccordées → Basse chromatique → Mélodie plaintive
//
// Format: WAV 8-bit mono 11025Hz · Total: ~980KB
// ════════════════════════════════════════════════════════════════
const MUSIC_DATA = {
  menu:    "data:audio/wav;base64,",
  combat:  "data:audio/wav;base64,",
  victory: "data:audio/wav;base64,",
  defeat:  "data:audio/wav;base64,",
};

const MusicPlayer = {
  current: null, currentName: null, vol: 0.38,

  play(name, loop=true) {
    if (this.currentName===name && this.current && !this.current.paused) return;
    this.stop();
    if (!MUSIC_DATA[name]) return;
    try {
      const a = new Audio(MUSIC_DATA[name]);
      a.volume = this.vol; a.loop = loop;
      a.play().catch(()=>{});
      this.current = a; this.currentName = name;
    } catch(e) {}
  },

  stop() {
    if (this.current) {
      try { this.current.pause(); this.current.currentTime=0; } catch(e) {}
      this.current=null; this.currentName=null;
    }
  },

  setVolume(v) {
    this.vol=Math.max(0,Math.min(1,v));
    if(this.current) try{this.current.volume=this.vol;}catch(e){}
  },

  pause()  { try{this.current?.pause();}catch(e){} },
  resume() { try{this.current?.play().catch(()=>{});}catch(e){} },
};

