// 🪐 AVATAR AVEC PLANÈTES EN ORBITE
// Les planètes débloquées gravitent autour de l'avatar.
// Anti-saturation : au-delà de 4 planètes, on n'affiche que les 4 plus
// récentes (les plus prestigieuses) pour garder l'orbite lisible.
// ════════════════════════════════════════════════════════
// Visuel de galaxie spirale (SVG, unique par couleur) — pour le carrousel
const GalaxyVisual=({color,glow,size=120,id})=>{
  const arms=[0,1,2];
  return (
    <div style={{width:size,height:size,position:"relative",display:"flex",alignItems:"center",justifyContent:"center"}}>
      <div style={{position:"absolute",width:size,height:size,borderRadius:"50%",
        background:`radial-gradient(circle at 50% 50%, ${glow}33, transparent 65%)`,animation:"pls 4s ease-in-out infinite"}}/>
      <svg width={size} height={size} viewBox="0 0 120 120" style={{position:"relative",animation:"rotS 36s linear infinite"}}>
        <defs>
          <radialGradient id={`gx-core-${id}`} cx="50%" cy="50%" r="50%">
            <stop offset="0%" stopColor="#fff" stopOpacity="0.95"/>
            <stop offset="35%" stopColor={color} stopOpacity="0.9"/>
            <stop offset="100%" stopColor={glow} stopOpacity="0"/>
          </radialGradient>
        </defs>
        {arms.map(a=>{
          const rot=a*120;
          const pts=[...Array(26)].map((_,i)=>{
            const t=i/25, ang=(t*230+rot)*Math.PI/180, r=8+t*48;
            const x=60+Math.cos(ang)*r, y=60+Math.sin(ang)*r;
            return `${x.toFixed(1)},${y.toFixed(1)}`;
          }).join(" ");
          return <polyline key={a} points={pts} fill="none" stroke={color} strokeWidth={3.2-a*0.3} strokeLinecap="round" opacity={0.5-a*0.07}/>;
        })}
        {[...Array(22)].map((_,i)=>{
          const ang=(i*53)%360*Math.PI/180, r=14+((i*7)%46);
          const x=60+Math.cos(ang)*r, y=60+Math.sin(ang)*r;
          return <circle key={i} cx={x.toFixed(1)} cy={y.toFixed(1)} r={i%4===0?1.4:0.8} fill={i%3===0?"#fff":color} opacity={0.85}/>;
        })}
        <circle cx="60" cy="60" r="26" fill={`url(#gx-core-${id})`}/>
        <circle cx="60" cy="60" r="6" fill="#fff" opacity="0.95"/>
      </svg>
    </div>
  );
};

// Compteur animé : interpole en douceur vers la nouvelle valeur (effet premium)
const AnimatedNumber=({value,duration=600,style})=>{
  const [display,setDisplay]=useState(value);
  const fromRef=useRef(value);
  useEffect(()=>{
    const from=fromRef.current, to=value, start=Date.now();
    if(from===to) return;
    let raf;
    const tick=()=>{
      const t=Math.min(1,(Date.now()-start)/duration);
      const eased=1-Math.pow(1-t,3); // easeOutCubic
      setDisplay(Math.round(from+(to-from)*eased));
      if(t<1) raf=requestAnimationFrame(tick); else fromRef.current=to;
    };
    raf=requestAnimationFrame(tick);
    return ()=>cancelAnimationFrame(raf);
  },[value,duration]);
  return <span style={style}>{display}</span>;
};

const AvatarOrbit=({avatarId,lifetimeStars,size=72})=>{
  const avatar = AVATARS.find(a=>a.id===avatarId) || AVATARS[0];
  const unlocked = getUnlockedPlanets(lifetimeStars);
  // Anti-saturation : maximum 4 planètes affichées (les plus prestigieuses)
  const shown = unlocked.slice(-4);
  const orbitR = size*0.62;
  return (
    <div style={{position:"relative",width:size*2,height:size*2,
      display:"flex",alignItems:"center",justifyContent:"center"}}>
      {/* Anneau d'orbite discret */}
      <div style={{position:"absolute",width:orbitR*2,height:orbitR*2,borderRadius:"50%",
        border:`1px solid ${avatar.color}22`}}/>
      {/* Avatar central */}
      <div style={{width:size,height:size,borderRadius:"50%",
        display:"flex",alignItems:"center",justifyContent:"center",
        background:`radial-gradient(circle at 35% 30%,${avatar.color}33,rgba(8,12,28,.95))`,
        border:`2px solid ${avatar.color}`,fontSize:size*0.5,
        boxShadow:`0 0 24px ${avatar.color}55,inset 0 0 18px ${avatar.color}22`,
        zIndex:2}}>
        {avatar.emoji}
      </div>
      {/* Planètes en orbite */}
      {shown.map((p,i)=>{
        const angle = (360/shown.length)*i;
        const dur = 14 + i*3; // vitesses légèrement différentes
        return (
          <div key={p.id} style={{position:"absolute",width:orbitR*2,height:orbitR*2,
            animation:`orbit${i} ${dur}s linear infinite`}}>
            <div style={{position:"absolute",top:0,left:"50%",transform:"translateX(-50%)",
              width:p.size*2,height:p.size*2,borderRadius:"50%",
              background:`radial-gradient(circle at 35% 30%,${p.color},${p.color}66)`,
              boxShadow:`0 0 8px ${p.color}aa`,
              border:p.ring?`${Math.max(1,p.size*0.18)}px solid ${p.color}55`:"none"}}
              title={p.name}/>
          </div>
        );
      })}
      <style>{shown.map((p,i)=>`@keyframes orbit${i}{from{transform:rotate(${(360/shown.length)*i}deg)}to{transform:rotate(${(360/shown.length)*i+360}deg)}}`).join("")}</style>
    </div>
  );
};

const ParticleSystem=({particles})=>(
  <div style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:1000,overflow:"hidden"}}>
    {particles.map(p=>(
      <div key={p.id} style={{position:"absolute",left:p.x,top:p.y,width:p.size,height:p.size,
        borderRadius:"50%",background:p.color,boxShadow:`0 0 ${p.size*2}px ${p.color}`,
        opacity:p.opacity,transform:"translate(-50%,-50%)",
        animation:`ptcl${p.dir} ${p.dur}s ease-out forwards`}}/>
    ))}
    <style>{`
      @keyframes ptcl0{to{transform:translate(calc(-50% + 30px),calc(-50% - 55px)) scale(0);opacity:0}}
      @keyframes ptcl1{to{transform:translate(calc(-50% - 45px),calc(-50% - 35px)) scale(0);opacity:0}}
      @keyframes ptcl2{to{transform:translate(calc(-50% + 20px),calc(-50% - 70px)) scale(0);opacity:0}}
      @keyframes ptcl3{to{transform:translate(calc(-50% - 35px),calc(-50% - 55px)) scale(0);opacity:0}}
      @keyframes ptcl4{to{transform:translate(calc(-50% + 55px),calc(-50% - 25px)) scale(0);opacity:0}}
      @keyframes ptcl5{to{transform:translate(calc(-50% - 20px),calc(-50% - 65px)) scale(0);opacity:0}}
    `}</style>
  </div>
);
const useParticles=()=>{
  const[particles,setParticles]=useState([]);const idRef=useRef(0);
  const burst=useCallback((x,y,color,count=14,size=7)=>{
    const np=Array.from({length:count},(_,i)=>({
      id:idRef.current++,x:x+(Math.random()-.5)*22,y:y+(Math.random()-.5)*22,
      size:size*(.4+Math.random()*.8),color,opacity:1,dur:.4+Math.random()*.45,dir:i%6}));
    setParticles(p=>[...p,...np]);
    setTimeout(()=>setParticles(p=>p.filter(x=>!np.find(n=>n.id===x.id))),950);
  },[]);
  return{particles,burst};
};

