const NotificationsScreen=({onNav,lang="fr"})=>{
  const[notifs,setNotifs]=useState(()=>notifSystem.getAll());
  const[prefs,setPrefs]=useState(()=>notifSystem.getPrefs());

  const markAll=()=>{notifSystem.markAllRead();setNotifs(notifSystem.getAll());try{audio.sfxClick();}catch(e){}};
  const savePrefs=(p)=>{const np={...prefs,...p};setPrefs(np);notifSystem.savePrefs(np);};

  const ICONS={streak:"🔥",tournament:"🏆",challenge:"⚔",daily:"📅",system:"🌌",win:"🎉",purchase:"💫"};

  const Toggle=({on,onToggle})=>(
    <div onClick={onToggle} style={{width:38,height:22,borderRadius:11,cursor:"pointer",flexShrink:0,
      background:on?C.blue:"rgba(74,158,255,.15)",border:`1px solid ${on?C.blue:C.dim+"40"}`,
      position:"relative",transition:"all .2s"}}>
      <div style={{position:"absolute",top:2,left:on?18:2,width:18,height:18,borderRadius:"50%",
        background:on?"#fff":"rgba(74,158,255,.4)",transition:"left .2s"}}/>
    </div>
  );

  return(
    <div style={{width:"100%",height:"100%",background:`linear-gradient(180deg,#060d1e,${C.void})`,
      display:"flex",flexDirection:"column",overflow:"hidden",fontFamily:"'Exo 2',sans-serif"}}>
      <Starfield count={30}/>
      <div style={{padding:"12px 14px 8px",display:"flex",alignItems:"center",gap:10,zIndex:2,
        borderBottom:`1px solid rgba(74,158,255,.1)`}}>
        <button onClick={()=>{try{audio.sfxClick();}catch(e){}onNav("home");}} style={{background:"rgba(74,158,255,.1)",
          border:`1px solid ${C.blue}38`,borderRadius:8,padding:"5px 10px",color:C.blue,cursor:"pointer",fontSize:15}}>‹</button>
        <div style={{fontSize:10,color:C.white,fontWeight:900,letterSpacing:3,fontFamily:"'Orbitron',monospace"}}>{tUI("NOTIFICATIONS",lang)}</div>
        {notifs.filter(n=>!n.read).length>0&&(
          <button onClick={markAll} style={{marginLeft:"auto",fontSize:8,color:C.blue,background:"none",border:"none",cursor:"pointer",letterSpacing:1}}>
            Tout lire
          </button>
        )}
      </div>

      <div style={{flex:1,overflowY:"auto",padding:"10px 14px",zIndex:2}}>
        {/* Préférences notifications */}
        <div style={{background:"rgba(10,18,35,.9)",border:`1px solid rgba(74,158,255,.12)`,
          borderRadius:10,padding:"10px 12px",marginBottom:12}}>
          <div style={{fontSize:7.5,color:C.dim,letterSpacing:3,marginBottom:8,fontFamily:"'Orbitron',monospace"}}>{tUI("PRÉFÉRENCES",lang)}</div>
          {[
            {k:"daily",l:"Récompense quotidienne",i:"📅"},
            {k:"tournament",l:"Alertes tournois",i:"🏆"},
            {k:"challenge",l:"Défis reçus",i:"⚔"},
            {k:"streak",l:"Rappels de série",i:"🔥"},
          ].map((p,i,arr)=>(
            <div key={p.k} style={{display:"flex",alignItems:"center",gap:10,
              padding:"7px 0",borderBottom:i<arr.length-1?`1px solid rgba(74,158,255,.07)`:"none"}}>
              <span style={{fontSize:14}}>{p.i}</span>
              <span style={{flex:1,fontSize:10,color:C.white}}>{p.l}</span>
              <Toggle on={prefs[p.k]} onToggle={()=>savePrefs({[p.k]:!prefs[p.k]})}/>
            </div>
          ))}
        </div>

        {/* Liste notifications */}
        <div style={{fontSize:7.5,color:C.dim,letterSpacing:3,marginBottom:8,fontFamily:"'Orbitron',monospace"}}>
          RÉCENTES
        </div>
        {notifs.length===0&&(
          <div style={{textAlign:"center",padding:"30px 0",color:C.dim,fontSize:10}}>
            Aucune notification pour l'instant
          </div>
        )}
        {notifs.map((n,i)=>(
          <div key={n.id} onClick={()=>{notifSystem.markRead(n.id);setNotifs(notifSystem.getAll());}}
            style={{display:"flex",gap:10,padding:"10px 12px",marginBottom:6,cursor:"pointer",
              background:n.read?"rgba(10,18,35,.7)":"rgba(74,158,255,.1)",
              border:`1px solid ${n.read?"rgba(74,158,255,.08)":C.blue+"38"}`,
              borderRadius:9,transition:"all .2s"}}>
            <span style={{fontSize:20,flexShrink:0}}>{ICONS[n.type]||"🌌"}</span>
            <div style={{flex:1}}>
              <div style={{fontSize:10,color:n.read?C.dim:C.white,fontWeight:n.read?400:700}}>{n.title}</div>
              <div style={{fontSize:8.5,color:C.dim,marginTop:2}}>{n.body}</div>
              <div style={{fontSize:7.5,color:C.dim,marginTop:3}}>
                {new Date(n.ts).toLocaleString("fr-FR",{hour:"2-digit",minute:"2-digit",day:"2-digit",month:"short"})}
              </div>
            </div>
            {!n.read&&<div style={{width:8,height:8,borderRadius:"50%",background:C.blue,flexShrink:0,marginTop:2,boxShadow:`0 0 5px ${C.blue}`}}/>}
          </div>
        ))}
      </div>
    </div>
  );
};

