const LoginScreen=({onNav,onLogin,lang="fr"})=>{
  const[tab,setTab]=useState("login"); // "login"|"register"|"guest"
  const[name,setName]=useState("");
  const[email,setEmail]=useState("");
  const[pass,setPass]=useState("");
  const[loading,setLoading]=useState(false);
  const[error,setError]=useState("");
  const[showPass,setShowPass]=useState(false);

  const inputStyle={
    width:"100%",padding:"11px 14px",background:"rgba(74,158,255,.07)",
    border:`1px solid rgba(74,158,255,.25)`,borderRadius:10,
    color:C.white,fontSize:13,outline:"none",
    fontFamily:"'Exo 2',sans-serif",boxSizing:"border-box",
  };
  const labelStyle={fontSize:8,color:C.dim,letterSpacing:2,
    fontFamily:"'Orbitron',monospace",marginBottom:5,display:"block"};

  const handleSubmit=async()=>{
    setError("");
    if(tab==="register"){
      if(!name.trim()){setError("Choisissez un pseudo.");return;}
      if(!email.trim()){setError("Email requis.");return;}
      if(pass.length<4){setError("Mot de passe trop court (min. 4 caractères).");return;}
    } else {
      // Connexion : pseudo OU email dans le champ "name"
      if(!name.trim()){setError("Entrez votre pseudo ou email.");return;}
      if(pass.length<4){setError("Mot de passe trop court (min. 4 caractères).");return;}
    }
    setLoading(true);
    await new Promise(r=>setTimeout(r,600));
    let result;
    if(tab==="register"){
      result=authRegister(name.trim(),email.trim(),pass);
    } else {
      result=authLogin(name.trim(),pass);   // name = identifiant (pseudo ou email)
    }
    setLoading(false);
    if(result.error){setError(result.error);return;}
    try{audio.sfxVictory();}catch(e){};try{MusicPlayer.play("victory",false);}catch(e){}
    onLogin(result.user);
  };

  const handleOAuth=async(provider)=>{
    setError("");setLoading(true);
    try{audio.sfxClick();}catch(e){}
    try{
      // Simule l'ouverture d'une popup OAuth (remplacer par SDK natif en production)
      await new Promise(r=>setTimeout(r,800));
      const result=authOAuthLogin(provider,null);
      if(!result||result.error){
        setError(result?.error||(provider==="google"?"Connexion Google échouée":"Connexion Facebook échouée"));
        setLoading(false);return;
      }
      if(!result.user||!result.user.uid){
        setError("Profil "+provider+" introuvable. Réessayez.");
        setLoading(false);return;
      }
      setLoading(false);
      try{audio.sfxVictory();}catch(e){}
      try{MusicPlayer.play("victory",false);}catch(e){}
      onLogin(result.user);
    }catch(err){
      setLoading(false);
      setError("Erreur "+provider+" : "+(err.message||"connexion impossible"));
    }
  };

  const handleGuest=()=>{
    try{audio.sfxClick();}catch(e){}
    const result=authGuestLogin();
    if(result.user) onLogin(result.user);
  };

  return(
    <div style={{width:"100%",height:"100%",display:"flex",flexDirection:"column",
      background:`linear-gradient(180deg,#060c1e,${C.void})`,overflow:"hidden",
      fontFamily:"'Exo 2',sans-serif"}}>
      <Starfield count={80}/><Nebulas/>

      {/* Logo */}
      <div style={{textAlign:"center",padding:"28px 0 16px",zIndex:2}}>
        <div style={{animation:"rotS 24s linear infinite",display:"inline-block",marginBottom:8}}>
          <StarSVG type="Sirus" color={C.white} size={52} glow anim/>
        </div>
        <div style={{fontSize:22,fontWeight:900,letterSpacing:8,color:C.white,
          fontFamily:"'Orbitron',monospace",
          background:`linear-gradient(135deg,${C.white},${C.blue})`,
          WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent"}}>
          DOSCO
        </div>
        <div style={{fontSize:8,color:C.blue,letterSpacing:5,marginTop:2}}>
          LA BATAILLE DES ÉTOILES
        </div>
      </div>

      {/* Tabs */}
      <div style={{display:"flex",margin:"0 16px 16px",gap:6,zIndex:2}}>
        {[["login","CONNEXION"],["register","INSCRIPTION"],["guest","INVITÉ"]].map(([v,l])=>(
          <button key={v} onClick={()=>{try{audio.sfxClick();}catch(e){}setTab(v);setError("");}}
            style={{flex:1,padding:"8px 4px",borderRadius:9,cursor:"pointer",
              background:tab===v?`rgba(74,158,255,.2)`:"rgba(10,18,35,.8)",
              border:`1px solid ${tab===v?C.blue:"rgba(74,158,255,.15)"}`,
              color:tab===v?C.blue:C.dim,fontSize:8,fontWeight:700,letterSpacing:1,
              fontFamily:"'Orbitron',monospace",transition:"all .2s"}}>
            {l}
          </button>
        ))}
      </div>

      <div style={{flex:1,overflowY:"auto",padding:"0 16px 16px",zIndex:2}}>
        {tab==="guest"?(
          <div style={{textAlign:"center",padding:"20px 0"}}>
            <div style={{fontSize:32,marginBottom:16}}>🚀</div>
            <div style={{fontSize:13,color:C.white,fontWeight:600,marginBottom:8}}>
              Jouer sans compte
            </div>
            <div style={{fontSize:10,color:C.dim,lineHeight:1.7,marginBottom:24}}>
              Accès immédiat à toutes les fonctionnalités. Vos points saison et historique
              ne seront pas sauvegardés entre les sessions.
            </div>
            <button onClick={handleGuest} className="btn-c"
              style={{width:"100%",padding:"14px",
                background:`linear-gradient(135deg,${C.teal},${C.blue})`,
                borderRadius:12,color:C.void,fontSize:12,fontWeight:900,
                letterSpacing:3,fontFamily:"'Orbitron',monospace",
                boxShadow:`0 0 20px ${C.teal}40`}}>
              🚀 JOUER EN INVITÉ
            </button>
            <div style={{marginTop:14,fontSize:9,color:C.dim}}>
              Créez un compte pour sauvegarder votre progression ✦
            </div>
          </div>
        ):(
          <div style={{display:"flex",flexDirection:"column",gap:14}}>
            {/* Pseudo */}
            <div>
              <label style={labelStyle}>{tab==="login"?(tUI("PSEUDO",lang)+" / "+tUI("EMAIL",lang)):tUI("PSEUDO",lang)}</label>
              <input value={name} onChange={e=>setName(e.target.value)}
                onKeyDown={e=>e.key==="Enter"&&handleSubmit()}
                placeholder={tab==="login"?"Pseudo ou email":"Ex: NEBULA_X"} maxLength={tab==="login"?64:14}
                style={inputStyle}/>
            </div>

            {/* Email (inscription seulement) */}
            {tab==="register"&&(
              <div>
                <label style={labelStyle}>{tUI("EMAIL",lang)}</label>
                <input value={email} onChange={e=>setEmail(e.target.value)}
                  onKeyDown={e=>e.key==="Enter"&&handleSubmit()}
                  placeholder="votre@email.com" type="email"
                  style={inputStyle}/>
              </div>
            )}

            {/* Mot de passe */}
            <div>
              <label style={labelStyle}>{tUI("MOT DE PASSE",lang)}</label>
              <div style={{position:"relative"}}>
                <input value={pass} onChange={e=>setPass(e.target.value)}
                  onKeyDown={e=>e.key==="Enter"&&handleSubmit()}
                  placeholder={tab==="login"?"••••••••":"Min. 8 caractères"}
                  type={showPass?"text":"password"}
                  style={{...inputStyle,paddingRight:44}}/>
                <button onClick={()=>setShowPass(p=>!p)}
                  style={{position:"absolute",right:12,top:"50%",transform:"translateY(-50%)",
                    background:"none",border:"none",color:C.dim,cursor:"pointer",fontSize:14}}>
                  {showPass?"🙈":"👁"}
                </button>
              </div>
            </div>

            {/* Mot de passe oublié */}
            {tab==="login"&&(
              <div style={{textAlign:"right"}}>
                <button onClick={()=>audio.sfxClick()}
                  style={{background:"none",border:"none",color:C.blue,
                    cursor:"pointer",fontSize:9,letterSpacing:1}}>
                  Mot de passe oublié ?
                </button>
              </div>
            )}

            {/* Erreur */}
            {error&&(
              <div style={{background:"rgba(255,68,102,.1)",border:`1px solid ${C.red}40`,
                borderRadius:8,padding:"8px 12px",fontSize:10,color:C.red,
                animation:"zIn .2s ease"}}>
                ⚠ {error}
              </div>
            )}

            {/* Bouton principal */}
            <button onClick={handleSubmit} disabled={loading} className="btn-c"
              style={{padding:"14px",
                background:loading?"rgba(74,158,255,.2)":`linear-gradient(135deg,${C.blue},${C.cyan})`,
                borderRadius:12,color:loading?C.dim:C.void,fontSize:12,fontWeight:900,
                letterSpacing:3,fontFamily:"'Orbitron',monospace",marginTop:4,
                boxShadow:loading?"none":`0 0 20px ${C.blue}40`,
                transition:"all .3s",cursor:loading?"not-allowed":"pointer"}}>
              {loading?"⟳ CONNEXION...":(tab==="login"?"✦ SE CONNECTER":"✦ CRÉER MON COMPTE")}
            </button>

            {/* Séparateur */}
            <div style={{display:"flex",alignItems:"center",gap:10}}>
              <div style={{flex:1,height:1,background:"rgba(74,158,255,.12)"}}/>
              <span style={{fontSize:8,color:C.dim}}>OU</span>
              <div style={{flex:1,height:1,background:"rgba(74,158,255,.12)"}}/>
            </div>

            {/* Connexion via Google / Facebook (OAuth) */}
            <button onClick={()=>handleOAuth("google")} disabled={loading}
              style={{padding:"11px",background:"#fff",border:"none",borderRadius:10,
                color:"#3c4043",fontSize:11,fontWeight:700,letterSpacing:1,
                fontFamily:"'Exo 2',sans-serif",cursor:loading?"not-allowed":"pointer",
                display:"flex",alignItems:"center",justifyContent:"center",gap:9}}>
              <span style={{fontSize:15,fontWeight:900,fontFamily:"'Orbitron',monospace",
                background:"conic-gradient(from -45deg,#ea4335,#fbbc05,#34a853,#4285f4,#ea4335)",
                WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent"}}>G</span>
              {tUI("Continuer avec Google",lang)}
            </button>
            <button onClick={()=>handleOAuth("facebook")} disabled={loading}
              style={{padding:"11px",background:"#1877f2",border:"none",borderRadius:10,
                color:"#fff",fontSize:11,fontWeight:700,letterSpacing:1,
                fontFamily:"'Exo 2',sans-serif",cursor:loading?"not-allowed":"pointer",
                display:"flex",alignItems:"center",justifyContent:"center",gap:9}}>
              <span style={{fontSize:16,fontWeight:900}}>f</span>
              {tUI("Continuer avec Facebook",lang)}
            </button>

            {/* Connexion invité */}
            <button onClick={handleGuest}
              style={{padding:"11px",background:"rgba(0,212,170,.08)",
                border:`1px solid ${C.teal}30`,borderRadius:10,
                color:C.teal,fontSize:10,fontWeight:700,letterSpacing:2,
                fontFamily:"'Orbitron',monospace",cursor:"pointer"}}>
              🚀 JOUER EN INVITÉ
            </button>

            {/* Toggle login/register */}
            <div style={{textAlign:"center",fontSize:9,color:C.dim}}>
              {tab==="login"?"Pas encore de compte ? ":"Déjà un compte ? "}
              <button onClick={()=>{setTab(tab==="login"?"register":"login");setError("");}}
                style={{background:"none",border:"none",color:C.blue,
                  cursor:"pointer",fontSize:9,fontWeight:700,letterSpacing:1}}>
                {tab==="login"?"S'inscrire →":"Se connecter →"}
              </button>
            </div>
          </div>
        )}

        {/* Avantages compte */}
        <div style={{marginTop:20,padding:"12px 14px",
          background:"rgba(74,158,255,.04)",
          border:`1px solid rgba(74,158,255,.1)`,borderRadius:10}}>
          <div style={{fontSize:8,color:C.blue,letterSpacing:2,marginBottom:8,
            fontFamily:"'Orbitron',monospace"}}>AVEC UN COMPTE :</div>
          {["🏆 Classement mondial","⭐ Points saison sauvegardés",
            "🎮 Historique & replays","🌐 Multijoueur en ligne","🎨 Skins & personnalisation"].map((a,i)=>(
            <div key={i} style={{fontSize:9,color:C.dim,marginBottom:4,
              display:"flex",alignItems:"center",gap:8}}>
              <span>{a}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

// ════════════════════════════════════════════════════════
// 💫 BOUTIQUE DE POINTS — Acheter des étoiles
// ════════════════════════════════════════════════════════
const ShopScreen=({onNav,user,season,onPurchase,lang="fr"})=>{
  const[selected,setSelected]=useState(null);
  const[purchasing,setPurchasing]=useState(false);
  const[purchased,setPurchased]=useState(null);
  const[restoring,setRestoring]=useState(false);
  const[restoreMsg,setRestoreMsg]=useState(null);

  // Restauration des achats (OBLIGATOIRE Apple/Google)
  const handleRestore=async()=>{
    if(restoring)return;
    setRestoring(true);
    try{audio.sfxClick();}catch(e){}
    const r=await iapRestorePurchases(user?.uid||"guest");
    setRestoring(false);
    if(r&&r.success){
      setRestoreMsg(r.restored?"✓ Achats restaurés !":"Aucun achat à restaurer.");
    }else{
      setRestoreMsg("Restauration échouée. Réessayez.");
    }
    setTimeout(()=>setRestoreMsg(null),3000);
  };

  const PACKS=[
    {id:"starter",stars:100,price:"0.99",bonus:0,
      label:"STARTER",icon:"⭐",color:C.blue,
      desc:"Idéal pour commencer"},
    {id:"explorer",stars:300,price:"1.99",bonus:50,
      label:"EXPLORATEUR",icon:"🌟",color:C.cyan,
      desc:"Le plus populaire",popular:true},
    {id:"champion",stars:700,price:"3.99",bonus:150,
      label:"CHAMPION",icon:"💫",color:C.gold,
      desc:"Pour les compétiteurs"},
    {id:"legend",stars:1500,price:"7.99",bonus:500,
      label:"LÉGENDE",icon:"🌌",color:C.purple,
      desc:"Pack ultime — meilleure valeur"},
  ];

  const SEASON_PASS={
    price:"2.99",label:"PASSE SAISON",
    perks:["★200 étoiles immédiatement",
      "Skin exclusif Nébuleuse",
      "Effet de capture Nova",
      "Bonus +10pts chaque victoire",
      "Badge Commandant de Saison"],
  };

  const handleBuy=async(pack)=>{
    if(purchasing) return;
    try{audio.sfxClick();}catch(e){}
    setSelected(pack.id);
    setPurchasing(true);
    const fn=onPurchase||iapPurchase;
    const result=await fn(pack.id,user?.uid||"guest");
    setPurchasing(false);
    if(result&&result.success){
      try{audio.sfxVictory();}catch(e){};try{MusicPlayer.play("victory",false);}catch(e){}
      setPurchased(pack);
    } else if(result&&result.error){
      try{audio.sfxError();}catch(e){}
      // Afficher erreur brièvement
      setSelected(null);
    }
  };

  if(purchased) return(
    <div style={{width:"100%",height:"100%",display:"flex",flexDirection:"column",
      alignItems:"center",justifyContent:"center",gap:16,
      background:`linear-gradient(180deg,#060c1e,${C.void})`,
      fontFamily:"'Exo 2',sans-serif",padding:"24px",zIndex:2}}>
      <Starfield count={140}/>
      <div style={{animation:"flt 3s ease-in-out infinite",fontSize:56}}>
        {purchased.icon}
      </div>
      <div style={{fontSize:16,fontWeight:900,color:C.gold,letterSpacing:4,
        fontFamily:"'Orbitron',monospace",animation:"glwG 2s infinite",textAlign:"center"}}>
        ACHAT RÉUSSI !
      </div>
      <div style={{fontSize:32,fontWeight:900,color:C.white,
        fontFamily:"'Orbitron',monospace",animation:"zIn .5s ease"}}>
        +{purchased.stars+(purchased.bonus||0)} ⭐
      </div>
      <div style={{fontSize:10,color:C.dim,textAlign:"center",lineHeight:1.6}}>
        {purchased.stars} étoiles{purchased.bonus>0?` + ${purchased.bonus} bonus`:""} ont été ajoutées à votre compte.
      </div>
      <button onClick={()=>{try{audio.sfxClick();}catch(e){}onNav("home");}} className="btn-c"
        style={{padding:"13px 32px",background:`linear-gradient(135deg,${C.gold},${C.orange})`,
          borderRadius:12,color:C.void,fontSize:11,fontWeight:900,letterSpacing:3,
          fontFamily:"'Orbitron',monospace",boxShadow:`0 0 20px ${C.gold}45`,marginTop:8}}>
        ✦ CONTINUER
      </button>
    </div>
  );

  return(
    <div style={{width:"100%",height:"100%",display:"flex",flexDirection:"column",
      background:`linear-gradient(180deg,#060c1e,${C.void})`,overflow:"hidden",
      fontFamily:"'Exo 2',sans-serif"}}>
      <Starfield count={50}/><Nebulas/>

      {/* Header */}
      <div style={{padding:"12px 14px 10px",display:"flex",alignItems:"center",
        gap:10,zIndex:2,borderBottom:`1px solid rgba(74,158,255,.1)`}}>
        <button onClick={()=>{try{audio.sfxClick();}catch(e){}onNav("home");}}
          style={{background:"rgba(74,158,255,.1)",border:`1px solid ${C.blue}38`,
            borderRadius:8,padding:"5px 10px",color:C.blue,cursor:"pointer",fontSize:15}}>‹</button>
        <div style={{fontSize:11,color:C.white,fontWeight:900,letterSpacing:3,
          fontFamily:"'Orbitron',monospace"}}>{tUI("BOUTIQUE",lang)}</div>
        <div style={{marginLeft:"auto",background:`linear-gradient(135deg,rgba(240,192,64,.2),rgba(240,192,64,.07))`,
          border:`1px solid ${C.gold}50`,borderRadius:10,padding:"4px 12px",
          display:"flex",alignItems:"center",gap:5}}>
          <span style={{fontSize:10,color:C.gold,fontWeight:900,
            fontFamily:"'Orbitron',monospace"}}>⭐ {season?.stars??100}</span>
        </div>
      </div>

      <div style={{flex:1,overflowY:"auto",padding:"10px 14px 16px",zIndex:2}}>

        {/* Passe saison */}
        <div style={{background:`linear-gradient(135deg,rgba(136,85,255,.15),rgba(74,158,255,.06))`,
          border:`2px solid ${C.purple}50`,borderRadius:14,padding:"14px 16px",
          marginBottom:16,position:"relative",overflow:"hidden"}}>
          <div style={{position:"absolute",top:-20,right:-20,fontSize:60,opacity:.08}}>🌌</div>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:10}}>
            <div>
              <div style={{fontSize:8,color:C.purple,letterSpacing:3,marginBottom:3,
                fontFamily:"'Orbitron',monospace"}}>{tUI("OFFRE SPÉCIALE",lang)}</div>
              <div style={{fontSize:14,fontWeight:900,color:C.white,letterSpacing:2,
                fontFamily:"'Orbitron',monospace"}}>{SEASON_PASS.label}</div>
            </div>
            <div style={{textAlign:"right"}}>
              <div style={{fontSize:18,fontWeight:900,color:C.purple,
                fontFamily:"'Orbitron',monospace"}}>{SEASON_PASS.price}€</div>
              <div style={{fontSize:7,color:C.dim}}>/ saison (7 jours)</div>
            </div>
          </div>
          {SEASON_PASS.perks.map((p,i)=>(
            <div key={i} style={{display:"flex",alignItems:"center",gap:8,
              marginBottom:4,fontSize:9,color:C.white}}>
              <span style={{color:C.purple,flexShrink:0}}>✦</span>{p}
            </div>
          ))}
          <button onClick={()=>handleBuy({id:"pass",stars:200,bonus:0,
              label:"Passe Saison",icon:"🌌",color:C.purple,price:SEASON_PASS.price})}
            className="btn-c"
            style={{width:"100%",marginTop:12,padding:"11px",
              background:`linear-gradient(135deg,${C.purple},${C.blue})`,
              borderRadius:10,color:C.white,fontSize:10,fontWeight:900,
              letterSpacing:2,fontFamily:"'Orbitron',monospace",
              boxShadow:`0 0 16px ${C.purple}40`,
              opacity:purchasing&&selected==="pass"?.6:1}}>
            {purchasing&&selected==="pass"?"⟳ TRAITEMENT...":"✦ ACTIVER LE PASSE"}
          </button>
        </div>

        {/* Titre packs */}
        <div style={{fontSize:8,color:C.dim,letterSpacing:3,marginBottom:10,
          fontFamily:"'Orbitron',monospace"}}>{tUI("PACKS D'ÉTOILES",lang)}</div>

        {/* Packs */}
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:16}}>
          {PACKS.map(pack=>(
            <div key={pack.id}
              style={{position:"relative",background:pack.popular
                ?`linear-gradient(135deg,${pack.color}18,${pack.color}08)`
                :"rgba(10,18,35,.88)",
                border:`${pack.popular?2:1.5}px solid ${pack.color}${pack.popular?"55":"28"}`,
                borderRadius:12,padding:"14px 12px",cursor:"pointer",
                transition:"all .2s",overflow:"hidden",
                boxShadow:pack.popular?`0 0 16px ${pack.color}20`:"none",
                transform:selected===pack.id?"scale(.97)":"scale(1)"}}>
              {pack.popular&&(
                <div style={{position:"absolute",top:0,right:0,
                  background:pack.color,color:C.void,fontSize:7,
                  fontWeight:900,padding:"3px 8px",borderRadius:"0 10px 0 8px",
                  letterSpacing:1,fontFamily:"'Orbitron',monospace"}}>
                  POPULAIRE
                </div>
              )}
              <div style={{fontSize:28,marginBottom:6,textAlign:"center"}}>{pack.icon}</div>
              <div style={{fontSize:9,fontWeight:900,color:pack.color,letterSpacing:2,
                textAlign:"center",fontFamily:"'Orbitron',monospace",marginBottom:4}}>
                {pack.label}
              </div>
              <div style={{textAlign:"center",marginBottom:6}}>
                <span style={{fontSize:20,fontWeight:900,color:C.white,
                  fontFamily:"'Orbitron',monospace"}}>
                  {pack.stars}
                </span>
                {pack.bonus>0&&(
                  <span style={{fontSize:10,color:pack.color,fontWeight:700,marginLeft:4}}>
                    +{pack.bonus}
                  </span>
                )}
                <div style={{fontSize:8,color:C.dim,marginTop:1}}>⭐ étoiles</div>
              </div>
              <div style={{fontSize:8,color:C.dim,textAlign:"center",marginBottom:10}}>
                {pack.desc}
              </div>
              <button onClick={()=>handleBuy(pack)}
                disabled={purchasing}
                className="btn-c"
                style={{width:"100%",padding:"9px",
                  background:`linear-gradient(135deg,${pack.color},${pack.color}99)`,
                  borderRadius:8,color:C.void,fontSize:11,fontWeight:900,
                  letterSpacing:1,fontFamily:"'Orbitron',monospace",
                  opacity:purchasing&&selected===pack.id?.5:1,
                  cursor:purchasing?"not-allowed":"pointer"}}>
                {purchasing&&selected===pack.id?"⟳":pack.price+"€"}
              </button>
            </div>
          ))}
        </div>

        {/* Gagner gratuitement */}
        <div style={{background:"rgba(0,255,136,.05)",border:`1px solid ${C.green}25`,
          borderRadius:12,padding:"12px 14px"}}>
          <div style={{fontSize:8,color:C.green,letterSpacing:3,marginBottom:8,
            fontFamily:"'Orbitron',monospace"}}>{tUI("GAGNER GRATUITEMENT",lang)}</div>
          {[
            {icon:"🏆",action:"Victoire en ligne",reward:"+15 ⭐"},
            {icon:"🔥",action:"Série de 5 victoires",reward:"+5 ⭐ bonus"},
            {icon:"📅",action:"Connexion quotidienne",reward:"+3 ⭐"},
            {icon:"🎯",action:"Tournoi hebdomadaire",reward:"★500"},
          ].map((r,i)=>(
            <div key={i} style={{display:"flex",alignItems:"center",gap:10,
              marginBottom:i<3?7:0}}>
              <span style={{fontSize:16}}>{r.icon}</span>
              <span style={{flex:1,fontSize:9,color:C.white}}>{r.action}</span>
              <span style={{fontSize:9,color:C.green,fontWeight:700,
                fontFamily:"'Orbitron',monospace"}}>{r.reward}</span>
            </div>
          ))}
        </div>

        {/* Restauration des achats (obligatoire Apple/Google) */}
        <button onClick={handleRestore} disabled={restoring}
          style={{marginTop:12,width:"100%",padding:"11px",background:"rgba(74,158,255,.08)",
            border:`1px solid ${C.blue}30`,borderRadius:10,color:C.blue,fontSize:10,fontWeight:700,
            letterSpacing:1,cursor:restoring?"wait":"pointer",fontFamily:"'Orbitron',monospace"}}>
          {restoring?"RESTAURATION...":"↻ RESTAURER MES ACHATS"}
        </button>
        {restoreMsg&&(
          <div style={{fontSize:9,color:restoreMsg.includes("✓")?C.green:C.dim,
            textAlign:"center",marginTop:6}}>{restoreMsg}</div>
        )}

        {/* Liens légaux */}
        <div style={{display:"flex",gap:12,justifyContent:"center",marginTop:12}}>
          <span onClick={()=>{try{audio.sfxClick();}catch(e){}onNav("legal");}}
            style={{fontSize:8,color:C.cyan,cursor:"pointer",textDecoration:"underline"}}>
            Conditions
          </span>
          <span onClick={()=>{try{audio.sfxClick();}catch(e){}onNav("legal");}}
            style={{fontSize:8,color:C.cyan,cursor:"pointer",textDecoration:"underline"}}>
            Confidentialité
          </span>
        </div>

        {/* Mention légale */}
        <div style={{marginTop:10,fontSize:7.5,color:C.dim,lineHeight:1.6,textAlign:"center"}}>
          Paiement sécurisé via {window.Capacitor?"l'App Store / Google Play":"votre store"}.<br/>
          Achats non remboursables · Étoiles valables uniquement dans DOSCO · Sans valeur monétaire réelle.
        </div>
      </div>
    </div>
  );
};


// ════════════════════════════════════════════════════════
// 🎁 WIDGET RÉCOMPENSE QUOTIDIENNE
// S'affiche au premier lancement du jour
// ════════════════════════════════════════════════════════
const DailyRewardModal=({onClose,reward,lang="fr"})=>{
  const[show,setShow]=useState(false);
  useEffect(()=>{setTimeout(()=>setShow(true),100);},[]);
  if(!reward||reward.alreadyClaimed) return null;

  return(
    <div style={{position:"absolute",inset:0,background:"rgba(3,4,10,.85)",
      display:"flex",alignItems:"center",justifyContent:"center",zIndex:100,
      animation:"zIn .3s ease"}}>
      <div style={{background:`linear-gradient(135deg,rgba(10,18,40,.98),rgba(6,12,24,.98))`,
        border:`2px solid ${C.gold}50`,borderRadius:20,padding:"28px 22px",
        maxWidth:300,width:"90%",textAlign:"center",
        transform:show?"scale(1)":"scale(.8)",transition:"transform .3s ease",
        boxShadow:`0 0 40px ${C.gold}25`}}>
        <div style={{fontSize:48,marginBottom:12,animation:"flt 3s ease-in-out infinite"}}>🎁</div>
        <div style={{fontSize:12,color:C.gold,fontWeight:900,letterSpacing:3,
          fontFamily:"'Orbitron',monospace",marginBottom:6}}>{tUI("BONUS HEBDOMADAIRE",lang)}</div>
        <div style={{fontSize:28,fontWeight:900,color:C.white,fontFamily:"'Orbitron',monospace",
          animation:"glwG 2s infinite",marginBottom:6}}>+{reward.reward} ⭐</div>
        {reward.streak>1&&(
          <div style={{display:"inline-flex",alignItems:"center",gap:5,
            background:"rgba(255,136,68,.12)",border:`1px solid ${C.orange}38`,
            borderRadius:20,padding:"4px 12px",marginBottom:10}}>
            <span style={{fontSize:14}}>🔥</span>
            <span style={{fontSize:9.5,color:C.orange,fontWeight:700}}>
              {tUI("Série de",lang)} {reward.streak} {tUI("semaines",lang)} !
            </span>
          </div>
        )}
        <div style={{fontSize:9,color:C.dim,marginBottom:18,lineHeight:1.6}}>
          {tUI("Revenez chaque semaine pour maintenir votre série et gagner des étoiles gratuitement.",lang)}
        </div>
        <button onClick={()=>{try{audio.sfxVictory();}catch(e){};try{MusicPlayer.play("victory",false);}catch(e){}onClose();}} className="btn-c"
          style={{width:"100%",padding:"12px",
            background:`linear-gradient(135deg,${C.gold},${C.orange})`,
            borderRadius:12,color:C.void,fontSize:11,fontWeight:900,
            letterSpacing:3,fontFamily:"'Orbitron',monospace",
            boxShadow:`0 0 18px ${C.gold}40`}}>
          RÉCUPÉRER
        </button>
      </div>
    </div>
  );
};

