// 🎮 PLATEAU — GameBoard avec trace de déplacement
// ════════════════════════════════════════════════════════
const BOARD_LAYOUT=[[null,null,null,"D1",null,null,null],[null,null,"C2","D2","E2",null,null],["A3","B3","C3","D3","E3","F3","G3"],["A4","B4","C4","D4","E4","F4","G4"],["A5","B5","C5","D5","E5","F5","G5"],["A6","B6","C6","D6","E6","F6","G6"],["A7","B7","C7","D7","E7","F7","G7"],[null,null,"C8","D8","E8",null,null],[null,null,null,"D9",null,null,null]];

// ── Hook : CELL dynamique via ResizeObserver sur le conteneur réel ──
const useBoardSize = (containerRef) => {
  const [cell, setCell] = useState(44);
  useEffect(() => {
    const GAP = 3, PAD = 28;
    const compute = (w, h) => {
      if (!w || !h) return;
      const cellW = Math.floor((w - PAD - 6 * GAP) / 7);
      const cellH = Math.floor((h - PAD - 8 * GAP) / 9);
      const c = Math.min(cellW, cellH, 130);
      if (c > 0) setCell(Math.max(c, 30));
    };
    const measure = () => {
      const el = containerRef && containerRef.current;
      if (el) {
        const r = el.getBoundingClientRect();
        if (r.width > 0 && r.height > 0) { compute(r.width, r.height); return true; }
      }
      // Fallback : estimer depuis la fenêtre si le conteneur n'est pas encore mesurable
      const w = (typeof window !== "undefined" ? window.innerWidth : 360);
      const h = (typeof window !== "undefined" ? window.innerHeight : 640) * 0.62;
      compute(w, h);
      return false;
    };
    // Mesures différées pour laisser le layout se stabiliser
    measure();
    const t1 = setTimeout(measure, 60);
    const t2 = setTimeout(measure, 200);
    let ro = null;
    const el = containerRef && containerRef.current;
    if (el && typeof ResizeObserver !== "undefined") {
      ro = new ResizeObserver(entries => {
        for (const e of entries) compute(e.contentRect.width, e.contentRect.height);
      });
      ro.observe(el);
    }
    const onResize = () => measure();
    if (typeof window !== "undefined") window.addEventListener("resize", onResize);
    return () => {
      clearTimeout(t1); clearTimeout(t2);
      if (ro) ro.disconnect();
      if (typeof window !== "undefined") window.removeEventListener("resize", onResize);
    };
  }, [containerRef]);
  return cell;
};

const GameBoard=({onGameEnd,playerColor="W",vsAI=false,aiDiff="n3",lang="fr",resumeState=null,onQuit=null})=>{
  const T=LANGS[lang];
  const R = resumeState; // état de reprise éventuel
  const[board,setBoard]=useState(()=>R?R.board:{...INIT_BOARD});
  const[turn,setTurn]=useState(()=>R?R.turn:"B");
  const[sel,setSel]=useState(null);
  const[vm,setVM]=useState([]);
  const[caps,setCaps]=useState([]);
  const[mc,setMC]=useState({});
  const[log,setLog]=useState(()=>R?["Partie reprise."]:["Les étoiles bleues commencent !"]);
  const[captured,setCaptured]=useState(()=>R?R.captured:{W:[],B:[]});
  const[msc,setMSC]=useState(()=>R?R.msc:0);
  const[moveCount,setMoveCount]=useState(()=>R?(R.moveCount||0):0);
  const[gameOver,setGameOver]=useState(null);
  const[flash,setFlash]=useState(null);
  const[lastFrom,setLastFrom]=useState(null);
  const[lastTo,setLastTo]=useState(null);
  const[aiThinking,setAiThinking]=useState(false);
  const[ptsResult,setPtsResult]=useState(null);
  const[timeW,setTimeW]=useState(()=>R?R.timeW:300); // 5 min = 300s
  const[timeB,setTimeB]=useState(()=>R?R.timeB:300);
  const[hintMove,setHintMove]=useState(null); // indice IA
  const[hintsUsed,setHintsUsed]=useState(0);   // indices utilisés cette partie (2 gratuits)
  const[hintMsg,setHintMsg]=useState(null);    // message paiement indice
  const FREE_HINTS=2; const HINT_COST=10;
  const[showConfirmQuit,setShowConfirmQuit]=useState(false);
  const[showDrawOffer,setShowDrawOffer]=useState(false); // modal pour proposer la nulle
  const[drawPending,setDrawPending]=useState(false); // l'adversaire doit répondre
  const logRef=useRef();const boardRef=useRef();

  // Retour haptique (vibration mobile)
  const haptic=(ms=15)=>{try{if(navigator.vibrate)navigator.vibrate(ms);}catch(e){}};
  const{particles,burst}=useParticles();
  const addLog=useCallback(m=>setLog(l=>[...l.slice(-10),m]),[]);

  // ── CHRONO 5 MINUTES PAR JOUEUR ──
  useEffect(()=>{
    if(gameOver) return;
    const interval=setInterval(()=>{
      if(turn==="W"){
        setTimeW(t=>{
          if(t<=1){
            clearInterval(interval);
            const end={winner:"B",reason:"Temps écoulé — Blancs ont dépassé 5 minutes"};
            setGameOver(end);
            try{audio.sfxError();}catch(e){}
            addLog("⏱ Temps écoulé ! Blancs perdent !");
            const res=updateSeason(false,"TEMPS",vsAI);
            setPtsResult(res);
            if(onGameEnd&&playerColor==="local")setTimeout(()=>onGameEnd(end),2200);
            return 0;
          }
          if(t===60||t===30||t===10) try{audio.sfxAlert();}catch(e){}
          return t-1;
        });
      } else {
        setTimeB(t=>{
          if(t<=1){
            clearInterval(interval);
            const end={winner:"W",reason:"Temps écoulé — Bleus ont dépassé 5 minutes"};
            setGameOver(end);
            try{audio.sfxError();}catch(e){}
            addLog("⏱ Temps écoulé ! Bleus perdent !");
            const res=updateSeason(false,"TEMPS",vsAI);
            setPtsResult(res);
            if(onGameEnd&&playerColor==="local")setTimeout(()=>onGameEnd(end),2200);
            return 0;
          }
          if(t===60||t===30||t===10) try{audio.sfxAlert();}catch(e){}
          return t-1;
        });
      }
    },1000);
    return()=>clearInterval(interval);
  },[turn,gameOver]);

  useEffect(()=>{
    if(gameOver) return;
    const c=getAllCaptures(turn,board);setMC(c);
    if(Object.keys(c).length>0){try{audio.sfxAlert();}catch(e){};addLog(`⚠ ${turn==="W"?T.turn_white.split(" ")[0]:T.turn_blue.split(" ")[0]} : capture !`);}
  },[turn,board,gameOver]);

  useEffect(()=>{if(logRef.current)logRef.current.scrollTop=logRef.current.scrollHeight;},[log]);

  // IA
  useEffect(()=>{
    if(!vsAI||gameOver||turn===playerColor)return;
    setAiThinking(true);
    const delay=aiDiff==="n1"?300:aiDiff==="n2"?400:aiDiff==="n3"?600:aiDiff==="n4"?800:600;
    const timer=setTimeout(()=>{
      // Calcul du coup IA dans un microtask pour ne pas bloquer le rendu de "réflexion"
      const compute=()=>{
        let mv=null;
        try{ mv=getAIMove(board,turn,aiDiff); }
        catch(e){ mv=null; }
        // Filet de sécurité : si l'IA n'a rien renvoyé, jouer un coup légal au hasard
        if(!mv){
          try{
            const all=getAllMoves(turn,board);
            if(all&&all.length) mv=all[Math.floor(Math.random()*all.length)];
          }catch(e){}
        }
        if(mv) applyMove(mv.from,mv.to,board,turn,true);
        setAiThinking(false);
      };
      // Laisser le navigateur peindre l'état "réflexion" avant le calcul lourd (n5–n7)
      if(typeof requestAnimationFrame==="function"){ requestAnimationFrame(()=>setTimeout(compute,0)); }
      else compute();
    },delay);
    return()=>clearTimeout(timer);
  },[turn,vsAI,gameOver]);

  const applyMove=(from,to,cb,ct,isAI=false)=>{
    // Sauvegarder l'état pour annulation (limité aux 20 derniers coups)
    setHintMove(null); // effacer l'indice après un coup
    const nb={...cb};
    const piece={...nb[from]};
    const isCapture=!!nb[to];
    if(isCapture){
      const capPiece=nb[to];
      setCaptured(p=>({...p,[ct]:[...p[ct],{type:capPiece.type}]}));
      addLog(`💥 ${piece.type} capture ${capPiece.type}`);
      try{audio.sfxCapture();}catch(e){}
      haptic(30);
      const br=boardRef.current?.getBoundingClientRect();
      if(br){const{c,r}=toRC(to);burst(br.left+c*38+19,br.top+r*38+19,ct==="W"?C.red:C.orange,14,7);}
    }else{addLog(`→ ${piece.type}: ${from}→${to}`);try{audio.sfxMove();}catch(e){}haptic(12);try{audio.sfxTrace();}catch(e){}}
    delete nb[from];nb[to]=piece;
    const newMsc=isCapture?0:msc+1;
    setBoard(nb);setMSC(newMsc);setSel(null);setVM([]);setCaps([]);
    setLastFrom(from);setLastTo(to);
    const thisMove = moveCount + 1; setMoveCount(thisMove);
    const end=checkEnd(nb,to,ct,newMsc);
    if(end){
      setGameOver(end);
      if(end.winner){
        try{audio.sfxVictory();}catch(e){};try{MusicPlayer.play("victory",false);}catch(e){}
        addLog(`🏆 ${end.winner==="W"?"BLANCS":"BLEUS"} — ${end.reason}`);
        // Mettre à jour les points saison
        const won=(end.winner===playerColor)||(vsAI&&end.winner===playerColor);
        const vsName=vsAI?"IA":(end.winner==="W"?"Joueur Bleu":"Joueur Blanc");
        const res=updateSeason(won,vsName,vsAI,end.type||"infiltration",0,{moves:thisMove,aiDiff});
        setPtsResult(res);
      }else{try{audio.sfxDraw();}catch(e){};try{MusicPlayer.play("defeat",false);}catch(e){}addLog(`🤝 ${end.reason}`);updateSeason(false,"NULLE",vsAI);}
      if(onGameEnd&&playerColor==="local")setTimeout(()=>onGameEnd(end),2200);
      return;
    }
    setTurn(t=>t==="W"?"B":"W");
  };

  const handleClick=(coord,evt)=>{
    if(gameOver)return;
    // Initialiser l'audio au premier clic (requis par les navigateurs)
    if(!audio.initialized){try{audio.init();audio.resume();}catch(e){}}
    // Mode local (2 joueurs) : les deux peuvent jouer selon leur tour
    // Mode vsAI : bloquer si ce n'est pas le tour du joueur humain
    if(vsAI&&turn!==playerColor)return;
    // Mode solo (non-local, non-IA) : bloquer si ce n'est pas son tour
    if(!vsAI&&playerColor!=="local"&&turn!==playerColor)return;
    const star=board[coord];const hasMand=Object.keys(mc).length>0;
    if(sel){
      if([...vm,...caps].includes(coord)){
        const isCapture=!!board[coord];
        if(!isCapture&&hasMand){try{audio.sfxError();}catch(e){}setFlash("err");setTimeout(()=>setFlash(null),500);addLog("⛔ Capture obligatoire !");return;}
        applyMove(sel,coord,board,turn);
      }else if(star?.color===turn){
        if(hasMand&&!mc[coord]){try{audio.sfxError();}catch(e){}return;}
        selectPiece(coord,board,hasMand);
      }else{setSel(null);setVM([]);setCaps([]);}
    }else{
      if(star?.color===turn){
        if(hasMand&&!mc[coord]){try{audio.sfxError();}catch(e){}return;}
        selectPiece(coord,board,hasMand);
      }
    }
  };

  const selectPiece=(coord,b,hasMand)=>{
    try{audio.sfxSelect();}catch(e){}
    const{moves,captures:c}=getMoves(coord,b);
    setSel(coord);setVM(hasMand?[]:moves);setCaps(hasMand?(mc[coord]||[]):c);
  };

  const reset=()=>{
    setBoard({...INIT_BOARD});setTurn("B");setSel(null);setVM([]);setCaps([]);
    setMC({});setLog(["Nouvelle partie !"]);setCaptured({W:[],B:[]});
    setMSC(0);setGameOver(null);setFlash(null);setLastFrom(null);setLastTo(null);setPtsResult(null);
    setTimeW(300);setTimeB(300);setHintMove(null);setHintsUsed(0);setShowConfirmQuit(false);setShowDrawOffer(false);setDrawPending(false);
    try{audio.sfxBattleStart();}catch(e){}
    try{MusicPlayer.play("combat");}catch(e){}
  };

  // ── Auto-sauvegarde de la partie (reprise après fermeture) ──
  useEffect(()=>{
    // Ne pas sauvegarder le mode en ligne (géré par le serveur), ni une partie terminée
    if(gameOver){ clearGameState(); return; }
    // Sauvegarder seulement les modes local et VS IA
    saveGameState({ board, turn, captured, msc, timeW, timeB,
      mode: vsAI?"ai":"local", playerColor, aiDiff });
  },[board,turn,gameOver]);

  // ── Indice : utilise l'IA pour suggérer le meilleur coup ──
  const showHintMove=()=>{
    if(gameOver||aiThinking||sel)return;
    const activeColor=playerColor==="local"?turn:(vsAI?playerColor:turn);
    if(turn!==activeColor&&playerColor!=="local")return;
    // Indices : 2 gratuits par partie, puis 10 étoiles chacun
    if(hintsUsed>=FREE_HINTS){
      const s=getSeason();
      if((s.stars||0) < HINT_COST){
        setHintMsg(tUI("Étoiles insuffisantes pour un indice",lang));
        try{audio.sfxError();}catch(e){}
        setTimeout(()=>setHintMsg(null),2200);
        return;
      }
      // Débiter 10 étoiles
      s.stars=Math.max(0,(s.stars||0)-HINT_COST);
      try{localStorage.setItem(SEASON_KEY,JSON.stringify(s));}catch(e){}
      setHintMsg("-"+HINT_COST+" ⭐");
      setTimeout(()=>setHintMsg(null),1800);
    }
    try{audio.sfxAlert();}catch(e){}
    haptic(15);
    const best=getAIMove(board,turn,"n4");
    if(best){
      setHintMove(best);
      setHintsUsed(h=>h+1);
      addLog(`💡 Suggestion : ${best.from} → ${best.to}`);
      setTimeout(()=>setHintMove(null),3000);
    }
  };

  // Ref sur le conteneur plateau pour mesure de taille
  const boardContainerRef = useRef(null);
  const CELL = useBoardSize(boardContainerRef);

  // Retournement plateau selon couleur joueur
  // "local" = mode 2 joueurs = vue neutre (pas de retournement)
  const viewLayout = playerColor==="W"
    ? [...BOARD_LAYOUT].reverse()
    : BOARD_LAYOUT; // "B" ou "local" → layout normal

  const fmt = s => `${Math.floor(s/60)}:${(s%60).toString().padStart(2,"0")}`;

  return(
    <div style={{width:"100%",height:"100%",display:"flex",flexDirection:"column",
      background:`linear-gradient(180deg,#04080f,${C.void})`,overflow:"hidden",position:"relative"}}>
      <ParticleSystem particles={particles}/>
      {flash&&<div style={{position:"absolute",inset:0,background:"rgba(255,68,102,.13)",
        animation:"cFlash .5s ease",pointerEvents:"none",zIndex:20}}/>}

      {/* ── BANDEAU CHRONOS (deux chronos centrés sur une ligne) ── */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:10,
        padding:"6px 10px",flexShrink:0,position:"relative",
        background:"rgba(8,14,30,.55)",borderBottom:"1px solid rgba(74,158,255,.1)"}}>
        {/* Chrono adversaire (haut) */}
        {(()=>{const t=playerColor==="local"?timeB:(playerColor==="W"?timeB:timeW);
          const lbl=playerColor==="local"?"BLEUS":(vsAI?"IA":"ADV.");
          const col=playerColor==="W"?C.blue:(playerColor==="local"?C.blue:C.white);
          return(
          <div style={{display:"flex",alignItems:"center",gap:5}}>
            <span style={{fontSize:7,letterSpacing:1.5,fontFamily:"'Orbitron',monospace",
              color:turn!==playerColor&&playerColor!=="local"?col:C.dim}}>{lbl}</span>
            <div style={{fontSize:13,fontFamily:"'Orbitron',monospace",fontWeight:900,
              color:t<=30?C.red:t<=60?C.orange:col,
              animation:t<=10?"pls .5s infinite":"none",
              background:t<=30?"rgba(255,68,102,.14)":"transparent",
              padding:"2px 8px",borderRadius:6,minWidth:48,textAlign:"center",
              border:`1px solid ${t<=30?C.red:t<=60?C.orange:"transparent"}`}}>{fmt(t)}</div>
          </div>);})()}
        <span style={{fontSize:9,color:C.dim,opacity:.6}}>⏱</span>
        {/* Chrono joueur (bas) */}
        {(()=>{const t=playerColor==="local"?timeW:(playerColor==="W"?timeW:timeB);
          const lbl=playerColor==="local"?"BLANCS":"VOUS";
          const col=(playerColor==="W"||playerColor==="local")?C.white:C.blue;
          return(
          <div style={{display:"flex",alignItems:"center",gap:5}}>
            <div style={{fontSize:13,fontFamily:"'Orbitron',monospace",fontWeight:900,
              color:t<=30?C.red:t<=60?C.orange:col,
              animation:t<=10?"pls .5s infinite":"none",
              background:t<=30?"rgba(255,68,102,.14)":"transparent",
              padding:"2px 8px",borderRadius:6,minWidth:48,textAlign:"center",
              border:`1px solid ${t<=30?C.red:t<=60?C.orange:"transparent"}`}}>{fmt(t)}</div>
            <span style={{fontSize:7,letterSpacing:1.5,fontFamily:"'Orbitron',monospace",
              color:turn===playerColor||playerColor==="local"?col:C.dim}}>{lbl}</span>
          </div>);})()}
        {onQuit&&(
          <button onClick={()=>{try{audio.sfxClick();}catch(e){}onQuit();}}
            style={{position:"absolute",right:8,top:"50%",transform:"translateY(-50%)",
              background:"rgba(255,68,102,.12)",border:`1px solid ${C.red}35`,borderRadius:7,
              padding:"3px 8px",color:C.red,cursor:"pointer",fontSize:11,
              fontFamily:"'Orbitron',monospace"}}>✕</button>
        )}
      </div>

      {/* ── BARRE ADVERSAIRE (haut) ── */}
      <div style={{display:"flex",alignItems:"center",gap:6,padding:"5px 10px",
        background:"rgba(74,158,255,.06)",borderBottom:`1px solid rgba(74,158,255,.1)`,
        flexShrink:0,minHeight:36}}>
        <StarSVG type={playerColor==="W"?"Rigel":"Sirus"}
          color={playerColor==="W"?C.blue:C.white} size={18} glow={false}/>
        <div style={{flex:1,minWidth:0}}>
          <div style={{fontSize:8,fontWeight:700,letterSpacing:2,
            color:playerColor==="local"?(turn!=="W"?C.blue:C.dim):(playerColor==="W"?C.blue:C.white),
            fontFamily:"'Orbitron',monospace"}}>
            {playerColor==="local"?"JOUEUR 2 · BLEUS":(playerColor==="W"?"BLEUS":"BLANCS")}
            {playerColor!=="local"&&turn===(playerColor==="W"?"W":"B")&&
              <span style={{fontSize:7,color:C.dim,marginLeft:5}}>en attente</span>}
          </div>
          {/* Captures adversaires (ses pertes) */}
          <div style={{display:"flex",gap:2,flexWrap:"wrap",marginTop:1}}>
            {(captured[playerColor==="local"?"B":(playerColor==="W"?"B":"W")]||[]).map((s,i)=>
              <StarSVG key={i} type={s.type}
                color={playerColor==="W"?C.blue:C.white} size={11} glow={false}/>)}
          </div>
        </div>
      </div>

      {/* ── INDICATEUR TOUR ── */}
      <div style={{display:"flex",alignItems:"center",gap:6,padding:"3px 10px",
        background:turn===playerColor
          ?"rgba(0,255,136,.06)":"rgba(74,158,255,.04)",
        borderBottom:`1px solid ${turn===playerColor?"rgba(0,255,136,.15)":"rgba(74,158,255,.07)"}`,
        flexShrink:0}}>
        <div style={{width:6,height:6,borderRadius:"50%",flexShrink:0,
          background:turn===playerColor?C.green:"rgba(74,158,255,.3)",
          boxShadow:turn===playerColor?`0 0 6px ${C.green}`:"none",
          animation:turn===playerColor?"pls 1.2s infinite":"none"}}/>
        <span style={{fontSize:8,fontWeight:700,letterSpacing:2,
          color:turn===playerColor?C.green:C.dim,
          fontFamily:"'Orbitron',monospace",flex:1}}>
          {playerColor==="local"
            ?(turn==="W"?"★ BLANCS jouent":"✦ BLEUS jouent")
            :turn===playerColor?"VOTRE TOUR"
            :vsAI?T.ai_thinking:"ADVERSAIRE JOUE"}
          {aiThinking&&<span style={{color:C.gold}}> …</span>}
        </span>
        {/* Capture obligatoire */}
        {Object.keys(mc).length>0&&turn===playerColor&&(
          <span style={{fontSize:7,color:C.red,fontWeight:700,letterSpacing:1,
            animation:"pls .7s infinite"}}>⚡ CAPTURE</span>
        )}
        {/* MSC */}
        <span style={{fontSize:7,color:C.dim,letterSpacing:1,marginLeft:"auto"}}>
          {msc}/50
        </span>
        {/* Résultat fin de partie */}
        {gameOver&&(
          <span style={{fontSize:8,fontWeight:700,letterSpacing:1.5,
            color:gameOver.winner
              ?(gameOver.winner===playerColor||playerColor==="local"?C.gold:C.red)
              :C.dim,
            fontFamily:"'Orbitron',monospace"}}>
            {gameOver.winner
              ?(playerColor==="local"
                ?`🏆 ${gameOver.winner==="W"?"BLANCS":"BLEUS"} GAGNENT`
                :(gameOver.winner===playerColor?"🏆 VICTOIRE":"💔 DÉFAITE"))
              :`🤝 NULLE`}
          </span>
        )}
      </div>

      {/* Message paiement indice */}
      {hintMsg&&(
        <div style={{textAlign:"center",padding:"2px 0",flexShrink:0,
          fontSize:9,fontWeight:700,fontFamily:"'Orbitron',monospace",
          color:hintMsg.indexOf("-")===0?C.gold:C.red,animation:"zIn .3s ease"}}>{hintMsg}</div>
      )}
      {/* ── BARRE D'ACTIONS (en haut, ne masque jamais le plateau ni le chrono) ── */}
      {!gameOver&&(
        <div style={{display:"flex",gap:6,padding:"4px 8px 6px",justifyContent:"center",flexShrink:0,width:"100%",boxSizing:"border-box"}}>
          <button onClick={()=>{try{audio.sfxClick();}catch(e){}setShowDrawOffer(true);}} disabled={aiThinking}
            style={{flex:1,minWidth:0,padding:"6px 2px",borderRadius:9,
              background:!aiThinking?"rgba(150,160,190,.12)":"rgba(40,48,65,.4)",
              border:`1px solid ${!aiThinking?"rgba(180,195,230,.45)":C.dim+"20"}`,
              color:!aiThinking?"#b8c5e6":C.dim,
              cursor:!aiThinking?"pointer":"not-allowed",
              fontFamily:"'Orbitron',monospace",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:2}}>
            <span style={{fontSize:15,lineHeight:1}}>🤝</span>
            <span style={{fontSize:7.5,fontWeight:700,letterSpacing:.3}}>{tUI("NULLE",lang)}</span>
          </button>
          <button onClick={showHintMove} disabled={aiThinking||!!sel}
            style={{flex:1,minWidth:0,padding:"6px 2px",borderRadius:9,
              background:!aiThinking&&!sel?"rgba(240,192,64,.12)":"rgba(40,48,65,.4)",
              border:`1px solid ${!aiThinking&&!sel?C.gold+"45":C.dim+"20"}`,
              color:!aiThinking&&!sel?C.gold:C.dim,
              cursor:!aiThinking&&!sel?"pointer":"not-allowed",
              fontFamily:"'Orbitron',monospace",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:2}}>
            <span style={{fontSize:15,lineHeight:1}}>💡</span>
            <span style={{fontSize:7.5,fontWeight:700,letterSpacing:.3}}>{tUI("INDICE",lang)}</span>
            <span style={{fontSize:6.5,color:hintsUsed<FREE_HINTS?C.green:C.gold,letterSpacing:.3,marginTop:1}}>
              {hintsUsed<FREE_HINTS?(FREE_HINTS-hintsUsed)+" "+tUI("gratuit(s)",lang):HINT_COST+"⭐"}
            </span>
          </button>
          <button onClick={()=>{try{audio.sfxClick();}catch(e){}setShowConfirmQuit(true);}}
            style={{flex:1,minWidth:0,padding:"6px 2px",borderRadius:9,
              background:"rgba(255,68,102,.1)",border:`1px solid ${C.red}38`,color:C.red,
              cursor:"pointer",
              fontFamily:"'Orbitron',monospace",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:2}}>
            <span style={{fontSize:15,lineHeight:1}}>🏳</span>
            <span style={{fontSize:7.5,fontWeight:700,letterSpacing:.3}}>{tUI("ABANDON",lang)}</span>
          </button>
        </div>
      )}

      {/* ── PLATEAU (prend tout l'espace restant) ── */}
      <div ref={boardContainerRef}
        style={{flex:1,display:"flex",alignItems:"center",justifyContent:"center",
          overflow:"hidden",padding:2}}>
        <div style={{display:"flex",flexDirection:"column",gap:3,
          padding:10,borderRadius:14,
          background:THEME_BOARD_BG[getBoardTheme()]||"radial-gradient(ellipse at center,rgba(28,48,90,.65),rgba(10,18,40,.85))",
          border:`1.5px solid ${THEME_BORDER_COLOR[getBoardTheme()]||"rgba(130,195,255,.35)"}`,
          boxShadow:"0 0 40px rgba(74,158,255,.25),inset 0 0 50px rgba(15,30,60,.5)"}}>
          {viewLayout.map((row,ri)=>(
            <div key={ri} style={{display:"flex",gap:3}}>
              {row.map((coord,ci)=>{
                if(!coord) return <div key={ci} style={{width:CELL,height:CELL}}/>;
                const star=board[coord];
                const isSel=sel===coord,isVM=vm.includes(coord),isCap=caps.includes(coord);
                const isMandSrc=Object.keys(mc).includes(coord)&&!sel&&(playerColor==="local"?true:turn===playerColor);
                const isLastFrom=lastFrom===coord,isLastTo=lastTo===coord;
                const isHintFrom=hintMove&&hintMove.from===coord,isHintTo=hintMove&&hintMove.to===coord;
                let bg=THEME_CELL_BG[getBoardTheme()]||"rgba(32,52,95,.95)",brd="rgba(130,195,255,.65)",shadow="inset 0 0 10px rgba(90,160,255,.18),0 0 4px rgba(74,158,255,.25)";
                const colIdx="ABCDEFG".indexOf(coord[0]),rowIdx=parseInt(coord[1])-1;
                let cellAnim=`cellRise .5s cubic-bezier(.22,1,.36,1) ${((colIdx+rowIdx)*0.035).toFixed(2)}s both`;
                const vmDelay=(([...vm,...caps].indexOf(coord))*0.04).toFixed(2);
                if(coord==="D1"){bg="rgba(30,70,210,.45)";brd=C.blue;shadow=`inset 0 0 16px ${C.blue}40`;}
                if(coord==="D9"){bg="rgba(200,220,255,.28)";brd=C.white;shadow="inset 0 0 16px rgba(255,255,255,.25)";}
                if(isLastFrom&&!star){bg="rgba(74,158,255,.07)";brd=`${C.blue}55`;}
                if(isLastTo){bg="rgba(0,229,255,.12)";brd=C.cyan;shadow=`0 0 8px ${C.cyan}40`;cellAnim=`landPulse .7s ease-out`;}
                if(isVM){bg="rgba(0,255,136,.1)";brd=C.green;}
                if(isCap){bg="rgba(255,68,102,.18)";brd=C.red;shadow=`0 0 8px ${C.red}45`;}
                if(isSel){bg="rgba(74,158,255,.28)";brd=C.cyan;shadow=`0 0 12px ${C.cyan}55`;cellAnim="selHalo 1.8s ease-in-out infinite";}
                if(isMandSrc){brd=C.red;shadow=`0 0 9px ${C.red}55`;cellAnim="pls 1s infinite";}
                if(isHintFrom){bg="rgba(240,192,64,.22)";brd=C.gold;shadow=`0 0 14px ${C.gold}70`;cellAnim="pls .7s infinite";}
                if(isHintTo){bg="rgba(240,192,64,.14)";brd=C.gold;shadow=`0 0 10px ${C.gold}50`;cellAnim="pls .9s infinite";}
                const r=Math.max(3, Math.round(CELL*0.1));
                return(
                  <div key={coord} onClick={e=>handleClick(coord,e)} className="cell-h"
                    role="button" tabIndex={0}
                    aria-label={`Case ${coord}${star?(star.color==="W"?", étoile blanche ":", étoile bleue ")+star.type:", vide"}`}
                    onKeyDown={(e)=>{if(e.key==="Enter"||e.key===" "){e.preventDefault();handleClick(coord,e);}}}
                    style={{width:CELL,height:CELL,background:bg,
                      border:`${CELL>44?2.5:2}px solid ${brd}`,borderRadius:r,
                      cursor:"pointer",display:"flex",alignItems:"center",
                      justifyContent:"center",position:"relative",
                      boxShadow:shadow,animation:cellAnim}}>
                    {(coord==="D1"||coord==="D9")&&!star&&(
                      <div style={{position:"absolute",inset:0,borderRadius:r,background:coord==="D1"?`radial-gradient(circle,${C.blue}22,transparent 70%)`:"radial-gradient(circle,rgba(255,255,255,.18),transparent 70%)",animation:"zoneShimmer 2.5s ease-in-out infinite",pointerEvents:"none"}}/>)}
                    {!star&&coord==="D1"&&(
                      <span style={{fontSize:Math.max(5,CELL*.1),color:C.blue,
                        fontFamily:"'Orbitron',monospace",fontWeight:700,opacity:.7,zIndex:1}}>D1</span>)}
                    {!star&&coord==="D9"&&(
                      <span style={{fontSize:Math.max(5,CELL*.1),color:C.white,
                        fontFamily:"'Orbitron',monospace",fontWeight:700,opacity:.7,zIndex:1}}>D9</span>)}
                    {isLastFrom&&!star&&(
                      <div style={{position:"absolute",inset:2,borderRadius:r,
                        border:`1px dashed ${C.blue}40`}}/>)}
                    {isVM&&!star&&(
                      <div style={{width:Math.round(CELL*.26),height:Math.round(CELL*.26),
                        borderRadius:"50%",background:`radial-gradient(circle,${C.green},rgba(0,255,136,.4))`,
                        boxShadow:`0 0 ${Math.round(CELL*.16)}px ${C.green}`,
                        animation:`moveDotIn .35s cubic-bezier(.34,1.56,.64,1) ${vmDelay}s both, moveDotBreathe 1.6s ease-in-out ${vmDelay}s infinite`}}/>)}
                    {isCap&&star&&(
                      <><div style={{position:"absolute",inset:-2,borderRadius:r+2,border:`2px solid ${C.red}`,animation:"capRing 1s ease-out infinite",pointerEvents:"none"}}/>
                      <div style={{position:"absolute",top:2,right:2,
                        width:Math.round(CELL*.14),height:Math.round(CELL*.14),
                        borderRadius:"50%",background:C.red,
                        boxShadow:`0 0 5px ${C.red}`,animation:"capCorner .7s ease-in-out infinite",zIndex:5}}/></>)}
                    {star&&(
                      <div style={{zIndex:3,animation:isSel?"pieceLevitate 1.6s cubic-bezier(.45,0,.55,1) infinite":"none",transition:"transform .3s cubic-bezier(.34,1.56,.64,1)"}}>
                        <StarSVG type={star.type}
                          color={star.color==="W"?getEquippedSkinColor(C.white,true):C.blue}
                          size={Math.round(CELL*.78)}
                          glow={isSel||isCap||isMandSrc}
                          flipped={playerColor==="W"}/>
                      </div>)}
                    <span style={{position:"absolute",top:1,left:2,
                      fontSize:Math.min(Math.max(5,Math.round(CELL*.1)),11),
                      color:"rgba(74,158,255,.22)",fontFamily:"monospace",
                      pointerEvents:"none",userSelect:"none",zIndex:1}}>{coord}</span>
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </div>

      {/* ── OVERLAY FIN DE PARTIE (dans GameBoard) ── */}
      {gameOver&&playerColor!=="local"&&(
        <div style={{position:"absolute",inset:0,zIndex:80,pointerEvents:"auto",
          background:"rgba(3,4,10,.94)",
          display:"flex",flexDirection:"column",alignItems:"center",
          justifyContent:"center",padding:"20px",gap:10,
          animation:"zIn .5s cubic-bezier(.34,1.56,.64,1)"}}>
          <Starfield count={gameOver.winner?100:40}/>

          {/* Étoile vainqueur — couleur de l'équipe gagnante */}
          <div style={{animation:"flt 3s ease-in-out infinite"}}>
            <StarSVG
              type={gameOver.winner==="W"?"Sirus":gameOver.winner==="B"?"Rigel":"Sirus"}
              color={gameOver.winner==="W"?C.white:gameOver.winner==="B"?C.blue:C.dim}
              size={66} glow={!!gameOver.winner} anim={!!gameOver.winner}
              flipped={gameOver.winner==="W"}/>
          </div>

          {/* Famille gagnante */}
          {gameOver.winner?(
            <div style={{textAlign:"center"}}>
              <div style={{fontSize:9,letterSpacing:5,
                color:gameOver.winner==="W"?C.white:C.blue,
                fontFamily:"'Orbitron',monospace",fontWeight:700,marginBottom:4}}>
                {gameOver.winner==="W"?"★ FAMILLE BLANCHE":"✦ FAMILLE BLEUE"}
              </div>
              <div style={{
                fontSize:playerColor==="local"?22:24,fontWeight:900,
                letterSpacing:4,fontFamily:"'Orbitron',monospace",
                color:playerColor==="local"?C.gold
                  :(gameOver.winner===playerColor?C.gold:C.red),
                textShadow:playerColor==="local"||gameOver.winner===playerColor
                  ?`0 0 28px ${C.gold}`:"none",
                animation:playerColor==="local"||gameOver.winner===playerColor
                  ?"glwG 1.5s ease-in-out infinite":"none"}}>
                {playerColor==="local"?"VICTOIRE"
                  :(gameOver.winner===playerColor?"VICTOIRE":"DÉFAITE")}
              </div>
              {playerColor!=="local"&&(
                <div style={{fontSize:8,color:C.dim,marginTop:4,letterSpacing:1.5}}>
                  {gameOver.winner===playerColor
                    ?`contre les ${gameOver.winner==="W"?"Bleus":"Blancs"}`
                    :`les ${gameOver.winner==="W"?"Blancs":"Bleus"} ont gagné`}
                </div>
              )}
            </div>
          ):(
            <div style={{fontSize:20,fontWeight:900,color:C.dim,
              letterSpacing:4,fontFamily:"'Orbitron',monospace"}}>{tUI("NULLE",lang)}</div>
          )}

          {/* Raison */}
          <div style={{background:"rgba(10,18,35,.9)",
            border:`1px solid ${gameOver.winner?C.gold:C.dim}28`,
            borderRadius:10,padding:"7px 16px",maxWidth:"100%"}}>
            <div style={{fontSize:8.5,color:gameOver.winner?C.gold:C.dim,
              textAlign:"center",letterSpacing:1}}>
              {gameOver.reason}
            </div>
          </div>

          {/* Récompenses : étoiles gagnées + points de classement */}
          {ptsResult&&(
            <div style={{textAlign:"center"}}>
              {/* Étoiles gagnées — la récompense principale */}
              {ptsResult.stars>0&&(
                <div style={{display:"inline-flex",alignItems:"center",gap:6,
                  padding:"6px 16px",borderRadius:20,marginBottom:6,
                  background:`linear-gradient(135deg,${C.gold}22,${C.orange}14)`,
                  border:`1px solid ${C.gold}45`}}>
                  <span style={{fontSize:16}}>⭐</span>
                  <span style={{fontSize:15,fontWeight:900,color:C.gold,
                    fontFamily:"'Orbitron',monospace",letterSpacing:1}}>+{ptsResult.stars}</span>
                  <span style={{fontSize:8,color:C.dim,letterSpacing:1}}>ÉTOILES</span>
                </div>
              )}
              {/* Points de classement (uniquement parties classées, jamais contre l'IA) */}
              {ptsResult.ranked&&ptsResult.pts!==0&&(
                <div style={{fontSize:11,fontWeight:700,
                  color:ptsResult.pts>0?C.green:C.red,
                  fontFamily:"'Orbitron',monospace",letterSpacing:1}}>
                  {ptsResult.pts>0?"+":""}{ptsResult.pts} pts classement
                </div>
              )}
              {!ptsResult.ranked&&(
                <div style={{fontSize:8,color:C.dim,marginTop:2,letterSpacing:1,textAlign:"center"}}>
                  Entraînement — non classé
                </div>
              )}
              {ptsResult.bonusStreak>0&&(
                <div style={{fontSize:8,color:C.cyan,marginTop:1}}>
                  +{ptsResult.bonusStreak} pts bonus série
                </div>
              )}
            </div>
          )}

          {/* Actions */}
          <div style={{display:"flex",gap:10,width:"100%",maxWidth:260,marginTop:4}}>
            <button onClick={()=>{reset();try{audio.sfxBattleStart();}catch(e){}}}
              className="btn-c"
              style={{flex:1,padding:"11px",
                background:`linear-gradient(135deg,${C.blue},${C.cyan})`,
                borderRadius:10,color:C.void,fontSize:10,fontWeight:900,
                letterSpacing:2,fontFamily:"'Orbitron',monospace",
                boxShadow:`0 0 16px ${C.blue}45`}}>
              REVANCHE
            </button>
            {onGameEnd&&(
              <button onClick={()=>{try{audio.sfxClick();}catch(e){}if(onGameEnd)onGameEnd(gameOver);}}
                style={{flex:1,padding:"11px",background:"rgba(10,18,35,.9)",
                  border:`1px solid ${C.dim}38`,borderRadius:10,
                  color:C.white,fontSize:10,cursor:"pointer",
                  letterSpacing:2,fontFamily:"'Orbitron',monospace"}}>
                MENU
              </button>
            )}
          </div>
        </div>
      )}

      {/* Confirmation abandon */}
      {showConfirmQuit&&(
        <div style={{position:"absolute",inset:0,zIndex:60,background:"rgba(3,4,10,.88)",
          display:"flex",alignItems:"center",justifyContent:"center",padding:20,
          animation:"zIn .2s ease"}} onClick={()=>setShowConfirmQuit(false)}>
          <div onClick={e=>e.stopPropagation()} style={{background:"rgba(10,18,35,.97)",
            border:`1px solid ${C.red}40`,borderRadius:16,padding:"24px 20px",maxWidth:300,
            textAlign:"center",boxShadow:`0 0 30px ${C.red}25`}}>
            <div style={{fontSize:32,marginBottom:8}}>🏳</div>
            <div style={{fontSize:13,color:C.white,fontWeight:900,letterSpacing:1,marginBottom:6,
              fontFamily:"'Orbitron',monospace"}}>{tUI("ABANDONNER ?",lang)}</div>
            <div style={{fontSize:10,color:C.dim,marginBottom:18,lineHeight:1.5}}>
              Vous perdrez la partie. {vsAI?"L'IA sera déclarée vainqueur.":"Votre adversaire gagnera."}
            </div>
            <div style={{display:"flex",gap:8}}>
              <button onClick={()=>{setShowConfirmQuit(false);try{audio.sfxClick();}catch(e){}}}
                style={{flex:1,padding:"10px",background:"rgba(74,158,255,.1)",
                  border:`1px solid ${C.blue}40`,borderRadius:10,color:C.blue,
                  fontSize:10,fontWeight:700,cursor:"pointer",fontFamily:"'Orbitron',monospace"}}>
                CONTINUER
              </button>
              <button onClick={()=>{
                  setShowConfirmQuit(false);
                  const winner=playerColor==="local"?(turn==="W"?"B":"W"):(playerColor==="W"?"B":"W");
                  setGameOver({winner,reason:"Abandon",type:"forfeit"});
                  try{audio.sfxDraw();}catch(e){}try{MusicPlayer.play("defeat",false);}catch(e){}
                  haptic(50);
                }}
                style={{flex:1,padding:"10px",background:`linear-gradient(135deg,${C.red},#cc3355)`,
                  border:"none",borderRadius:10,color:"#fff",
                  fontSize:10,fontWeight:900,cursor:"pointer",fontFamily:"'Orbitron',monospace"}}>
                ABANDONNER
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Demande de match nul */}
      {showDrawOffer&&(
        <div style={{position:"absolute",inset:0,zIndex:60,background:"rgba(3,4,10,.88)",
          display:"flex",alignItems:"center",justifyContent:"center",padding:20,
          animation:"zIn .2s ease"}} onClick={()=>setShowDrawOffer(false)}>
          <div onClick={e=>e.stopPropagation()} style={{background:"rgba(10,18,35,.97)",
            border:`1px solid rgba(180,195,230,.4)`,borderRadius:16,padding:"24px 20px",maxWidth:300,
            textAlign:"center",boxShadow:"0 0 30px rgba(150,170,210,.2)"}}>
            <div style={{fontSize:32,marginBottom:8}}>🤝</div>
            <div style={{fontSize:13,color:C.white,fontWeight:900,letterSpacing:1,marginBottom:6,
              fontFamily:"'Orbitron',monospace"}}>{tUI("PROPOSER LA NULLE ?",lang)}</div>
            <div style={{fontSize:10,color:C.dim,marginBottom:18,lineHeight:1.5}}>
              {vsAI
                ?"L'ordinateur acceptera si la position est équilibrée."
                :(playerColor==="local"
                  ?`${turn==="W"?"Les Blancs proposent. Les Bleus":"Les Bleus proposent. Les Blancs"} doivent accepter.`
                  :"Votre adversaire devra accepter.")}
            </div>
            <div style={{display:"flex",gap:8}}>
              <button onClick={()=>{setShowDrawOffer(false);try{audio.sfxClick();}catch(e){}}}
                style={{flex:1,padding:"10px",background:"rgba(74,158,255,.1)",
                  border:`1px solid ${C.blue}40`,borderRadius:10,color:C.blue,
                  fontSize:10,fontWeight:700,cursor:"pointer",fontFamily:"'Orbitron',monospace"}}>
                ANNULER
              </button>
              <button onClick={()=>{
                  setShowDrawOffer(false);
                  if(vsAI){
                    // L'IA évalue : accepte si sa position n'est pas gagnante
                    const aiColor=playerColor==="W"?"B":"W";
                    let score=0; try{score=evalBoard(board,aiColor);}catch(e){score=0;}
                    // Si l'IA n'a pas un avantage clair (>250), elle accepte la nulle
                    if(score<250){
                      try{audio.sfxDraw();}catch(e){}try{MusicPlayer.play("defeat",false);}catch(e){}
                      setGameOver({winner:null,reason:"Match nul accepté",type:"draw"});
                    }else{
                      // L'IA refuse
                      setDrawPending("refused");
                      setTimeout(()=>setDrawPending(false),2500);
                      try{audio.sfxError();}catch(e){}
                    }
                  }else if(playerColor==="local"){
                    // Mode 2 joueurs : l'autre joueur doit confirmer
                    setDrawPending("local");
                  }else{
                    // Multijoueur en ligne : envoyer la demande (simulé : accepté)
                    setDrawPending("sent");
                    setTimeout(()=>{
                      try{audio.sfxDraw();}catch(e){}try{MusicPlayer.play("defeat",false);}catch(e){}
                      setGameOver({winner:null,reason:"Match nul accepté",type:"draw"});
                    },1500);
                  }
                }}
                style={{flex:1,padding:"10px",background:"linear-gradient(135deg,#8a95b5,#5a6585)",
                  border:"none",borderRadius:10,color:"#fff",
                  fontSize:10,fontWeight:900,cursor:"pointer",fontFamily:"'Orbitron',monospace"}}>
                PROPOSER
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Réponse à la demande de nulle (mode local : l'autre joueur) */}
      {drawPending==="local"&&(
        <div style={{position:"absolute",inset:0,zIndex:61,background:"rgba(3,4,10,.9)",
          display:"flex",alignItems:"center",justifyContent:"center",padding:20,animation:"zIn .2s ease"}}>
          <div style={{background:"rgba(10,18,35,.97)",border:`1px solid rgba(180,195,230,.4)`,
            borderRadius:16,padding:"24px 20px",maxWidth:300,textAlign:"center",
            boxShadow:"0 0 30px rgba(150,170,210,.2)"}}>
            <div style={{fontSize:32,marginBottom:8}}>🤝</div>
            <div style={{fontSize:12,color:C.white,fontWeight:900,letterSpacing:1,marginBottom:6,
              fontFamily:"'Orbitron',monospace"}}>
              {turn==="W"?"LES BLEUS":"LES BLANCS"} ACCEPTENT-ILS ?
            </div>
            <div style={{fontSize:10,color:C.dim,marginBottom:18,lineHeight:1.5}}>
              {turn==="W"?"Les Blancs":"Les Bleus"} proposent un match nul.
            </div>
            <div style={{display:"flex",gap:8}}>
              <button onClick={()=>{setDrawPending(false);try{audio.sfxClick();}catch(e){}}}
                style={{flex:1,padding:"10px",background:"rgba(255,68,102,.1)",
                  border:`1px solid ${C.red}40`,borderRadius:10,color:C.red,
                  fontSize:10,fontWeight:700,cursor:"pointer",fontFamily:"'Orbitron',monospace"}}>
                REFUSER
              </button>
              <button onClick={()=>{
                  setDrawPending(false);
                  try{audio.sfxDraw();}catch(e){}try{MusicPlayer.play("defeat",false);}catch(e){}
                  setGameOver({winner:null,reason:"Match nul accepté",type:"draw"});
                }}
                style={{flex:1,padding:"10px",background:"linear-gradient(135deg,#00d4aa,#00a884)",
                  border:"none",borderRadius:10,color:"#fff",
                  fontSize:10,fontWeight:900,cursor:"pointer",fontFamily:"'Orbitron',monospace"}}>
                ACCEPTER
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Notification : nulle refusée / en attente */}
      {(drawPending==="refused"||drawPending==="sent")&&(
        <div style={{position:"absolute",top:"45%",left:"50%",transform:"translate(-50%,-50%)",
          zIndex:62,background:"rgba(10,18,35,.95)",
          border:`1px solid ${drawPending==="refused"?C.red+"50":"rgba(180,195,230,.4)"}`,
          borderRadius:12,padding:"14px 22px",textAlign:"center",animation:"zIn .2s ease",
          boxShadow:"0 0 24px rgba(0,0,0,.5)"}}>
          <div style={{fontSize:11,color:drawPending==="refused"?C.red:"#b8c5e6",fontWeight:700,
            letterSpacing:1,fontFamily:"'Orbitron',monospace"}}>
            {drawPending==="refused"?"❌ NULLE REFUSÉE":"⏳ DEMANDE ENVOYÉE..."}
          </div>
        </div>
      )}

      {/* ── BARRE JOUEUR (bas) ── */}
      <div style={{display:"flex",alignItems:"center",gap:6,padding:"5px 10px",
        background:(playerColor==="W"||playerColor==="local")?"rgba(200,220,255,.05)":"rgba(74,158,255,.05)",
        borderTop:`1px solid ${(playerColor==="W"||playerColor==="local")?"rgba(200,220,255,.1)":"rgba(74,158,255,.12)"}`,
        flexShrink:0,minHeight:36}}>
        <StarSVG type={(playerColor==="W"||playerColor==="local")?"Sirus":"Rigel"}
          color={(playerColor==="W"||playerColor==="local")?C.white:C.blue} size={18} glow={false}
          flipped={playerColor==="W"}/>
        <div style={{flex:1,minWidth:0}}>
          <div style={{fontSize:8,fontWeight:700,letterSpacing:2,
            color:(playerColor==="W"||playerColor==="local")?C.white:C.blue,
            fontFamily:"'Orbitron',monospace"}}>
            {vsAI?"VOUS":(playerColor==="local"?"JOUEUR 1 · BLANCS":(playerColor==="W"?"BLANCS":"BLEUS"))}
          </div>
          {/* Mes captures */}
          <div style={{display:"flex",gap:2,flexWrap:"wrap",marginTop:1}}>
            {(captured[playerColor==="local"?"W":playerColor]||[]).map((s,i)=>
              <StarSVG key={i} type={s.type}
                color={(playerColor==="W"||playerColor==="local")?C.white:C.blue} size={11} glow={false}/>)}
          </div>
        </div>
      </div>
    </div>
  );
};
// ════════════════════════════════════════════════════════
// 📱 SCREENS PRINCIPAUX
// ════════════════════════════════════════════════════════
const SplashScreen=({onNext,lang="fr"})=>{
  const T=LANGS[lang];const[ph,setPh]=useState(0);
  useEffect(()=>{const t=[setTimeout(()=>setPh(1),350),setTimeout(()=>setPh(2),800),setTimeout(()=>setPh(3),1300)];return()=>t.forEach(clearTimeout);},[]);
  const go=()=>{
  try{audio.init();}catch(e){}
  try{audio.sfxBattleStart();}catch(e){}
  try{MusicPlayer.play("menu");}catch(e){}
  onNext();
};
  return(
    <div style={{width:"100%",height:"100%",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",background:`radial-gradient(ellipse 100% 80% at 50% 35%,#081430,${C.void})`,position:"relative",overflow:"hidden",fontFamily:"'Orbitron',monospace"}}>
      <Starfield count={130}/><Nebulas/>
      <div style={{position:"absolute",top:0,left:0,right:0,height:1,background:`linear-gradient(90deg,transparent,${C.cyan},transparent)`,animation:"scan 5s linear infinite",opacity:.22}}/>
      {[130,190,255].map((s,i)=><div key={i} style={{position:"absolute",width:s,height:s,borderRadius:"50%",border:`1px solid ${C.blue}${24-i*6}`,animation:`plsR ${3+i}s ${i*.5}s ease-out infinite`}}/>)}
      <div style={{animation:"flt 4s ease-in-out infinite",marginBottom:10,zIndex:1,opacity:ph>=1?1:0,transform:ph>=1?"scale(1)":"scale(.5)",transition:"all .6s cubic-bezier(.34,1.56,.64,1)"}}>
        <div style={{animation:"rotS 28s linear infinite",display:"inline-block"}}><StarSVG type="Sirus" color={C.cyan} size={88} anim/></div>
      </div>
      <div style={{fontSize:44,fontWeight:900,letterSpacing:10,color:C.white,fontFamily:"'Orbitron',monospace",textShadow:`0 0 8px ${C.white}, 0 0 20px ${C.cyan}, 0 0 40px ${C.blue}`,animation:"glw 3s ease-in-out infinite",zIndex:1,opacity:ph>=2?1:0,transform:ph>=2?"translateY(0)":"translateY(16px)",transition:"all .7s ease"}}>DOSCO</div>
      <div style={{fontSize:9,letterSpacing:7,color:C.blue,marginTop:4,zIndex:1,opacity:ph>=2?1:0,transition:"opacity .8s ease .2s"}}>{T.splash_sub.toUpperCase()}</div>
      <div style={{width:ph>=3?130:0,height:1,margin:"16px auto",background:`linear-gradient(90deg,transparent,${C.blue},${C.cyan},${C.blue},transparent)`,transition:"width .8s ease",zIndex:1}}/>
      <div style={{fontSize:7.5,color:C.dim,letterSpacing:4,zIndex:1,marginBottom:18,opacity:ph>=3?1:0,transition:"opacity .5s ease .3s"}}>WORLD CLASS EDITION · v5.0</div>
      <div style={{opacity:ph>=3?1:0,transform:ph>=3?"translateY(0)":"translateY(14px)",transition:"all .6s ease .4s",zIndex:1}}>
        <button onClick={go} className="btn-c" style={{padding:"14px 44px",background:`linear-gradient(135deg,rgba(74,158,255,.22),rgba(0,229,255,.13))`,border:`1.5px solid ${C.cyan}`,borderRadius:30,color:C.white,fontSize:14,fontWeight:700,boxShadow:`0 0 22px ${C.cyan}48,0 0 46px ${C.blue}26,inset 0 0 18px rgba(74,158,255,.1)`,animation:"pls 2.5s ease-in-out infinite",fontFamily:"'Orbitron',monospace",letterSpacing:5}}>{T.play}</button>
      </div>
      <div style={{position:"absolute",bottom:28,display:"flex",gap:14,zIndex:1,opacity:ph>=3?.45:0,transition:"opacity .8s ease .6s"}}>
        {["Sirus","Merak","Alioth","Deneb","Rigel"].map((t,i)=><div key={i} style={{animation:`flt ${3+i*.4}s ${i*.3}s ease-in-out infinite`}}><StarSVG type={t} color={i%2===0?C.blue:C.white} size={13} glow={false}/></div>)}
      </div>
    </div>
  );
};

const HomeScreen=({onNav,user,muted,onToggleAudio,lang,season,notifCount=0,onResume})=>{
  useEffect(()=>{if(!muted)try{MusicPlayer.play("menu");}catch(e){}},[]);
  const T=LANGS[lang];
  const[savedGame,setSavedGame]=useState(()=>loadGameState());
  const menu=[
    {icon:"🌐",label:T.menu_online,sub:T.menu_online_sub,s:"online",c:C.cyan},
    {icon:"🤖",label:T.menu_ai,sub:T.menu_ai_sub,s:"vsai",c:C.purple},
    {icon:"🏆",label:tUI("TOURNOIS",lang),sub:tUI("Compétitions à élimination",lang),s:"tournament",c:C.gold},
    {icon:"⭐",label:T.menu_rank,sub:T.menu_rank_sub,s:"ranking",c:C.gold},
    {icon:"📖",label:T.menu_story,sub:T.menu_story_sub,s:"story",c:"#ff8844"},
    {icon:"👤",label:tUI("PROFIL",lang),sub:tUI("Statistiques et succès",lang),s:"profile",c:"#e8eeff"},
    {icon:"🎯",label:tUI("MISSIONS",lang),sub:tUI("Défis à récompenses",lang),s:"missions",c:C.green},
    {icon:"💫",label:tUI("BOUTIQUE",lang),sub:tUI("Acheter des étoiles",lang),s:"shop",c:C.gold},
    {icon:"🎨",label:tUI("SKINS",lang),sub:tUI("Personnaliser les étoiles",lang),s:"customize",c:C.purple},
    {icon:"📜",label:T.menu_rules,sub:T.menu_rules_sub,s:"rules",c:C.blue},
    {icon:"🎓",label:tUI("TUTORIEL",lang),sub:tUI("Apprendre à jouer",lang),s:"tutorial",c:C.green},
    {icon:"⚙️",label:T.menu_settings,sub:T.menu_settings_sub,s:"settings",c:C.dim},
  ];
  return(
    <div style={{width:"100%",height:"100%",position:"relative",overflow:"hidden",background:`linear-gradient(180deg,#060c1e,${C.void})`,display:"flex",flexDirection:"column",fontFamily:"'Exo 2',sans-serif"}} dir={lang==="ar"?"rtl":"ltr"}>
      <Starfield count={60}/><Nebulas/>
      <div style={{padding:"12px 14px 8px",background:"linear-gradient(180deg,rgba(10,18,40,.98),rgba(10,18,40,.32))",position:"relative",zIndex:2}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:8}}>
          <div style={{animation:"sIn .5s ease"}}>
            <div style={{fontSize:7,color:C.dim,letterSpacing:4,marginBottom:3,fontFamily:"'Orbitron',monospace"}}>{T.home_commander}</div>
            <div style={{fontSize:17,fontWeight:900,color:C.white,fontFamily:"'Orbitron',monospace",letterSpacing:2,textShadow:`0 0 13px ${C.blue}48`}}>{user.name}</div>
          </div>
          <div style={{display:"flex",gap:7,alignItems:"center"}}>
            <button onClick={onToggleAudio} style={{background:"rgba(74,158,255,.1)",border:`1px solid ${C.blue}38`,borderRadius:20,padding:"4px 8px",color:C.blue,cursor:"pointer",fontSize:13,fontFamily:"monospace"}}>{muted?"🔇":"🔊"}</button>
            <NotifBadge count={notifCount||0} onClick={()=>{try{audio.sfxClick();}catch(e){}onNav("notifications");}}/>
            <div style={{background:`linear-gradient(135deg,rgba(240,192,64,.2),rgba(240,192,64,.07))`,border:`1px solid ${C.gold}52`,borderRadius:12,padding:"7px 12px",textAlign:"center",boxShadow:`0 0 10px ${C.gold}20`}}>
              <AnimatedNumber value={season?.stars??user.stars??100} style={{fontSize:18,color:C.gold,fontWeight:900,fontFamily:"'Orbitron',monospace",animation:"glwG 3s ease-in-out infinite",display:"inline-block"}}/>
              <div style={{fontSize:6.5,color:C.goldDim,letterSpacing:3}}>★ {T.home_stars}</div>
            </div>
          </div>
        </div>
        {/* Barre saison */}
        <div style={{display:"flex",gap:8,marginBottom:7}}>
          <div style={{flex:1,background:"rgba(74,158,255,.07)",border:`1px solid rgba(74,158,255,.12)`,borderRadius:8,padding:"5px 10px",textAlign:"center"}}>
            <div style={{fontSize:13,fontWeight:900,color:C.green,fontFamily:"'Orbitron',monospace"}}>{season?.wins||user.wins}</div>
            <div style={{fontSize:6.5,color:C.dim,letterSpacing:2}}>{T.home_wins}</div>
          </div>
          <div style={{flex:1,background:"rgba(255,68,102,.07)",border:`1px solid rgba(255,68,102,.12)`,borderRadius:8,padding:"5px 10px",textAlign:"center"}}>
            <div style={{fontSize:13,fontWeight:900,color:C.red,fontFamily:"'Orbitron',monospace"}}>{season?.losses||user.losses}</div>
            <div style={{fontSize:6.5,color:C.dim,letterSpacing:2}}>{T.home_losses}</div>
          </div>
          <div style={{flex:1,background:"rgba(240,192,64,.07)",border:`1px solid rgba(240,192,64,.12)`,borderRadius:8,padding:"5px 10px",textAlign:"center"}}>
            <div style={{fontSize:13,fontWeight:900,color:C.gold,fontFamily:"'Orbitron',monospace"}}>{season?.winStreak||user.streak}🔥</div>
            <div style={{fontSize:6.5,color:C.dim,letterSpacing:2}}>{T.home_streak}</div>
          </div>
          <div style={{flex:1.5,background:"rgba(136,85,255,.07)",border:`1px solid rgba(136,85,255,.12)`,borderRadius:8,padding:"5px 10px",textAlign:"center"}}>
            <div style={{fontSize:9,color:C.purple,fontFamily:"'Orbitron',monospace",fontWeight:700}}>⏱ {timeUntilReset()}</div>
            <div style={{fontSize:5.5,color:C.dim,letterSpacing:1,marginTop:1}}>{T.season_reset}</div>
          </div>
        </div>
      </div>
      <div style={{padding:"0 13px",display:"flex",flexDirection:"column",gap:6,position:"relative",zIndex:2,flex:1,overflowY:"auto"}}>
        {savedGame&&(
          <button onClick={()=>{try{audio.sfxClick();}catch(e){}if(onResume)onResume(savedGame);}} className="btn-c"
            aria-label="Reprendre la partie en cours"
            style={{display:"flex",alignItems:"center",gap:12,padding:"13px 15px",borderRadius:13,
              background:`linear-gradient(135deg,${C.green}22,${C.cyan}14)`,
              border:`1.5px solid ${C.green}55`,cursor:"pointer",marginBottom:2,
              boxShadow:`0 0 18px ${C.green}25`,animation:"pls 2.5s ease-in-out infinite"}}>
            <span style={{fontSize:22}}>⏵</span>
            <div style={{flex:1,textAlign:"left"}}>
              <div style={{fontSize:11,fontWeight:900,color:C.green,letterSpacing:1.5,
                fontFamily:"'Orbitron',monospace"}}>{tUI("REPRENDRE LA PARTIE",lang)}</div>
              <div style={{fontSize:8.5,color:C.dim,marginTop:2}}>
                {savedGame.mode==="ai"?"Contre l'ordinateur":"2 joueurs"} · en cours
              </div>
            </div>
            <span onClick={(e)=>{e.stopPropagation();clearGameState();setSavedGame(null);try{audio.sfxClick();}catch(er){}}}
              role="button" aria-label="Abandonner la partie sauvegardée"
              style={{fontSize:14,color:C.dim,padding:"4px 8px",borderRadius:6,
                background:"rgba(255,68,102,.1)"}}>✕</span>
          </button>
        )}
        {menu.map((item,i)=>(
          <button key={i} onClick={()=>{try{audio.sfxClick();}catch(e){}onNav(item.s);}} className="btn-c"
            style={{display:"flex",alignItems:"center",gap:11,background:`linear-gradient(135deg,rgba(10,16,32,.95),rgba(6,12,24,.98))`,border:`1px solid ${item.c}18`,borderLeft:`3px solid ${item.c}`,borderRadius:10,padding:"10px 13px",textAlign:"left",animation:`sUp .35s ease ${.1+i*.06}s both`,boxShadow:`inset 0 0 16px ${item.c}03`}}>
            <span style={{fontSize:20}}>{item.icon}</span>
            <div style={{flex:1}}>
              <div style={{fontSize:10.5,fontWeight:700,color:C.white,letterSpacing:1.5,fontFamily:"'Orbitron',monospace"}}>{item.label}</div>
              <div style={{fontSize:8.5,color:C.dim,marginTop:1,fontFamily:"'Exo 2',sans-serif"}}>{item.sub}</div>
            </div>
            <span style={{color:item.c,fontSize:16,opacity:.5}}>›</span>
          </button>
        ))}
      </div>
      <div style={{height:48,background:"rgba(4,6,15,.97)",borderTop:`1px solid rgba(74,158,255,.1)`,display:"flex",alignItems:"center",justifyContent:"space-around",position:"relative",zIndex:2,flexShrink:0}}>
        {[{i:"🏠",l:T.nav_home,a:true,s:"home"},{i:"🌐",l:T.nav_online,s:"online"},{i:"🏆",l:T.nav_rank,s:"ranking"},{i:"⚙️",l:T.nav_profile,s:"settings"}].map((n,i)=>(
          <button key={i} onClick={()=>{try{audio.sfxClick();}catch(e){}onNav(n.s);}} style={{textAlign:"center",background:"none",border:"none",cursor:"pointer",opacity:n.a?1:.35,padding:"3px 7px"}}>
            <div style={{fontSize:17}}>{n.i}</div>
            <div style={{fontSize:5.5,color:n.a?C.blue:C.dim,letterSpacing:1,fontFamily:"'Orbitron',monospace",marginTop:1}}>{n.l}</div>
          </button>
        ))}
      </div>
    </div>
  );
};

const GameScreen=({onNav,lang="fr",resumeState=null})=>{
  const T=LANGS[lang];
  const[gameOver,setGameOver]=useState(null);
  return(
    <div style={{width:"100%",height:"100%",background:`linear-gradient(180deg,#05091c,${C.void})`,display:"flex",flexDirection:"column",overflow:"hidden",fontFamily:"'Exo 2',sans-serif"}}>
      <Starfield count={28}/>
      {/* Plateau avec chronos intégrés (bandeau chronos + bouton quitter inclus dans GameBoard) */}
      <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden",padding:"0",zIndex:1}}>
        <GameBoard onGameEnd={setGameOver} playerColor="local" lang={lang} resumeState={resumeState} onQuit={()=>{onNav("home");}}/>
      </div>
      {/* Overlay fin de partie — version pro */}
      {gameOver&&(
        <div style={{position:"absolute",inset:0,zIndex:50,
          background:"rgba(3,4,10,.92)",
          display:"flex",flexDirection:"column",alignItems:"center",
          justifyContent:"center",padding:"20px",
          animation:"zIn .4s ease"}}>
          <Starfield count={gameOver.winner?140:60}/>

          {/* Étoile animée du vainqueur — couleur de l'équipe gagnante */}
          <div style={{animation:"flt 3s ease-in-out infinite",marginBottom:16}}>
            <StarSVG
              type={gameOver.winner==="W"?"Sirus":gameOver.winner==="B"?"Rigel":"Sirus"}
              color={gameOver.winner==="W"?C.white:gameOver.winner==="B"?C.blue:C.dim}
              size={72} glow={!!gameOver.winner} anim={!!gameOver.winner}
              flipped={gameOver.winner==="W"}/>
          </div>

          {/* Résultat principal */}
          {gameOver.winner?(
            <div style={{textAlign:"center",marginBottom:6}}>
              <div style={{fontSize:10,color:gameOver.winner==="W"?C.white:C.blue,
                letterSpacing:5,fontFamily:"'Orbitron',monospace",marginBottom:4,
                fontWeight:700}}>
                {gameOver.winner==="W"?"★ FAMILLE BLANCHE":"✦ FAMILLE BLEUE"}
              </div>
              <div style={{fontSize:28,fontWeight:900,
                color:C.gold,letterSpacing:4,
                fontFamily:"'Orbitron',monospace",
                textShadow:`0 0 30px ${C.gold}`,
                animation:"glwG 1.5s ease-in-out infinite"}}>
                VICTOIRE
              </div>
              <div style={{fontSize:9,color:C.dim,marginTop:6,letterSpacing:2}}>
                contre la {gameOver.winner==="W"?"Famille Bleue":"Famille Blanche"}
              </div>
            </div>
          ):(
            <div style={{textAlign:"center",marginBottom:6}}>
              <div style={{fontSize:22,fontWeight:900,color:C.dim,
                letterSpacing:4,fontFamily:"'Orbitron',monospace"}}>
                NULLE
              </div>
            </div>
          )}

          {/* Raison de fin */}
          <div style={{
            background:"rgba(10,18,35,.85)",
            border:`1px solid ${gameOver.winner?C.gold:C.dim}30`,
            borderRadius:10,padding:"8px 18px",
            marginBottom:18,marginTop:8}}>
            <div style={{fontSize:9,color:gameOver.winner?C.gold:C.dim,
              textAlign:"center",letterSpacing:1.5,
              fontFamily:"'Orbitron',monospace"}}>
              {gameOver.reason}
            </div>
          </div>

          {/* Boutons */}
          <div style={{display:"flex",gap:10,width:"100%",maxWidth:280}}>
            <button onClick={()=>{try{audio.sfxBattleStart();}catch(e){}onNav("game");}}
              className="btn-c"
              style={{flex:1,padding:"12px",
                background:`linear-gradient(135deg,${C.blue},${C.cyan})`,
                borderRadius:10,color:C.void,fontSize:10,fontWeight:900,
                letterSpacing:2,fontFamily:"'Orbitron',monospace",
                boxShadow:`0 0 16px ${C.blue}48`}}>
              {T.revenge}
            </button>
            <button onClick={()=>{try{audio.sfxClick();}catch(e){}onNav("home");}}
              style={{flex:1,padding:"12px",background:"rgba(10,18,35,.9)",
                border:`1px solid ${C.dim}38`,borderRadius:10,
                color:C.white,fontSize:10,cursor:"pointer",
                letterSpacing:2,fontFamily:"'Orbitron',monospace"}}>
              {T.back_home}
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

const VsAIScreen=({onNav,user,lang="fr",season,setSeason,resumeState=null})=>{
  const T=LANGS[lang];
  const[diff,setDiff]=useState(()=>resumeState?.aiDiff||"n3");
  const[playerColor,setPlayerColor]=useState(()=>resumeState?.playerColor||"W");
  const[started,setStarted]=useState(()=>!!resumeState);
  const DIFFS=[{k:"n1",l:"NAINE",d:"Aléatoire pur",c:"#88ee88",i:"⚪"},{k:"n2",l:"GÉANTE",d:"Préfère capturer",c:C.green,i:"🔴"},{k:"n3",l:"NÉBULEUSE",d:"Minimax léger",c:C.cyan,i:"🌫️"},{k:"n4",l:"PULSARE",d:"Profondeur 3",c:C.blue,i:"📡"},{k:"n5",l:"QUASAR",d:"Alpha-Beta depth-4",c:C.purple,i:"🌠"},{k:"n6",l:"SUPERNOVA",d:"Profondeur 5",c:C.orange,i:"💥"},{k:"n7",l:"TROU NOIR",d:"God Mode — depth 6",c:C.red,i:"🕳️"}];
  if(started)return(
    <div style={{width:"100%",height:"100%",background:`linear-gradient(180deg,#05091c,${C.void})`,display:"flex",flexDirection:"column",overflow:"hidden",position:"relative"}}>
      <Starfield count={25}/><Nebulas/>
      <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden",zIndex:1}}>
        <GameBoard onGameEnd={e=>{try{const s=getSeason();if(setSeason)setSeason({...s});}catch(er){}setStarted(false);if(onNav)onNav("home");}} playerColor={playerColor} vsAI={true} aiDiff={diff} lang={lang} resumeState={resumeState} onQuit={()=>setStarted(false)}/>
      </div>
    </div>
  );
  return(
    <div style={{width:"100%",height:"100%",background:`linear-gradient(180deg,#080d20,${C.void})`,display:"flex",flexDirection:"column",overflow:"hidden",fontFamily:"'Exo 2',sans-serif"}}>
      <Starfield count={45}/><Nebulas/>
      <div style={{padding:"14px 14px 0",display:"flex",alignItems:"center",gap:10,zIndex:2}}>
        <button onClick={()=>{try{audio.sfxClick();}catch(e){}onNav("home");}} style={{background:"rgba(74,158,255,.1)",border:`1px solid ${C.blue}38`,borderRadius:8,padding:"5px 10px",color:C.blue,cursor:"pointer",fontSize:15}}>‹</button>
        <div style={{fontSize:10,color:C.white,fontWeight:700,letterSpacing:3,fontFamily:"'Orbitron',monospace"}}>{T.menu_ai}</div>
      </div>
      <div style={{flex:1,overflowY:"auto",padding:"12px 14px",zIndex:2,display:"flex",flexDirection:"column",gap:10}}>
        <div style={{textAlign:"center",padding:"8px 0"}}>
          <div style={{animation:"flt 4s ease-in-out infinite",display:"inline-block"}}>
            <div style={{animation:"rotS 8s linear infinite",display:"inline-block"}}><StarSVG type="Rigel" color={C.purple} size={56} anim/></div>
          </div>
          <div style={{fontSize:8.5,color:C.purple,letterSpacing:3,marginTop:8,fontFamily:"'Orbitron',monospace"}}>{tUI("INTELLIGENCE ARTIFICIELLE DOSCO",lang)}</div>
        </div>
        <div>
          <div style={{fontSize:7.5,color:C.dim,letterSpacing:3,marginBottom:8,fontFamily:"'Orbitron',monospace"}}>{tUI("DIFFICULTÉ",lang)} <span style={{opacity:.5}}>‹ ›</span></div>
          <div className="gx-scroll" style={{display:"flex",gap:12,overflowX:"auto",overflowY:"hidden",
            scrollSnapType:"x mandatory",WebkitOverflowScrolling:"touch",padding:"4px 2px 12px",marginBottom:4}}>
            {DIFFS.map((d,i)=>{
              const sel=diff===d.k;
              return(
                <button key={d.k}
                  onClick={()=>{try{audio.sfxClick();}catch(e){}setDiff(d.k);}}
                  aria-label={`${d.l}, ${d.d}`}
                  style={{flex:"0 0 auto",width:150,scrollSnapAlign:"center",
                    display:"flex",flexDirection:"column",alignItems:"center",gap:6,padding:"14px 12px",borderRadius:16,
                    background:sel?`linear-gradient(160deg,${d.c}2e,rgba(8,12,28,.92))`:"rgba(10,18,35,.82)",
                    border:`1.5px solid ${sel?d.c:d.c+"30"}`,cursor:"pointer",
                    boxShadow:sel?`0 0 26px ${d.c}50`:"none",
                    transform:sel?"scale(1.04)":"scale(1)",transition:"transform .25s cubic-bezier(.34,1.56,.64,1),box-shadow .25s,border-color .25s,background .25s"}}>
                  <div style={{fontSize:42,lineHeight:1,animation:sel?"flt 3s ease-in-out infinite":"none"}}>{d.i}</div>
                  <div style={{fontSize:12,fontWeight:900,color:sel?d.c:C.white,letterSpacing:1,fontFamily:"'Orbitron',monospace",textAlign:"center"}}>{d.l}</div>
                  <div style={{fontSize:7.5,color:C.dim,lineHeight:1.3,textAlign:"center",minHeight:20}}>{d.d}</div>
                  <div style={{display:"flex",alignItems:"center",gap:3,marginTop:2,padding:"3px 10px",borderRadius:20,background:`${d.c}14`,border:`1px solid ${d.c}30`}}>
                    <span style={{fontSize:9,fontWeight:900,color:d.c,letterSpacing:1,fontFamily:"'Orbitron',monospace"}}>NIVEAU {i+1}</span>
                  </div>
                </button>
              );
            })}
          </div>
        </div>
        <div>
          <div style={{fontSize:7.5,color:C.dim,letterSpacing:3,marginBottom:8,fontFamily:"'Orbitron',monospace"}}>{tUI("VOTRE COULEUR",lang)}</div>
          <div style={{display:"flex",gap:8}}>
            {[{c:"W",l:"★ BLANCS",col:C.white,t:"Sirus"},{c:"B",l:"✦ BLEUS",col:C.blue,t:"Rigel"}].map(opt=>(
              <button key={opt.c} onClick={()=>{try{audio.sfxClick();}catch(e){}setPlayerColor(opt.c);}} style={{flex:1,padding:"11px 8px",borderRadius:10,cursor:"pointer",background:playerColor===opt.c?`${opt.col}14`:"rgba(10,18,35,.82)",border:`1.5px solid ${playerColor===opt.c?opt.col:opt.col+"22"}`,display:"flex",flexDirection:"column",alignItems:"center",gap:5,transition:"all .2s",boxShadow:playerColor===opt.c?`0 0 11px ${opt.col}26`:"none"}}>
                <StarSVG type={opt.t} color={opt.col} size={26} glow={playerColor===opt.c}/>
                <span style={{fontSize:8.5,fontWeight:700,color:playerColor===opt.c?opt.col:C.dim,letterSpacing:1.5,fontFamily:"'Orbitron',monospace"}}>{opt.l}</span>
              </button>
            ))}
          </div>
          <div style={{fontSize:8,color:C.dim,marginTop:6,textAlign:"center"}}>{playerColor==="B"?"Les bleus commencent — vous jouez en premier !":"Les bleus commencent — l'IA joue d'abord"}</div>
        </div>
        <button onClick={()=>{try{audio.sfxBattleStart();}catch(e){}setTimeout(()=>setStarted(true),400);}} className="btn-c" style={{width:"100%",padding:"14px",background:`linear-gradient(135deg,${C.purple},${C.blue})`,borderRadius:12,color:C.white,fontSize:12,fontWeight:900,letterSpacing:3,boxShadow:`0 0 22px ${C.purple}48`,fontFamily:"'Orbitron',monospace"}}>🤖 LANCER LA PARTIE</button>
      </div>
    </div>
  );
};

const RankingScreen=({onNav,lang="fr",season})=>{
  const T=LANGS[lang];
  const[scope,setScope]=useState("world"); // "world" ou "national"
  const myCountry=(season?.country)||detectCountry();
  // Classement AUTOMATIQUE : tous les joueurs inscrits, classés par points.
  // Le classement "national" filtre par pays détecté de chaque joueur.
  const all=buildLeaderboard().map(p=>({...p,
    c:p.me?C.white:C.blue, badge:p.me?"★":"·",
    tier:countryFlag(p.country), winPct:winPct(p.wins,p.losses)}));
  let pool=all;
  if(scope==="national") pool=all.filter(p=>p.country===myCountry);
  const ranked=pool.sort((a,b)=>b.pts-a.pts).map((p,i)=>({...p,rank:i+1}));
  const me=ranked.find(p=>p.me)||{id:"me",name:tUI("VOUS",lang),pts:season?.pts||0,wins:season?.wins||0,country:myCountry,me:true,rank:1};
  const myRank=me.rank||1;
  const podium=ranked.slice(0,3);
  while(podium.length<3) podium.push({name:"—",pts:0,wins:0,c:C.dim,t:"Rigel",rank:podium.length+1,empty:true,tier:"🏳️"});
  const P=ranked.length>=1?ranked:[me];
  return(
    <div style={{width:"100%",height:"100%",background:`linear-gradient(180deg,#080d20,${C.void})`,display:"flex",flexDirection:"column",overflow:"hidden",fontFamily:"'Exo 2',sans-serif"}}>
      <Starfield count={55}/><Nebulas/>
      <div style={{padding:"13px 13px 8px",zIndex:1,background:"linear-gradient(180deg,rgba(10,18,40,.97),transparent)"}}>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:10}}>
          <button onClick={()=>{try{audio.sfxClick();}catch(e){}onNav("home");}} style={{background:"rgba(74,158,255,.1)",border:`1px solid ${C.blue}38`,borderRadius:8,padding:"5px 10px",color:C.blue,cursor:"pointer",fontSize:15}}>‹</button>
          <div style={{fontSize:11,color:C.white,fontWeight:900,letterSpacing:3,fontFamily:"'Orbitron',monospace",textShadow:`0 0 13px ${C.blue}38`}}>{T.menu_rank.toUpperCase()}</div>
        </div>
        {/* Saison info */}
        <div style={{background:"rgba(136,85,255,.07)",border:`1px solid rgba(136,85,255,.2)`,borderRadius:8,padding:"7px 12px",display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}>
          <div style={{fontSize:8,color:C.purple,fontFamily:"'Orbitron',monospace",letterSpacing:2}}>{tUI("SAISON EN COURS",lang)}</div>
          <div style={{fontSize:8,color:C.dim}}>⏱ Reset dans: <span style={{color:C.purple,fontWeight:700}}>{timeUntilReset()}</span></div>
        </div>
        {/* Bascule Mondial / National (classement automatique par pays) */}
        <div style={{display:"flex",gap:6}}>
          <button onClick={()=>{try{audio.sfxClick();}catch(e){}setScope("world");}}
            style={{flex:1,padding:"7px",borderRadius:8,cursor:"pointer",
              background:scope==="world"?"rgba(240,192,64,.16)":"rgba(10,18,35,.7)",
              border:`1px solid ${scope==="world"?C.gold:C.dim+"28"}`,
              color:scope==="world"?C.gold:C.dim,fontSize:8.5,fontWeight:700,letterSpacing:1.5,
              fontFamily:"'Orbitron',monospace"}}>🌍 {tUI("MONDIAL",lang)}</button>
          <button onClick={()=>{try{audio.sfxClick();}catch(e){}setScope("national");}}
            style={{flex:1,padding:"7px",borderRadius:8,cursor:"pointer",
              background:scope==="national"?"rgba(74,158,255,.16)":"rgba(10,18,35,.7)",
              border:`1px solid ${scope==="national"?C.blue:C.dim+"28"}`,
              color:scope==="national"?C.blue:C.dim,fontSize:8.5,fontWeight:700,letterSpacing:1.5,
              fontFamily:"'Orbitron',monospace"}}>{countryFlag(myCountry)} {countryName(myCountry)}</button>
        </div>
      </div>
      <div style={{display:"flex",alignItems:"flex-end",justifyContent:"center",gap:8,padding:"0 14px 10px",zIndex:1}}>
        {[podium[1],podium[0],podium[2]].map((p,i)=>{
          const h=[76,96,65][i],rank=[2,1,3][i];
          return(
            <div key={i} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:3,animation:`sUp .5s ease ${i*.1}s both`}}>
              <div style={{animation:"flt 4s ease-in-out infinite"}}><StarSVG type={p.t} color={p.c} size={26}/></div>
              <div style={{fontSize:7.5,color:p.c,fontWeight:700,textAlign:"center",letterSpacing:.8,fontFamily:"'Orbitron',monospace"}}>{p.name}</div>
              <div style={{fontSize:10,color:C.gold,fontWeight:900,fontFamily:"'Orbitron',monospace"}}>★{p.pts}</div>
              <div style={{width:"100%",height:h,background:`linear-gradient(180deg,${p.c}26,${p.c}08)`,border:`1px solid ${p.c}30`,borderRadius:"5px 5px 0 0",display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,fontWeight:900,color:p.c,fontFamily:"'Orbitron',monospace"}}>{rank}</div>
            </div>
          );
        })}
      </div>
      <div style={{flex:1,overflowY:"auto",padding:"0 13px",zIndex:1}}>
        {P.slice(3).map((p,i)=>(
          <div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"9px 12px",marginBottom:5,background:p.me?`linear-gradient(135deg,rgba(74,158,255,.13),rgba(0,229,255,.06))`:"rgba(10,18,35,.72)",border:`1px solid ${p.me?C.blue:"rgba(74,158,255,.08)"}`,borderRadius:9,boxShadow:p.me?`0 0 10px ${C.blue}14`:"none",animation:`sUp .4s ease ${i*.08}s both`}}>
            <div style={{fontSize:11,color:C.dim,fontWeight:700,width:22,textAlign:"center",fontFamily:"'Orbitron',monospace"}}>#{p.rank}</div>
            <StarSVG type={p.t} color={p.c} size={19} glow={false}/>
            <div style={{flex:1}}><div style={{fontSize:10,color:p.me?C.cyan:C.white,fontWeight:700,letterSpacing:.8}}>{p.name}</div><div style={{fontSize:8,color:p.c,marginTop:1}}>{p.tier} · {p.wins} {tUI("victoires",lang)}</div></div>
            <div style={{fontSize:13,color:C.gold,fontWeight:900,fontFamily:"'Orbitron',monospace"}}>★{p.pts}</div>
          </div>
        ))}
      </div>
    </div>
  );
};

// ── MA CONSTELLATION : zone d'affrontement avec joueurs réels ajoutés ──
const ArenaPanel=({lang="fr",onNav})=>{
  const[list,setList]=useState(()=>getArena());
  const[input,setInput]=useState("");
  const[msg,setMsg]=useState(null);
  const[myCode]=useState(()=>{
    try{const k="dosco_mycode_v1";let c=localStorage.getItem(k);if(!c){c=genArenaCode();localStorage.setItem(k,c);}return c;}catch{return "DOSCO-XXXX";}
  });
  const refresh=()=>setList(getArena());
  const add=()=>{
    const r=addArenaPlayer(input);
    if(!r.ok){ setMsg(r.reason==="exists"?tUI("Ce joueur est déjà dans ta constellation.",lang):tUI("Entre un pseudo ou un code d'invitation.",lang)); return; }
    setInput("");setMsg(null);refresh();try{audio.sfxConnect();}catch(e){}
  };
  return(
    <div style={{margin:"10px 0 16px",background:"rgba(8,14,30,.7)",border:`1px solid rgba(136,85,255,.22)`,borderRadius:14,padding:"12px 13px"}}>
      <div style={{display:"flex",alignItems:"center",gap:7,marginBottom:4}}>
        <span style={{fontSize:16}}>✦</span>
        <span style={{fontSize:10,fontWeight:900,letterSpacing:2,color:C.purple,fontFamily:"'Orbitron',monospace"}}>{tUI("MA CONSTELLATION",lang)}</span>
      </div>
      <div style={{fontSize:8,color:C.dim,lineHeight:1.5,marginBottom:10}}>
        {tUI("Ajoute de vrais joueurs par pseudo ou code, puis défie-les. Chacun devient une étoile de ta constellation.",lang)}
      </div>
      {/* Ton code d'invitation à partager */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:8,background:"rgba(136,85,255,.08)",border:`1px solid ${C.purple}33`,borderRadius:9,padding:"7px 11px",marginBottom:10}}>
        <span style={{fontSize:8,color:C.dim,letterSpacing:1}}>{tUI("TON CODE",lang)}</span>
        <span style={{fontSize:11,color:C.purple,fontWeight:900,fontFamily:"'Orbitron',monospace",letterSpacing:1}}>{myCode}</span>
      </div>
      {/* Carte de constellation : étoiles disposées en cercle */}
      {list.length>0&&(
        <div style={{position:"relative",height:150,marginBottom:10,borderRadius:12,overflow:"hidden",
          background:"radial-gradient(ellipse at center,rgba(40,30,80,.4),rgba(6,10,24,.6))",border:"1px solid rgba(136,85,255,.15)"}}>
          {/* toi au centre */}
          <div style={{position:"absolute",left:"50%",top:"50%",transform:"translate(-50%,-50%)",zIndex:2,textAlign:"center"}}>
            <div style={{animation:"flt 3s ease-in-out infinite"}}><StarSVG type="Sirus" color={C.white} size={26} glow/></div>
          </div>
          {list.map((p,i)=>{
            const a=(p.angle||(i*137.5))*Math.PI/180;const R=52*(p.dist||0.7);
            const x=50+Math.cos(a)*R/1.5, y=50+Math.sin(a)*R/1.5;
            return(
              <div key={p.id} style={{position:"absolute",left:`${x}%`,top:`${y}%`,transform:"translate(-50%,-50%)",zIndex:1}}>
                <div style={{position:"absolute",left:"50%",top:"50%",width:1,height:R,background:`linear-gradient(${a}rad,${C.purple}44,transparent)`,transformOrigin:"top",transform:`translate(-50%,0) rotate(${a+Math.PI/2}rad)`,pointerEvents:"none"}}/>
                <div style={{animation:`flt ${2.5+i*0.2}s ease-in-out ${i*0.15}s infinite`}}><StarSVG type={p.t} color={C.blue} size={16}/></div>
              </div>
            );
          })}
        </div>
      )}
      {/* Liste des joueurs ajoutés */}
      {list.map((p,i)=>(
        <div key={p.id} style={{display:"flex",alignItems:"center",gap:9,padding:"8px 10px",marginBottom:5,background:"rgba(10,18,35,.72)",border:`1px solid rgba(74,158,255,.1)`,borderRadius:9}}>
          <StarSVG type={p.t} color={C.blue} size={18} glow={false}/>
          <div style={{flex:1,minWidth:0}}>
            <div style={{fontSize:9.5,color:C.white,fontWeight:700}}>{p.name}</div>
            <div style={{fontSize:7.5,color:C.dim,marginTop:1}}>{p.code} · {p.wins||0}V / {p.losses||0}D · ★{p.pts||0}</div>
          </div>
          <button onClick={()=>{try{audio.sfxClick();}catch(e){}if(onNav)onNav("online");}}
            style={{padding:"5px 10px",background:"rgba(74,158,255,.18)",border:`1px solid ${C.blue}45`,borderRadius:7,color:C.blue,fontSize:8,cursor:"pointer",fontWeight:700,letterSpacing:1,fontFamily:"'Orbitron',monospace"}}>{tUI("DÉFIER",lang)}</button>
          <button onClick={()=>{removeArenaPlayer(p.id);refresh();}}
            aria-label="Retirer" style={{padding:"5px 8px",background:"rgba(255,68,102,.1)",border:`1px solid ${C.red}30`,borderRadius:7,color:C.red,fontSize:10,cursor:"pointer"}}>✕</button>
        </div>
      ))}
      {/* Ajouter un joueur */}
      <div style={{display:"flex",gap:6,marginTop:8}}>
        <input value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>e.key==="Enter"&&add()}
          placeholder={tUI("Pseudo ou code DOSCO-XXXX",lang)}
          style={{flex:1,background:"rgba(74,158,255,.08)",border:`1px solid rgba(74,158,255,.2)`,borderRadius:8,padding:"8px 11px",color:C.white,fontSize:9.5,outline:"none",fontFamily:"'Exo 2',sans-serif"}}/>
        <button onClick={add} style={{padding:"8px 14px",background:`linear-gradient(135deg,${C.purple},${C.blue})`,border:"none",borderRadius:8,color:C.white,cursor:"pointer",fontSize:10,fontWeight:900,fontFamily:"'Orbitron',monospace"}}>+ {tUI("AJOUTER",lang)}</button>
      </div>
      {msg&&<div style={{fontSize:8,color:C.orange,marginTop:6}}>{msg}</div>}
    </div>
  );
};
// ════════════════════════════════════════════════════════
// 📱 APP — Assemblage final
// ════════════════════════════════════════════════════════
const RulesScreen=({onNav,lang="fr"})=>{
  const rules=[{icon:"⭐",title:"Déplacement",c:C.blue,t:"Chaque étoile se déplace d'UNE CASE selon ses rayons. La forme définit les directions. Aucun survol autorisé."},{icon:"💥",title:"Capture obligatoire",c:C.red,t:"Si une étoile adverse est accessible, vous DEVEZ la capturer. Elle est retirée, votre étoile prend sa place."},{icon:"🎯",title:"Victoire I — Élimination",c:C.gold,t:"Capturez TOUTES les étoiles adverses pour remporter la partie."},{icon:"🌌",title:"Victoire II — Infiltration",c:C.cyan,t:"Placez une étoile en D1 (Bleus) ou D9 (Blancs) pour remporter la partie."},{icon:"🏅",title:"Gain identique",c:C.purple,t:"Les deux chemins de victoire rapportent EXACTEMENT la même chose : la mise de la galaxie. Aucun n'est privilégié."},{icon:"🤝",title:"Nulle",c:C.dim,t:"50 coups sans capture = nulle automatique."}];
  return(
    <div style={{width:"100%",height:"100%",background:`linear-gradient(180deg,#080d20,${C.void})`,display:"flex",flexDirection:"column",overflow:"hidden",fontFamily:"'Exo 2',sans-serif"}}>
      <Starfield count={35}/><Nebulas/>
      <div style={{padding:"13px 13px 8px",display:"flex",alignItems:"center",gap:10,zIndex:1}}>
        <button onClick={()=>{try{audio.sfxClick();}catch(e){}onNav("home");}} style={{background:"rgba(74,158,255,.1)",border:`1px solid ${C.blue}38`,borderRadius:8,padding:"5px 10px",color:C.blue,cursor:"pointer",fontSize:15}}>‹</button>
        <div style={{fontSize:10,color:C.white,fontWeight:900,letterSpacing:3,fontFamily:"'Orbitron',monospace"}}>{tUI("RÈGLES DU JEU",lang)}</div>
      </div>
      <div style={{flex:1,overflowY:"auto",padding:"0 13px 13px",zIndex:1}}>
        <div style={{marginBottom:11,background:"rgba(10,18,35,.88)",border:`1px solid rgba(74,158,255,.13)`,borderRadius:10,padding:11,animation:"sUp .4s ease"}}>
          <div style={{fontSize:7.5,color:C.dim,letterSpacing:3,marginBottom:9,fontWeight:700,fontFamily:"'Orbitron',monospace"}}>{tUI("MORPHOLOGIES",lang)}</div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:5}}>
            {[{n:"Sirus / Rigel",d:"8 directions",wt:"Sirus",bt:"Rigel"},{n:"Alhena / Acrux",d:"3av·1G·1D·1ar",wt:"Alhena",bt:"Acrux"},{n:"Altaïr / Hadar",d:"2av·1G·1D·2ar",wt:"Altair",bt:"Hadar"},{n:"Véga / Epi",d:"1av·1G·1D·3ar",wt:"Vega",bt:"Epi"},{n:"Deneb / Spica",d:"3av·3ar ±lat",wt:"Deneb",bt:"Spica"},{n:"Merak / Mimosa",d:"1av·1G·1D·1ar",wt:"Merak",bt:"Mimosa"},{n:"Alioth / Régulus",d:"2av·2ar ±lat",wt:"Alioth",bt:"Regulus"}].map((s,i)=>(
              <div key={i} style={{display:"flex",alignItems:"center",gap:5,padding:"5px 7px",background:"rgba(5,10,25,.72)",borderRadius:7,border:`1px solid rgba(74,158,255,.07)`,animation:`sUp .3s ease ${i*.05}s both`}}>
                <StarSVG type={s.wt} color={C.white} size={16} glow={false}/><StarSVG type={s.bt} color={C.blue} size={16} glow={false}/>
                <div><div style={{fontSize:8,color:C.white,fontWeight:700}}>{s.n}</div><div style={{fontSize:6.5,color:C.dim}}>{s.d}</div></div>
              </div>
            ))}
          </div>
        </div>
        {rules.map((r,i)=>(
          <div key={i} style={{display:"flex",gap:9,marginBottom:7,background:"rgba(10,18,35,.77)",border:`1px solid ${r.c}13`,borderLeft:`3px solid ${r.c}`,borderRadius:8,padding:"9px 11px",animation:`sUp .4s ease ${.08+i*.07}s both`}}>
            <span style={{fontSize:17,flexShrink:0}}>{r.icon}</span>
            <div><div style={{fontSize:9,fontWeight:700,color:r.c,letterSpacing:2,marginBottom:3,fontFamily:"'Orbitron',monospace"}}>{r.title}</div><div style={{fontSize:9,color:C.white,opacity:.82,lineHeight:1.6}}>{r.t}</div></div>
          </div>
        ))}
      </div>
    </div>
  );
};

const OnlineScreen=({onNav,user,lang="fr",setSeason})=>{
  const T=LANGS[lang];
  const[view,setView]=useState("lobby");
  const[netStatus,setNetStatus]=useState(DOSCONet.isConfigured()?"connecting":"demo");
  const[netError,setNetError]=useState(null);

  // Connexion au serveur réel si configuré
  useEffect(()=>{
    if(!DOSCONet.isConfigured()){setNetStatus("demo");return;}
    let alive=true;
    DOSCONet.connect(user?.name||"Joueur")
      .then(()=>{if(alive)setNetStatus("online");})
      .catch(()=>{if(alive){setNetStatus("demo");setNetError("Serveur injoignable — mode entraînement");}});
    return()=>{alive=false;DOSCONet.disconnect();};
  },[]);
  const[selectedGalaxy,setSelectedGalaxy]=useState(GALAXIES[0]);
  const stake=selectedGalaxy.stake;
  const[myStars,setMyStars]=useState(()=>getSeason()?.stars??100);
  const refreshStars=()=>setMyStars(getSeason()?.stars??100);
  const[opp,setOpp]=useState(null);
  const[dots,setDots]=useState(0);
  const[roomId]=useState(()=>`DOSCO-${Math.random().toString(36).slice(2,6).toUpperCase()}`);
  const[chatMsgs,setChatMsgs]=useState([]);
  const[chatInput,setChatInput]=useState("");
  const[chatOpen,setChatOpen]=useState(false);
  const[noHuman,setNoHuman]=useState(false);   // aucun joueur humain trouvé après le délai
  const[vsAIOnline,setVsAIOnline]=useState(false); // l'IA a été acceptée comme adversaire
  const[searchElapsed,setSearchElapsed]=useState(0);
  const[onlineHint,setOnlineHint]=useState(null);   // indice : coup suggéré
  const[onlineHintsUsed,setOnlineHintsUsed]=useState(0);
  const[onlineHintMsg,setOnlineHintMsg]=useState(null);
  const O_FREE_HINTS=2; const O_HINT_COST=10;
  // Etat de partie en ligne
  const[gameBoard,setGameBoard]=useState(null);
  const[myColor,setMyColor]=useState("W");
  const[onlineTurn,setOnlineTurn]=useState("B");
  const[waitingOpp,setWaitingOpp]=useState(false);
  const[drawOffer,setDrawOffer]=useState(false);   // l'adversaire propose la nulle
  const[drawSent,setDrawSent]=useState(false);     // j'ai proposé la nulle
  const[lastOppMove,setLastOppMove]=useState(null);
  const[gameResult,setGameResult]=useState(null);
  // Rafraîchir le solde d'étoiles dès qu'une partie se termine (gain/perte de mise appliqué)
  useEffect(()=>{ if(gameResult) refreshStars(); },[gameResult]);
  const settledRef=useRef(false);
  const[syncing,setSyncing]=useState(false);
  const[capturedOnline,setCapturedOnline]=useState({W:[],B:[]});
  const[oTimeW,setOTimeW]=useState(300); // chrono blancs (5 min)
  const[oTimeB,setOTimeB]=useState(300); // chrono bleus (5 min)
  const[abandoned,setAbandoned]=useState(false); // anti-triche : le joueur a quitté la partie en cours
  const[selCell,setSelCell]=useState(null);
  const[vmCells,setVmCells]=useState([]);
  const[capCells,setCapCells]=useState([]);

  // Helper format chrono mm:ss
  const fmtT=(t)=>`${Math.floor(t/60)}:${String(t%60).padStart(2,"0")}`;

  // ── CHRONO ONLINE + ANTI-TRICHE ──
  // Le chrono continue de tourner tant que la partie n'est pas terminée, MÊME si le
  // joueur quitte l'écran (anti-triche). Celui dont le temps atteint 0 perd la partie ;
  // l'adversaire n'est jamais pénalisé par un départ prématuré.
  useEffect(()=>{
    if(!gameBoard||gameResult) return;
    if(view!=="game" && !abandoned) return; // ne tourne que pendant la partie ou après un abandon
    const finishOnTime=(winner)=>{
      finalizeOnline({winner,reason:abandoned?tUI("Abandon — temps écoulé",lang):tUI("Temps écoulé",lang),type:"timeout"});
    };
    // Si le joueur a abandonné, c'est SON chrono qui s'écoule (il finira par perdre)
    const activeColor = abandoned ? myColor : onlineTurn;
    const itv=setInterval(()=>{
      if(activeColor==="W"){
        setOTimeW(t=>{
          if(t<=1){clearInterval(itv);finishOnTime("B");return 0;}
          if(!abandoned&&(t===60||t===30||t===10))try{audio.sfxAlert();}catch(e){}
          return t-1;});
      }else{
        setOTimeB(t=>{
          if(t<=1){clearInterval(itv);finishOnTime("W");return 0;}
          if(!abandoned&&(t===60||t===30||t===10))try{audio.sfxAlert();}catch(e){}
          return t-1;});
      }
    },1000);
    return()=>clearInterval(itv);
  },[view,gameBoard,gameResult,onlineTurn,abandoned]);

  // ── GARDE-FOU DE FIN DE PARTIE ──
  // Surveille le plateau en permanence : dès qu'un camp n'a plus aucune étoile
  // (élimination) ou qu'une infiltration est réalisée, la partie se termine
  // IMMÉDIATEMENT — le chrono ne peut plus tourner dans le vide. C'est la garantie
  // que la défaite par élimination prend effet sans dépendre du serveur.
  useEffect(()=>{
    if(!gameBoard||gameResult) return;
    if(view!=="game"&&!abandoned) return; // uniquement pendant la partie (ou un abandon en cours)
    const end=checkEnd(gameBoard,lastOppMove,onlineTurn,0);
    if(end&&end.winner){ finalizeOnline(end); }
  },[gameBoard,gameResult,myColor,onlineTurn,view,abandoned]);

  // Anti-triche : prévenir le serveur si l'onglet/app se ferme en pleine partie
  useEffect(()=>{
    if(view!=="game"||!gameBoard||gameResult) return;
    const onLeave=()=>{ try{ if(netStatus==="online"&&DOSCONet.isConfigured()&&!vsAIOnline) DOSCONet.resign(); }catch(e){} };
    if(typeof window!=="undefined"&&window.addEventListener){
      window.addEventListener("beforeunload",onLeave);
      return()=>window.removeEventListener("beforeunload",onLeave);
    }
  },[view,gameBoard,gameResult,netStatus,vsAIOnline]);

  // Quand une partie abandonnée se termine (temps écoulé), nettoyer l'état
  useEffect(()=>{
    if(gameResult&&abandoned){
      const t=setTimeout(()=>{ setAbandoned(false);setGameBoard(null); },200);
      return()=>clearTimeout(t);
    }
  },[gameResult,abandoned]);

  useEffect(()=>{
    if(view!=="search") return;
    setNoHuman(false);setVsAIOnline(false);setSearchElapsed(0);
    const t=setInterval(()=>setDots(d=>(d+1)%4),500);
    const elapsed=setInterval(()=>setSearchElapsed(s=>s+1),1000);
    // Recherche d'un VRAI adversaire humain (priorité absolue)
    if(netStatus==="online" && DOSCONet.isConfigured()){
      DOSCONet.findMatch(selectedGalaxy.id);
    }
    // Au bout de 10 s sans humain : proposer l'IA (le joueur doit accepter)
    const noHumanTimer=setTimeout(()=>{
      if(viewRef.current==="search"){ setNoHuman(true); try{audio.sfxAlert();}catch(e){} }
    },10000);
    return()=>{clearInterval(t);clearInterval(elapsed);clearTimeout(noHumanTimer);};
  },[view,netStatus,selectedGalaxy]);

  // Lancer une partie contre l'IA après acceptation explicite du joueur
  const acceptAIOpponent=()=>{
    try{audio.sfxConnect();}catch(e){}
    setVsAIOnline(true);
    setOpp({name:"DOSCO IA",rank:"Intelligence Artificielle",stars:0,ping:0,t:"Sirus",isAI:true});
    setNoHuman(false);
    setView("room");
  };

  // ── ÉCOUTEURS DU SERVEUR RÉEL (multijoueur) ──
  // Refs pour accéder à l'état frais sans recréer les écouteurs
  const galaxyRef=useRef(selectedGalaxy);   galaxyRef.current=selectedGalaxy;
  const oppRef=useRef(opp);                 oppRef.current=opp;
  const viewRef=useRef(view);               viewRef.current=view;
  const myColorRef=useRef(myColor);         myColorRef.current=myColor;
  // Applique le résultat d'une partie en ligne UNE SEULE FOIS (anti double-crédit/débit).
  const finalizeOnline=(end)=>{
    if(settledRef.current) return;
    settledRef.current=true;
    const iWon=end.winner===myColorRef.current;
    const sd=end.winner?(iWon?galaxyRef.current.stake:-galaxyRef.current.stake):0;
    setGameResult({...end,iWon,stakeDelta:sd,galaxy:galaxyRef.current.name});
    if(end.winner){try{iWon?audio.sfxVictory():(audio.sfxDefeat&&audio.sfxDefeat());}catch(e){};try{MusicPlayer.play(iWon?"victory":"defeat",false);}catch(e){}}
    try{ updateSeason(iWon,oppRef.current?.name||"ONLINE",false,end.type||"infiltration",sd); }catch(e){}
    refreshStars();
    try{ if(setSeason) setSeason(getSeason()); }catch(e){}  // rafraîchit le solde global (menu d'accueil)
  };
  useEffect(()=>{
    if(!DOSCONet.isConfigured()) return;
    // Un vrai adversaire est trouvé → le serveur démarre la partie
    DOSCONet.on("gameStart",(msg)=>{
      try{audio.sfxConnect();}catch(e){}
      setOpp({name:msg.opponent,stars:0,t:"Rigel",ping:0});
      setMyColor(msg.color);
      setGameBoard({...msg.board});
      setOnlineTurn(msg.turn||"B");
      setCapturedOnline({W:[],B:[]});setGameResult(null);setLastOppMove(null);
      setOTimeW(300);setOTimeB(300);
      setSelCell(null);setVmCells([]);setCapCells([]);
      try{audio.sfxBattleStart();}catch(e){}
      setView("game");
    });
    // Coup (le serveur diffuse TOUS les coups, y compris la confirmation du mien)
    DOSCONet.on("move",(msg)=>{
      setGameBoard({...msg.board});       // état autoritaire du serveur
      setLastOppMove(msg.to);
      setOnlineTurn(msg.turn);
      if(msg.by!==DOSCONet.myColor){      // son du coup adverse uniquement
        if(msg.isCapture){try{audio.sfxCapture();}catch(e){}setCapturedOnline(p=>({...p,[msg.by]:[...p[msg.by],{type:"?"}]}));}
        else try{audio.sfxMove();}catch(e){}
      }
      // FILET DE SÉCURITÉ : terminer immédiatement si une condition de fin est atteinte
      // (élimination/infiltration), sans attendre l'événement "gameEnd" du serveur.
      const end=checkEnd(msg.board,msg.to,msg.by===DOSCONet.myColor?DOSCONet.myColor:msg.by,0);
      if(end&&end.winner){ finalizeOnline(end); }
    });
    // Fin de partie annoncée par le serveur (mises réglées côté serveur)
    DOSCONet.on("gameEnd",(msg)=>{
      finalizeOnline({winner:msg.winner,type:msg.type});
    });
    // Proposition de nulle reçue de l'adversaire
    DOSCONet.on("drawOffered",()=>{ setDrawOffer(true); });
    DOSCONet.on("drawDeclined",()=>{ setDrawSent(false); });
    // Revanche : l'adversaire a proposé une revanche → afficher un prompt d'acceptation
    DOSCONet.on("rematchOffered",(msg)=>{ 
      // Sauvegarder le gameId de la partie qui vient de se terminer
      if(msg&&msg.gameId) DOSCONet.lastGameId=msg.gameId;
      setIncomingRematch(true); try{audio.sfxAlert();}catch(e){} 
    });
    DOSCONet.on("rematchAccepted",(msg)=>{ 
      if(msg&&msg.gameId) DOSCONet.lastGameId=msg.gameId;
      setRematchMsg(null);setIncomingRematch(false);startGame(); 
    });
    DOSCONet.on("rematchDeclined",()=>{ setRematchMsg(tUI("L'adversaire n'est pas disponible pour une revanche.",lang)); });
    // Message de chat reçu
    DOSCONet.on("chat",(msg)=>{ setChatMsgs(c=>[...c,{from:oppRef.current?.name||"ADVERSAIRE",msg:msg.text}]); });
    DOSCONet.on("error",(msg)=>{ if(viewRef.current==="search"){setView("lobby");} });
    return()=>{ DOSCONet.handlers={}; };
  },[]);  // monté une seule fois — écouteurs stables

  // Tour adverse : IA locale — uniquement si le joueur a accepté de jouer contre l'IA
  useEffect(()=>{
    if(view!=="game"||!gameBoard||gameResult||onlineTurn===myColor) return;
    if(!vsAIOnline) return; // adversaire humain réel : le serveur gère ses coups
    let cancelled=false;
    const doOppMove=async()=>{
      setWaitingOpp(true);
      // Temps de réflexion réaliste
      await new Promise(r=>setTimeout(r,800+Math.random()*900));
      if(cancelled) return;
      // L'adversaire IA joue un bon coup (niveau Pulsare)
      const mv=getAIMove(gameBoard,onlineTurn,"n4");
      if(cancelled||!mv) return;
      const nb={...gameBoard};
      if(!nb[mv.from]||nb[mv.from].color!==onlineTurn){setWaitingOpp(false);return;}
      const isC=!!nb[mv.to];
      if(isC){try{audio.sfxCapture();}catch(e){}setCapturedOnline(p=>({...p,[onlineTurn]:[...p[onlineTurn],{type:nb[mv.to].type}]}));}
      else try{audio.sfxMove();}catch(e){}
      delete nb[mv.from];nb[mv.to]={...gameBoard[mv.from]};
      setGameBoard(nb);setLastOppMove(mv.to);
      const end=checkEnd(nb,mv.to,onlineTurn,0);
      if(end&&end.winner){ finalizeOnline(end); }
      setOnlineTurn(t=>t==="W"?"B":"W");
      setWaitingOpp(false);
    };
    doOppMove();
    return()=>{cancelled=true;};
  },[view,onlineTurn,gameBoard,gameResult,myColor,vsAIOnline]);

  const startGame=()=>{
    settledRef.current=false;
    setGameBoard({...INIT_BOARD});setMyColor("W");setOnlineTurn("B");
    setCapturedOnline({W:[],B:[]});setGameResult(null);setLastOppMove(null);
    setSelCell(null);setVmCells([]);setCapCells([]);
    setAbandoned(false);setOTimeW(300);setOTimeB(300);
    setOnlineHint(null);setOnlineHintsUsed(0);setOnlineHintMsg(null);
    setDrawSent(false);setDrawOffer(false);setWaitingOpp(false);setIncomingRematch(false);setRematchMsg(null);
    try{audio.sfxBattleStart();}catch(e){}setView("game");
  };

  // Revanche : contre l'IA on relance directement ; contre un humain réel, on tente une
  // revanche via le serveur et on prévient si l'adversaire n'est pas disponible.
  const[rematchMsg,setRematchMsg]=useState(null);
  const[incomingRematch,setIncomingRematch]=useState(false);
  const requestRematch=()=>{
    try{audio.sfxClick();}catch(e){}
    if(vsAIOnline || !(netStatus==="online" && DOSCONet.isConfigured())){
      // IA ou hors-ligne : revanche immédiate
      startGame();
      return;
    }
    // S'assurer que lastGameId est bien conservé avant l'envoi
    if(!DOSCONet.lastGameId && !DOSCONet.gameId){
      setRematchMsg("Identifiant de partie perdu — relancez une recherche.");
      return;
    }
    // Adversaire humain réel : demander une revanche au serveur (les écouteurs
    // persistants rematchAccepted/rematchDeclined gèrent la réponse)
    setRematchMsg(tUI("Demande de revanche envoyée…",lang));
    try{ DOSCONet.requestRematch(); }catch(e){}
    // Délai d'attente : si pas de réponse en 12s, adversaire indisponible
    setTimeout(()=>{
      setRematchMsg(m=> m===tUI("Demande de revanche envoyée…",lang)
        ? tUI("L'adversaire n'est pas disponible pour une revanche.",lang) : m);
    },12000);
  };

  // Indice en ligne : 2 gratuits par partie, puis 10 étoiles. Suggère le meilleur coup.
  const showOnlineHint=()=>{
    if(!gameBoard||gameResult||onlineTurn!==myColor||waitingOpp) return;
    if(onlineHintsUsed>=O_FREE_HINTS){
      const s=getSeason();
      if((s.stars||0) < O_HINT_COST){
        setOnlineHintMsg(tUI("Étoiles insuffisantes pour un indice",lang));
        try{audio.sfxError();}catch(e){}
        setTimeout(()=>setOnlineHintMsg(null),2200);
        return;
      }
      s.stars=Math.max(0,(s.stars||0)-O_HINT_COST);
      try{localStorage.setItem(SEASON_KEY,JSON.stringify(s));}catch(e){}
      setOnlineHintMsg("-"+O_HINT_COST+" ⭐");
      setTimeout(()=>setOnlineHintMsg(null),1800);
    }
    try{audio.sfxAlert();}catch(e){}
    const best=getAIMove(gameBoard,myColor,"n4");
    if(best){
      setOnlineHint(best);
      setOnlineHintsUsed(h=>h+1);
      setTimeout(()=>setOnlineHint(null),3000);
    }
  };

  const handleCellClick=(coord)=>{
    if(!gameBoard||gameResult||onlineTurn!==myColor||waitingOpp) return;
    const star=gameBoard[coord];
    const mc=getAllCaptures(myColor,gameBoard);
    const hasMand=Object.keys(mc).length>0;
    if(selCell){
      if([...vmCells,...capCells].includes(coord)){
        const isCapture=!!gameBoard[coord];
        if(!isCapture&&hasMand){try{audio.sfxError();}catch(e){}return;}
        // MODE EN LIGNE RÉEL (humain) : envoyer le coup au serveur (il valide et renvoie l'état)
        if(netStatus==="online" && DOSCONet.isConfigured() && !vsAIOnline){
          DOSCONet.sendMove(selCell,coord);
          if(isCapture){try{audio.sfxCapture();}catch(e){}}else try{audio.sfxMove();}catch(e){}
          // Mise à jour optimiste de l'affichage ; le serveur confirmera via "move"
          const nbo={...gameBoard};delete nbo[selCell];nbo[coord]={...gameBoard[selCell]};
          if(isCapture)setCapturedOnline(p=>({...p,[myColor]:[...p[myColor],{type:gameBoard[coord].type}]}));
          setGameBoard(nbo);setLastOppMove(null);
          // Vérifier aussi la fin côté client (filet si le serveur tarde)
          const endN=checkEnd(nbo,coord,myColor,0);
          if(endN){
            const iWon=endN.winner===myColor;const sd=endN.winner?(iWon?stake:-stake):0;
            setGameResult({...endN,iWon,stakeDelta:sd,galaxy:selectedGalaxy.name});
            if(endN.winner){try{iWon?audio.sfxVictory():(audio.sfxDefeat&&audio.sfxDefeat());}catch(e){};try{MusicPlayer.play(iWon?"victory":"defeat",false);}catch(e){}}
            setSelCell(null);setVmCells([]);setCapCells([]);return;
          }
          setOnlineTurn(t=>t==="W"?"B":"W");
          setSelCell(null);setVmCells([]);setCapCells([]);
          return;
        }
        const nb={...gameBoard};
        if(isCapture){setCapturedOnline(p=>({...p,[myColor]:[...p[myColor],{type:nb[coord].type}]}));try{audio.sfxCapture();}catch(e){}}
        else try{audio.sfxMove();}catch(e){}
        delete nb[selCell];nb[coord]={...gameBoard[selCell]};
        setGameBoard(nb);setLastOppMove(null);
        const end=checkEnd(nb,coord,myColor,0);
        if(end&&end.winner){ finalizeOnline(end); return; }
        setOnlineTurn(t=>t==="W"?"B":"W");
        setSelCell(null);setVmCells([]);setCapCells([]);
      } else if(star?.color===myColor){
        if(hasMand&&!mc[coord]){try{audio.sfxError();}catch(e){}return;}
        try{audio.sfxSelect();}catch(e){}
        const{moves,captures}=getMoves(coord,gameBoard);
        setSelCell(coord);setVmCells(hasMand?[]:moves);setCapCells(hasMand?(mc[coord]||[]):captures);
      } else{setSelCell(null);setVmCells([]);setCapCells([]);}
    } else if(star?.color===myColor){
      if(hasMand&&!mc[coord]){try{audio.sfxError();}catch(e){}return;}
      try{audio.sfxSelect();}catch(e){}
      const{moves,captures}=getMoves(coord,gameBoard);
      setSelCell(coord);setVmCells(hasMand?[]:moves);setCapCells(hasMand?(mc[coord]||[]):captures);
    }
  };

  const sendChat=()=>{
    if(!chatInput.trim()) return;
    const text=chatInput.trim();
    setChatMsgs(c=>[...c,{from:user.name,msg:text}]);
    setChatInput("");
    // Le chat n'est relayé qu'à un adversaire humain réel (jamais simulé)
    if(netStatus==="online" && DOSCONet.isConfigured() && !vsAIOnline){
      DOSCONet.sendChat(text);
    }
  };

  const onlineBoardRef=useRef(null);
  const CELL = useBoardSize(onlineBoardRef);
  const mc=gameBoard?getAllCaptures(myColor,gameBoard):{};

  if(view==="game"&&gameBoard) return(
    <div style={{width:"100%",height:"100%",background:`linear-gradient(180deg,#05091c,${C.void})`,display:"flex",flexDirection:"column",overflow:"hidden",fontFamily:"'Exo 2',sans-serif",position:"relative"}}>
      <Starfield count={22}/>

      {/* ── BANDEAU CHRONOS (deux chronos centrés sur une ligne) ── */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:10,
        padding:"6px 10px",flexShrink:0,position:"relative",
        background:"rgba(8,14,30,.55)",borderBottom:"1px solid rgba(74,158,255,.1)"}}>
        {/* Chrono adversaire */}
        {(()=>{const t=myColor==="W"?oTimeB:oTimeW;const col=myColor==="W"?C.blue:C.white;return(
          <div style={{display:"flex",alignItems:"center",gap:5}}>
            <span style={{fontSize:7,letterSpacing:1.5,fontFamily:"'Orbitron',monospace",
              color:onlineTurn!==myColor?col:C.dim}}>{(opp?.name||"ADV.").slice(0,8)}</span>
            <div style={{fontSize:13,fontFamily:"'Orbitron',monospace",fontWeight:900,
              color:t<=30?C.red:t<=60?C.orange:col,
              animation:t<=10?"pls .5s infinite":"none",
              background:t<=30?"rgba(255,68,102,.14)":"transparent",
              padding:"2px 8px",borderRadius:6,minWidth:48,textAlign:"center",
              border:`1px solid ${t<=30?C.red:t<=60?C.orange:"transparent"}`}}>{fmtT(t)}</div>
          </div>);})()}
        <span style={{fontSize:9,color:C.dim,opacity:.6}}>⏱</span>
        {/* Mon chrono */}
        {(()=>{const t=myColor==="W"?oTimeW:oTimeB;const col=myColor==="W"?C.white:C.blue;return(
          <div style={{display:"flex",alignItems:"center",gap:5}}>
            <div style={{fontSize:13,fontFamily:"'Orbitron',monospace",fontWeight:900,
              color:t<=30?C.red:t<=60?C.orange:col,
              animation:t<=10?"pls .5s infinite":"none",
              background:t<=30?"rgba(255,68,102,.14)":"transparent",
              padding:"2px 8px",borderRadius:6,minWidth:48,textAlign:"center",
              border:`1px solid ${t<=30?C.red:t<=60?C.orange:"transparent"}`}}>{fmtT(t)}</div>
            <span style={{fontSize:7,letterSpacing:1.5,fontFamily:"'Orbitron',monospace",
              color:onlineTurn===myColor?col:C.dim}}>VOUS</span>
          </div>);})()}
        <button onClick={()=>{
            try{audio.sfxClick();}catch(e){}
            if(gameResult){ setView("lobby");setGameBoard(null);return; }
            // ANTI-TRICHE : quitter une partie en cours ne met pas fin au match.
            // Le chrono du joueur continue de tourner ; il perdra à l'épuisement du temps.
            const warn=tUI("Quitter la partie ? Votre chronomètre continuera de tourner et vous perdrez si votre temps s'épuise.",lang);
            if(typeof confirm==="function" && !confirm(warn)) return;
            setAbandoned(true);
            try{ if(netStatus==="online"&&DOSCONet.isConfigured()&&!vsAIOnline) DOSCONet.resign(); }catch(e){}
            setView("lobby");
          }}
          style={{position:"absolute",right:8,top:"50%",transform:"translateY(-50%)",
            background:"rgba(255,68,102,.12)",border:`1px solid ${C.red}35`,borderRadius:7,
            padding:"3px 8px",color:C.red,cursor:"pointer",fontSize:11,
            fontFamily:"'Orbitron',monospace"}}>✕</button>
      </div>

      {/* ── BARRE ADVERSAIRE (haut) ── */}
      <div style={{display:"flex",alignItems:"center",gap:6,padding:"5px 10px",
        background:"rgba(74,158,255,.06)",borderBottom:`1px solid rgba(74,158,255,.1)`,
        flexShrink:0,minHeight:36}}>
        <StarSVG type={opp?.t||"Rigel"} color={myColor==="W"?C.blue:C.white} size={18} glow={false}/>
        <div style={{flex:1,minWidth:0}}>
          <div style={{fontSize:8,fontWeight:700,letterSpacing:2,
            color:myColor==="W"?C.blue:C.white,fontFamily:"'Orbitron',monospace"}}>
            {opp?.name} {waitingOpp&&<span style={{color:C.gold,fontSize:7}}>✦ réfléchit…</span>}{syncing&&<span style={{color:C.cyan,fontSize:7}}> sync…</span>}
          </div>
          <div style={{display:"flex",gap:2,flexWrap:"wrap",marginTop:1}}>
            {capturedOnline[myColor==="W"?"B":"W"].slice(-7).map((s,i)=>
              <StarSVG key={i} type={s.type==="?"?"Sirus":s.type} color={myColor==="W"?C.blue:C.white} size={11} glow={false}/>)}
          </div>
        </div>
        <div style={{fontSize:7,color:C.dim}}>Mise <span style={{color:C.gold,fontWeight:700}}>★{stake}</span></div>
      </div>

      {/* ── INDICATEUR TOUR ── */}
      <div style={{display:"flex",alignItems:"center",gap:6,padding:"3px 10px",
        background:onlineTurn===myColor?"rgba(0,255,136,.06)":"rgba(255,68,102,.04)",
        borderBottom:`1px solid ${onlineTurn===myColor?"rgba(0,255,136,.15)":"rgba(255,68,102,.09)"}`,
        flexShrink:0}}>
        <div style={{width:6,height:6,borderRadius:"50%",flexShrink:0,
          background:onlineTurn===myColor?C.green:C.red,
          boxShadow:onlineTurn===myColor?`0 0 6px ${C.green}`:"none",
          animation:"pls 1.2s infinite"}}/>
        <span style={{fontSize:8,fontWeight:700,letterSpacing:2,
          color:onlineTurn===myColor?C.green:C.dim,
          fontFamily:"'Orbitron',monospace",flex:1}}>
          {onlineTurn===myColor?"VOTRE TOUR":"ADVERSAIRE JOUE…"}
        </span>
        {Object.keys(mc).length>0&&onlineTurn===myColor&&(
          <span style={{fontSize:7,color:C.red,fontWeight:700,letterSpacing:1,animation:"pls .7s infinite"}}>⚡ CAPTURE</span>
        )}
      </div>

      {/* ── BARRE D'ACTIONS (en haut — Nulle / Chat / Abandon) ── */}
      {!gameResult&&(
        <div style={{display:"flex",gap:6,padding:"4px 8px 6px",justifyContent:"center",flexShrink:0,width:"100%",boxSizing:"border-box"}}>
          <button onClick={()=>{
              try{audio.sfxClick();}catch(e){}
              if(drawSent||gameResult) return;
              if(netStatus==="online" && DOSCONet.isConfigured() && !vsAIOnline){
                // Adversaire humain réel : transmettre l'offre au serveur
                DOSCONet.offerDraw(); setDrawSent(true);
                setOnlineHintMsg(tUI("Proposition envoyée à l'adversaire",lang));
                setTimeout(()=>setOnlineHintMsg(null),2200);
              } else {
                // Contre l'IA : réponse automatique immédiate (l'IA accepte si la position est serrée)
                setDrawSent(true);
                setTimeout(()=>{
                  const wc=Object.values(gameBoard||{}).filter(s=>s.color==="W").length;
                  const bc=Object.values(gameBoard||{}).filter(s=>s.color==="B").length;
                  const accept=Math.abs(wc-bc)<=1; // l'IA accepte si l'écart de matériel est faible
                  if(accept){
                    finalizeOnline({winner:null,type:"draw",reason:tUI("Nulle acceptée",lang)});
                  } else {
                    setDrawSent(false);
                    setOnlineHintMsg(tUI("L'adversaire a refusé la nulle",lang));
                    setTimeout(()=>setOnlineHintMsg(null),2200);
                  }
                },700);
              }
            }}
            disabled={drawSent}
            style={{flex:1,minWidth:0,padding:"6px 2px",borderRadius:9,
              background:drawSent?"rgba(240,192,64,.05)":"rgba(240,192,64,.12)",
              border:`1px solid ${C.gold}45`,color:C.gold,
              cursor:drawSent?"default":"pointer",opacity:drawSent?.5:1,
              fontFamily:"'Orbitron',monospace",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:2}}>
            <span style={{fontSize:15,lineHeight:1}}>🤝</span>
            <span style={{fontSize:7.5,fontWeight:700,letterSpacing:.3}}>{drawSent?tUI("PROPOSÉE",lang):tUI("NULLE",lang)}</span>
          </button>
          <button onClick={showOnlineHint} disabled={onlineTurn!==myColor||waitingOpp}
            style={{flex:1,minWidth:0,padding:"6px 2px",borderRadius:9,
              background:(onlineTurn===myColor&&!waitingOpp)?"rgba(240,192,64,.12)":"rgba(40,48,65,.4)",
              border:`1px solid ${(onlineTurn===myColor&&!waitingOpp)?C.gold+"45":C.dim+"20"}`,
              color:(onlineTurn===myColor&&!waitingOpp)?C.gold:C.dim,
              cursor:(onlineTurn===myColor&&!waitingOpp)?"pointer":"not-allowed",
              fontFamily:"'Orbitron',monospace",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:2}}>
            <span style={{fontSize:15,lineHeight:1}}>💡</span>
            <span style={{fontSize:7.5,fontWeight:700,letterSpacing:.3}}>{tUI("INDICE",lang)}</span>
            <span style={{fontSize:6.5,color:onlineHintsUsed<O_FREE_HINTS?C.green:C.gold,letterSpacing:.3,marginTop:1}}>
              {onlineHintsUsed<O_FREE_HINTS?(O_FREE_HINTS-onlineHintsUsed)+" "+tUI("gratuit(s)",lang):O_HINT_COST+"⭐"}
            </span>
          </button>
          <button onClick={()=>{
              try{audio.sfxClick();}catch(e){}
              if(gameResult) return;
              if(typeof confirm==="function" && !confirm(tUI("ABANDONNER ?",lang))) return;
              if(netStatus==="online" && DOSCONet.isConfigured() && !vsAIOnline){
                try{DOSCONet.resign();}catch(e){}
              }
              // Dans tous les cas : terminer la partie localement par une défaite (mise réglée une seule fois)
              finalizeOnline({winner:myColor==="W"?"B":"W",reason:tUI("ABANDON",lang),type:"resign"});
            }}
            style={{flex:1,minWidth:0,padding:"6px 2px",borderRadius:9,
              background:"rgba(255,68,102,.1)",border:`1px solid ${C.red}38`,color:C.red,
              cursor:"pointer",
              fontFamily:"'Orbitron',monospace",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:2}}>
            <span style={{fontSize:15,lineHeight:1}}>🏳</span>
            <span style={{fontSize:7.5,fontWeight:700,letterSpacing:.3}}>{tUI("ABANDON",lang)}</span>
          </button>
        </div>
      )}

      {/* Modale : l'adversaire propose la nulle */}
      {drawOffer&&!gameResult&&(
        <div style={{position:"absolute",inset:0,background:"rgba(3,4,10,.85)",display:"flex",flexDirection:"column",
          alignItems:"center",justifyContent:"center",zIndex:60,gap:14,animation:"zIn .3s ease"}}>
          <div style={{fontSize:13,color:C.gold,fontWeight:900,letterSpacing:2,fontFamily:"'Orbitron',monospace"}}>🤝 {tUI("PROPOSER LA NULLE ?",lang)}</div>
          <div style={{fontSize:9,color:C.dim}}>{opp?.name} propose le match nul</div>
          <div style={{display:"flex",gap:10}}>
            <button onClick={()=>{DOSCONet.respondDraw(true);setDrawOffer(false);}}
              style={{padding:"9px 20px",borderRadius:10,background:`linear-gradient(135deg,${C.green},${C.cyan})`,
                border:"none",color:C.void,fontSize:10,fontWeight:900,letterSpacing:1,cursor:"pointer",fontFamily:"'Orbitron',monospace"}}>ACCEPTER</button>
            <button onClick={()=>{DOSCONet.respondDraw(false);setDrawOffer(false);}}
              style={{padding:"9px 20px",borderRadius:10,background:"rgba(255,68,102,.15)",
                border:`1px solid ${C.red}45`,color:C.red,fontSize:10,fontWeight:900,letterSpacing:1,cursor:"pointer",fontFamily:"'Orbitron',monospace"}}>REFUSER</button>
          </div>
        </div>
      )}
      {gameResult&&(
        <div style={{position:"absolute",inset:0,background:"rgba(3,4,10,.9)",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",zIndex:200,animation:"zIn .5s ease",gap:12,pointerEvents:"auto"}}>
          <Starfield count={100}/>
          <div style={{animation:"flt 3s ease-in-out infinite"}}><StarSVG type={gameResult.winner==="W"?"Sirus":gameResult.winner==="B"?"Rigel":"Sirus"} color={gameResult.winner==="W"?C.white:gameResult.winner==="B"?C.blue:C.dim} size={64} glow={!!gameResult.winner} anim={!!gameResult.winner} flipped={gameResult.winner==="W"}/></div>
          {/* Gagnant */}
          <div style={{textAlign:"center",marginBottom:10}}>
            {gameResult.winner?(
              <>
                <div style={{fontSize:9,color:gameResult.winner===myColor?C.white:C.blue,
                  letterSpacing:4,fontFamily:"'Orbitron',monospace",marginBottom:3,fontWeight:700}}>
                  {gameResult.winner===myColor?"VOUS":""+opp?.name}
                </div>
                <div style={{fontSize:24,fontWeight:900,
                  color:gameResult.winner===myColor?C.gold:C.red,
                  letterSpacing:4,fontFamily:"'Orbitron',monospace",
                  animation:gameResult.winner===myColor?"glwG 1.5s infinite":"none"}}>
                  {gameResult.winner===myColor?"VICTOIRE":"DÉFAITE"}
                </div>
                <div style={{fontSize:8,color:C.dim,marginTop:4}}>
                  {gameResult.iWon?`Victoire contre ${opp?.name||"ADVERSAIRE"}`:`Défaite contre ${opp?.name||"ADVERSAIRE"}`}
                </div>
              </>
            ):(
              <div style={{fontSize:22,fontWeight:900,color:C.dim,
                letterSpacing:4,fontFamily:"'Orbitron',monospace"}}>{tUI("NULLE",lang)}</div>
            )}
          </div>
          <div style={{background:"rgba(10,18,35,.85)",border:`1px solid rgba(74,158,255,.2)`,
            borderRadius:8,padding:"6px 16px",marginBottom:10}}>
            <div style={{fontSize:8.5,color:C.dim,textAlign:"center"}}>{gameResult.reason}</div>
          </div>
          {gameResult.winner&&(
            <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:6,marginBottom:10}}>
              {/* Résultat de la mise — winner-takes-all */}
              <div style={{display:"inline-flex",alignItems:"center",gap:8,padding:"8px 20px",borderRadius:24,
                background:gameResult.iWon?`linear-gradient(135deg,${C.gold}28,${C.green}14)`:`linear-gradient(135deg,${C.red}22,${C.red}10)`,
                border:`1.5px solid ${gameResult.iWon?C.gold:C.red}55`}}>
                <span style={{fontSize:20}}>⭐</span>
                <span style={{fontSize:20,fontWeight:900,fontFamily:"'Orbitron',monospace",
                  color:gameResult.iWon?C.gold:C.red,letterSpacing:1}}>
                  {gameResult.iWon?"+":""}{gameResult.stakeDelta}
                </span>
              </div>
              <div style={{fontSize:8,color:C.dim,letterSpacing:1}}>
                {gameResult.iWon?`Mise remportée dans ${gameResult.galaxy}`:`Mise perdue dans ${gameResult.galaxy}`}
              </div>
              <div style={{fontSize:9,color:gameResult.iWon?C.green:C.red,fontWeight:700,
                fontFamily:"'Orbitron',monospace"}}>
                {gameResult.iWon?"+":""}{gameResult.stakeDelta} pts classement
              </div>
            </div>
          )}
          {incomingRematch&&(
            <div style={{background:"rgba(74,158,255,.12)",border:`1px solid ${C.blue}55`,borderRadius:10,padding:"10px 12px",marginBottom:10,textAlign:"center"}}>
              <div style={{fontSize:9,color:C.cyan,fontWeight:700,marginBottom:8,fontFamily:"'Orbitron',monospace"}}>{tUI("L'adversaire propose une revanche !",lang)}</div>
              <div style={{display:"flex",gap:8,justifyContent:"center"}}>
                <button onClick={()=>{try{DOSCONet.respondRematch(true);}catch(e){}setIncomingRematch(false);startGame();}}
                  style={{padding:"7px 16px",borderRadius:8,background:`linear-gradient(135deg,${C.green},${C.cyan})`,border:"none",color:C.void,fontSize:9,fontWeight:900,cursor:"pointer",fontFamily:"'Orbitron',monospace"}}>{tUI("ACCEPTER",lang)}</button>
                <button onClick={()=>{try{DOSCONet.respondRematch(false);}catch(e){}setIncomingRematch(false);}}
                  style={{padding:"7px 16px",borderRadius:8,background:"rgba(255,68,102,.12)",border:`1px solid ${C.red}40`,color:C.red,fontSize:9,fontWeight:700,cursor:"pointer",fontFamily:"'Orbitron',monospace"}}>{tUI("REFUSER",lang)}</button>
              </div>
            </div>
          )}
          {rematchMsg&&(
            <div style={{fontSize:9,color:C.gold,textAlign:"center",marginBottom:8,lineHeight:1.4,
              fontFamily:"'Orbitron',monospace",animation:"zIn .3s ease"}}>{rematchMsg}</div>
          )}
          <div style={{display:"flex",gap:10,marginTop:8}}>
            <button onClick={requestRematch} className="btn-c" style={{padding:"10px 20px",background:`linear-gradient(135deg,${C.blue},${C.cyan})`,borderRadius:10,color:C.void,fontSize:10,fontWeight:900,letterSpacing:2,boxShadow:`0 0 16px ${C.blue}48`,fontFamily:"'Orbitron',monospace"}}>{tUI("REVANCHE",lang)}</button>
            <button onClick={()=>{setRematchMsg(null);try{DOSCONet.lastGameId=null;DOSCONet.gameId=null;}catch(e){}setView("lobby");setGameBoard(null);}} style={{padding:"10px 20px",background:"rgba(10,18,35,.9)",border:`1px solid ${C.dim}38`,borderRadius:10,color:C.white,fontSize:10,cursor:"pointer",letterSpacing:2,fontFamily:"'Orbitron',monospace"}}>{tUI("LOBBY",lang)}</button>
          </div>
        </div>
      )}
      {/* Plateau retourné selon couleur du joueur : ses pièces toujours en bas */}
      <div ref={onlineBoardRef} style={{flex:1,overflow:"hidden",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:2,zIndex:1,pointerEvents:onlineTurn!==myColor||waitingOpp?"none":"auto",opacity:onlineTurn!==myColor?.88:1,transition:"opacity .3s"}}>
        <div style={{display:"flex",flexDirection:"column",gap:3,padding:10,borderRadius:14,
          background:THEME_BOARD_BG[getBoardTheme()]||"radial-gradient(ellipse at center,rgba(28,48,90,.65),rgba(10,18,40,.85))",
          border:`1.5px solid ${THEME_BORDER_COLOR[getBoardTheme()]||"rgba(130,195,255,.35)"}`,
          boxShadow:"0 0 40px rgba(74,158,255,.25),inset 0 0 50px rgba(15,30,60,.5)"}}>
        {(myColor==="W"?[...BOARD_LAYOUT].reverse():BOARD_LAYOUT).map((row,ri)=>(
          <div key={ri} style={{display:"flex",gap:3}}>
            {row.map((coord,ci)=>{
              if(!coord) return <div key={ci} style={{width:CELL,height:CELL}}/>;
              const star=gameBoard[coord];
              const isSel=selCell===coord,isVM=vmCells.includes(coord),isCap=capCells.includes(coord);
              const isHintFrom=onlineHint&&onlineHint.from===coord,isHintTo=onlineHint&&onlineHint.to===coord;
              const isMandSrc=Object.keys(mc).includes(coord)&&!selCell;
              const isLastOpp=lastOppMove===coord;
              const colIdx="ABCDEFG".indexOf(coord[0]),rowIdx=parseInt(coord[1])-1;
              const riseDelay=((colIdx+rowIdx)*0.035).toFixed(2);   // cascade diagonale à l'apparition
              const vmDelay=(([...vmCells,...capCells].indexOf(coord))*0.04).toFixed(2); // vague des cases jouables
              let bg=THEME_CELL_BG[getBoardTheme()]||"rgba(32,52,95,.95)",brd="rgba(130,195,255,.65)",shadow="inset 0 0 10px rgba(90,160,255,.18),0 0 4px rgba(74,158,255,.25)",cellAnim=`cellRise .5s cubic-bezier(.22,1,.36,1) ${riseDelay}s both`;
              if(coord==="D1"){bg="rgba(30,70,210,.45)";brd=C.blue;shadow=`inset 0 0 16px ${C.blue}40`;}
              if(coord==="D9"){bg="rgba(200,220,255,.28)";brd=C.white;shadow="inset 0 0 16px rgba(255,255,255,.25)";}
              if(isLastOpp){bg="rgba(255,136,68,.12)";brd=C.orange;cellAnim=`landPulse .7s ease-out`;}
              if(isVM){bg="rgba(0,255,136,.09)";brd=C.green;}
              if(isCap){bg="rgba(255,68,102,.16)";brd=C.red;shadow=EFFECT_CAP_GLOW[getBoardEffect()]||EFFECT_CAP_GLOW.sparkle;}
              if(isSel){bg="rgba(74,158,255,.28)";brd=C.cyan;shadow=`0 0 11px ${C.cyan}52`;cellAnim="selHalo 1.8s ease-in-out infinite";}
              if(isMandSrc){brd=C.red;shadow=`0 0 9px ${C.red}52`;cellAnim="pls 1s infinite";}
              if(isHintFrom){bg="rgba(240,192,64,.22)";brd=C.gold;shadow=`0 0 14px ${C.gold}70`;cellAnim="pls .7s infinite";}
              if(isHintTo){bg="rgba(240,192,64,.14)";brd=C.gold;shadow=`0 0 10px ${C.gold}50`;cellAnim="pls .9s infinite";}
              return(
                <div key={coord} onClick={()=>handleCellClick(coord)} className="cell-h"
                  role="button" tabIndex={0}
                  aria-label={`Case ${coord}${star?(star.color==="W"?", étoile blanche ":", étoile bleue ")+star.type:", vide"}`}
                  onKeyDown={(e)=>{if(e.key==="Enter"||e.key===" "){e.preventDefault();handleCellClick(coord);}}}
                  style={{width:CELL,height:CELL,background:bg,border:`2px solid ${brd}`,borderRadius:5,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",position:"relative",boxShadow:shadow,animation:cellAnim}}>
                  {(coord==="D1"||coord==="D9")&&!star&&<div style={{position:"absolute",inset:0,borderRadius:5,background:coord==="D1"?`radial-gradient(circle,${C.blue}22,transparent 70%)`:"radial-gradient(circle,rgba(255,255,255,.18),transparent 70%)",animation:"zoneShimmer 2.5s ease-in-out infinite",pointerEvents:"none"}}/>}
                  {!star&&coord==="D1"&&<span style={{fontSize:Math.max(5,CELL*.1),color:C.cyan,fontFamily:"'Orbitron',monospace",fontWeight:700,zIndex:1}}>{tUI("BLEU",lang)}</span>}
                  {!star&&coord==="D9"&&<span style={{fontSize:Math.max(5,CELL*.1),color:C.white,fontFamily:"'Orbitron',monospace",fontWeight:700,zIndex:1}}>{tUI("BLANC",lang)}</span>}
                  {isVM&&!star&&<div style={{width:Math.round(CELL*0.24),height:Math.round(CELL*0.24),borderRadius:"50%",background:`radial-gradient(circle,${C.green},rgba(0,255,136,.4))`,boxShadow:`0 0 8px ${C.green}`,animation:`moveDotIn .35s cubic-bezier(.34,1.56,.64,1) ${vmDelay}s both, moveDotBreathe 1.6s ease-in-out ${vmDelay}s infinite`}}/>}
                  {isCap&&star&&<><div style={{position:"absolute",inset:-2,borderRadius:6,border:`2px solid ${C.red}`,animation:"capRing 1s ease-out infinite",pointerEvents:"none"}}/><div style={{position:"absolute",top:3,right:3,width:Math.max(6,CELL*.13),height:Math.max(6,CELL*.13),borderRadius:"50%",background:C.red,boxShadow:`0 0 6px ${C.red}`,animation:"capCorner .7s ease-in-out infinite",zIndex:5}}/></>}
                  {star&&<div style={{zIndex:3,animation:isSel?"pieceLevitate 1.6s cubic-bezier(.45,0,.55,1) infinite":"none",transition:"transform .3s cubic-bezier(.34,1.56,.64,1)"}}><StarSVG type={star.type} color={star.color==="W"?getEquippedSkinColor(C.white,true):C.blue} size={CELL-8} glow={isSel||isCap} flipped={myColor==="W"}/></div>}
                  <span style={{position:"absolute",top:1,left:2,fontSize:Math.min(Math.max(5,CELL*.1),11),color:"rgba(74,158,255,.3)",fontFamily:"monospace",zIndex:1}}>{coord}</span>
                </div>
              );
            })}
          </div>
        ))}
        </div>
      </div>
      {/* ── BARRE JOUEUR (bas) ── */}
      <div style={{display:"flex",alignItems:"center",gap:6,padding:"5px 10px",
        background:myColor==="W"?"rgba(200,220,255,.05)":"rgba(74,158,255,.05)",
        borderTop:`1px solid ${myColor==="W"?"rgba(200,220,255,.1)":"rgba(74,158,255,.12)"}`,
        flexShrink:0,minHeight:36}}>
        <StarSVG type={myColor==="W"?"Sirus":"Rigel"} color={myColor==="W"?C.white:C.blue} size={18} glow={false} flipped={myColor==="W"}/>
        <div style={{flex:1,minWidth:0}}>
          <div style={{fontSize:8,fontWeight:700,letterSpacing:2,
            color:myColor==="W"?C.white:C.blue,fontFamily:"'Orbitron',monospace"}}>
            {user.name} <span style={{fontSize:7,color:C.dim}}>· {myColor==="W"?"★ "+tUI("BLANCS",lang):"✦ "+tUI("BLEUS",lang)}</span>
          </div>
          <div style={{display:"flex",gap:2,flexWrap:"wrap",marginTop:1}}>
            {capturedOnline[myColor].slice(-7).map((s,i)=>
              <StarSVG key={i} type={s.type==="?"?"Rigel":s.type} color={myColor==="W"?C.white:C.blue} size={11} glow={false}/>)}
          </div>
        </div>
      </div>

      {/* Chat coulissant (ouvre via le bouton CHAT) */}
      {/* Message paiement indice en ligne */}
      {onlineHintMsg&&(
        <div style={{position:"absolute",left:0,right:0,bottom:64,zIndex:70,textAlign:"center",
          fontSize:10,fontWeight:700,fontFamily:"'Orbitron',monospace",
          color:onlineHintMsg.indexOf("-")===0?C.gold:C.red,animation:"zIn .3s ease",pointerEvents:"none"}}>{onlineHintMsg}</div>
      )}
    </div>
  );

  return(
    <div style={{width:"100%",height:"100%",background:`linear-gradient(180deg,#060c1e,${C.void})`,display:"flex",flexDirection:"column",overflow:"hidden",fontFamily:"'Exo 2',sans-serif"}}>
      <Starfield count={50}/><Nebulas/>
      <div style={{padding:"13px 13px 0",display:"flex",alignItems:"center",gap:10,zIndex:2}}>
        <button onClick={()=>{try{audio.sfxClick();}catch(e){}onNav("home");}} style={{background:"rgba(74,158,255,.1)",border:`1px solid ${C.blue}38`,borderRadius:8,padding:"5px 10px",color:C.blue,cursor:"pointer",fontSize:15}}>&#8249;</button>
        <div style={{fontSize:10,color:C.white,fontWeight:700,letterSpacing:3,fontFamily:"'Orbitron',monospace"}}>{tUI("JEU EN LIGNE",lang)}</div>
        <div style={{marginLeft:"auto",display:"flex",alignItems:"center",gap:5}}>
          <div style={{width:6,height:6,borderRadius:"50%",
            background:netStatus==="online"?C.green:(netStatus==="connecting"?C.gold:C.dim),
            animation:netStatus==="connecting"?"pls .8s infinite":"pls 1.5s infinite",
            boxShadow:`0 0 5px ${netStatus==="online"?C.green:C.gold}`}}/>
          <span style={{fontSize:7.5,color:netStatus==="online"?C.green:(netStatus==="connecting"?C.gold:C.dim),letterSpacing:2}}>
            {netStatus==="online"?tUI("CONNECTÉ",lang):(netStatus==="connecting"?tUI("CONNEXION...",lang):tUI("ENTRAÎNEMENT",lang))}
          </span>
        </div>
      </div>

      {/* Bannière de statut : honnête sur le mode réel vs démo */}
      {netStatus==="demo"&&(
        <div style={{margin:"8px 13px 0",padding:"8px 11px",background:"rgba(240,192,64,.08)",
          border:`1px solid ${C.gold}30`,borderRadius:9,display:"flex",alignItems:"center",gap:8,zIndex:2}}>
          <span style={{fontSize:14}}>🎯</span>
          <div style={{flex:1}}>
            <div style={{fontSize:8.5,color:C.gold,fontWeight:700,letterSpacing:1,fontFamily:"'Orbitron',monospace"}}>{tUI("MODE ENTRAÎNEMENT",lang)}</div>
            <div style={{fontSize:7.5,color:C.dim,marginTop:1,lineHeight:1.4}}>
              {netError||tUI("Vous affrontez l'ordinateur. Le multijoueur entre vrais joueurs s'activera dès la mise en ligne du serveur.",lang)}
            </div>
          </div>
        </div>
      )}
      {view==="lobby"&&(
        <div style={{flex:1,overflowY:"auto",padding:"10px 13px",zIndex:2}}>
          {/* Anti-triche : partie abandonnée toujours en cours (chrono qui tourne) */}
          {abandoned&&!gameResult&&(
            <div style={{display:"flex",alignItems:"center",gap:10,
              background:"rgba(255,68,102,.1)",border:`1px solid ${C.red}40`,borderRadius:10,
              padding:"10px 13px",marginBottom:10,animation:"pls 1.5s infinite"}}>
              <span style={{fontSize:20}}>⚠️</span>
              <div style={{flex:1}}>
                <div style={{fontSize:9,color:C.red,fontWeight:700,letterSpacing:1,fontFamily:"'Orbitron',monospace"}}>{tUI("PARTIE ABANDONNÉE",lang)}</div>
                <div style={{fontSize:8,color:C.dim,marginTop:2,lineHeight:1.4}}>{tUI("Votre temps continue de s'écouler. Vous perdrez à 0.",lang)}</div>
              </div>
              <div style={{fontSize:15,color:C.red,fontWeight:900,fontFamily:"'Orbitron',monospace"}}>{fmtT(myColor==="W"?oTimeW:oTimeB)}</div>
            </div>
          )}
          {/* Solde d'étoiles de mise */}
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",
            background:"rgba(240,192,64,.06)",border:`1px solid ${C.gold}26`,borderRadius:10,
            padding:"9px 13px",marginBottom:10}}>
            <span style={{fontSize:8,color:C.dim,letterSpacing:2,fontFamily:"'Orbitron',monospace"}}>{econUI("yourStakeStars",lang)}</span>
            <span style={{fontSize:14,color:C.gold,fontWeight:900,fontFamily:"'Orbitron',monospace"}}>⭐ {myStars}</span>
          </div>
          {/* Sélecteur de galaxies — carrousel horizontal défilable */}
          <div style={{fontSize:7.5,color:C.dim,letterSpacing:3,marginBottom:8,fontFamily:"'Orbitron',monospace"}}>{econUI("chooseGalaxy",lang)} <span style={{opacity:.5}}>‹ ›</span></div>
          <div className="gx-scroll" style={{display:"flex",gap:12,overflowX:"auto",overflowY:"hidden",
            scrollSnapType:"x mandatory",WebkitOverflowScrolling:"touch",padding:"4px 2px 12px",marginBottom:8}}>
            {GALAXIES.map(g=>{
              const affordable = myStars >= g.stake;
              const sel = selectedGalaxy.id===g.id;
              return (
                <button key={g.id} disabled={!affordable}
                  onClick={()=>{if(!affordable)return;try{audio.sfxClick();}catch(e){}setSelectedGalaxy(g);}}
                  aria-label={`${galaxyName(g.id,lang)}, mise ${g.stake} étoiles${affordable?"":", étoiles insuffisantes"}`}
                  style={{flex:"0 0 auto",width:158,scrollSnapAlign:"center",
                    display:"flex",flexDirection:"column",alignItems:"center",gap:6,padding:"14px 12px",borderRadius:16,
                    background:sel?`linear-gradient(160deg,${g.glow}2e,rgba(8,12,28,.92))`:"rgba(10,18,35,.82)",
                    border:`1.5px solid ${sel?g.color:(affordable?g.color+"30":C.dim+"18")}`,
                    cursor:affordable?"pointer":"not-allowed",opacity:affordable?1:0.4,
                    boxShadow:sel?`0 0 26px ${g.glow}50`:"none",
                    transform:sel?"scale(1.04)":"scale(1)",transition:"transform .25s cubic-bezier(.34,1.56,.64,1),box-shadow .25s,border-color .25s,background .25s"}}>
                  <GalaxyVisual color={g.color} glow={g.glow} size={100} id={g.id}/>
                  <div style={{fontSize:12,fontWeight:900,color:sel?g.color:C.white,letterSpacing:1,fontFamily:"'Orbitron',monospace",textAlign:"center"}}>{galaxyName(g.id,lang)}</div>
                  <div style={{fontSize:7.5,color:C.dim,lineHeight:1.3,textAlign:"center",minHeight:20}}>{galaxyDesc(g.id,lang)}</div>
                  <div style={{display:"flex",alignItems:"center",gap:4,marginTop:2,padding:"3px 10px",borderRadius:20,background:`${C.gold}14`,border:`1px solid ${C.gold}30`}}>
                    <span style={{fontSize:13,fontWeight:900,color:C.gold,fontFamily:"'Orbitron',monospace"}}>⭐{g.stake}</span>
                    <span style={{fontSize:6.5,color:C.goldDim,letterSpacing:1}}>{econUI("stake",lang)}</span>
                  </div>
                  {sel&&(
                    <button
                      onClick={(e)=>{e.stopPropagation();try{audio.sfxConnect();}catch(er){}setView("search");}}
                      style={{marginTop:4,width:"100%",padding:"9px",borderRadius:10,
                        background:`linear-gradient(135deg,${g.color},${g.glow})`,
                        border:"none",color:C.void,fontSize:10,fontWeight:900,letterSpacing:1.5,
                        cursor:"pointer",fontFamily:"'Orbitron',monospace",
                        boxShadow:`0 0 18px ${g.glow}66`,animation:"pls 2s ease-in-out infinite"}}>
                      ▶ {tUI("ENTRER",lang)}
                    </button>
                  )}
                </button>
              );
            })}
          </div>
          {/* Statut de connexion réseau */}
          <div style={{marginTop:6,background:"rgba(5,10,25,.72)",border:`1px solid ${netStatus==="online"?"rgba(0,255,136,.18)":"rgba(255,136,68,.18)"}`,borderRadius:10,padding:"12px 14px",textAlign:"center"}}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:7,marginBottom:5}}>
              <div style={{width:7,height:7,borderRadius:"50%",background:netStatus==="online"?C.green:C.orange,boxShadow:`0 0 7px ${netStatus==="online"?C.green:C.orange}`,animation:"pls 1.4s infinite"}}/>
              <span style={{fontSize:9,fontWeight:700,letterSpacing:2,color:netStatus==="online"?C.green:C.orange,fontFamily:"'Orbitron',monospace"}}>
                {netStatus==="online"?tUI("CONNECTÉ AU SERVEUR",lang):tUI("SERVEUR INJOIGNABLE",lang)}
              </span>
            </div>
            <div style={{fontSize:8,color:C.dim,lineHeight:1.4}}>
              {netStatus==="online"
                ?tUI("Choisissez une galaxie et lancez la recherche d'un adversaire.",lang)
                :tUI("La recherche en ligne est momentanément indisponible.",lang)}
            </div>
          </div>
        </div>
      )}
      {view==="search"&&(
        <div style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:20,padding:"20px",zIndex:2}}>
          {!noHuman?(
            <>
              <div style={{position:"relative",width:150,height:150,display:"flex",alignItems:"center",justifyContent:"center"}}>
                {[75,105,135].map((s,i)=><div key={i} style={{position:"absolute",width:s,height:s,borderRadius:"50%",border:`1px solid ${C.blue}${28-i*8}`,animation:`plsR ${2+i*.5}s ${i*.4}s ease-out infinite`}}/>)}
                <div style={{position:"absolute",width:68,height:1,background:`linear-gradient(90deg,transparent,${C.cyan})`,transformOrigin:"left center",left:"50%",top:"50%",animation:"rotS 3s linear infinite"}}/>
                <div style={{animation:"flt 3s ease-in-out infinite"}}><StarSVG type="Sirus" color={C.cyan} size={42} anim/></div>
              </div>
              <div style={{textAlign:"center"}}>
                <div style={{fontSize:13,color:C.white,fontWeight:700,letterSpacing:3,fontFamily:"'Orbitron',monospace"}}>{tUI("RECHERCHE D'UN JOUEUR",lang)}{".".repeat(dots)}</div>
                <div style={{fontSize:9,color:C.dim,marginTop:5}}>{tUI("Mise",lang)}: <span style={{color:C.gold}}>⭐{stake}</span> · {searchElapsed}s</div>
              </div>
              <button onClick={()=>{try{audio.sfxClick();}catch(e){}setView("lobby");}} style={{padding:"8px 22px",background:"transparent",border:`1px solid ${C.red}42`,borderRadius:20,color:C.red,fontSize:9,cursor:"pointer",letterSpacing:2,fontFamily:"'Orbitron',monospace"}}>{tUI("ANNULER",lang)}</button>
            </>
          ):(
            <div style={{width:"100%",maxWidth:340,display:"flex",flexDirection:"column",alignItems:"center",gap:16,animation:"zIn .4s ease"}}>
              <div style={{fontSize:40}}>🌌</div>
              <div style={{textAlign:"center"}}>
                <div style={{fontSize:12,color:C.orange,fontWeight:900,letterSpacing:2,fontFamily:"'Orbitron',monospace",marginBottom:6}}>{tUI("AUCUN JOUEUR CONNECTÉ",lang)}</div>
                <div style={{fontSize:9.5,color:C.dim,lineHeight:1.5}}>{tUI("Aucun joueur n'est disponible pour le moment. Voulez-vous jouer contre l'intelligence artificielle DOSCO ?",lang)}</div>
              </div>
              <div style={{display:"flex",flexDirection:"column",gap:10,width:"100%"}}>
                <button onClick={acceptAIOpponent} className="btn-c"
                  style={{width:"100%",padding:"13px",borderRadius:12,
                    background:`linear-gradient(135deg,${C.purple},${C.blue})`,border:"none",
                    color:C.white,fontSize:11,fontWeight:900,letterSpacing:2,cursor:"pointer",
                    fontFamily:"'Orbitron',monospace",boxShadow:`0 0 20px ${C.purple}55`}}>
                  🤖 {tUI("JOUER CONTRE L'IA",lang)}
                </button>
                <button onClick={()=>{try{audio.sfxClick();}catch(e){}setNoHuman(false);setView("search");}}
                  style={{width:"100%",padding:"11px",borderRadius:12,
                    background:"rgba(74,158,255,.1)",border:`1px solid ${C.blue}38`,
                    color:C.blue,fontSize:10,fontWeight:700,letterSpacing:1.5,cursor:"pointer",
                    fontFamily:"'Orbitron',monospace"}}>
                  🔄 {tUI("CONTINUER LA RECHERCHE",lang)}
                </button>
                <button onClick={()=>{try{audio.sfxClick();}catch(e){}setView("lobby");}}
                  style={{width:"100%",padding:"9px",borderRadius:12,background:"transparent",
                    border:`1px solid ${C.red}38`,color:C.red,fontSize:9,letterSpacing:2,cursor:"pointer",
                    fontFamily:"'Orbitron',monospace"}}>
                  {tUI("ANNULER",lang)}
                </button>
              </div>
            </div>
          )}
        </div>
      )}
      {view==="room"&&opp&&(
        <div style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:14,padding:"16px 18px",zIndex:2}}>
          <div style={{fontSize:9.5,color:C.green,letterSpacing:4,fontWeight:700,fontFamily:"'Orbitron',monospace",animation:"zIn .4s ease"}}>{tUI("ADVERSAIRE TROUVE",lang)}</div>
          <div style={{width:"100%",background:"rgba(10,18,40,.92)",border:`1px solid rgba(74,158,255,.18)`,borderRadius:16,padding:15,display:"flex",alignItems:"center",gap:12,animation:"zIn .5s ease"}}>
            <div style={{flex:1,textAlign:"center"}}><div style={{animation:"flt 3s ease-in-out infinite"}}><StarSVG type="Sirus" color={C.white} size={34}/></div><div style={{fontSize:10,color:C.white,fontWeight:700,marginTop:5,letterSpacing:2,fontFamily:"'Orbitron',monospace"}}>{user.name}</div><div style={{fontSize:13,color:C.gold,fontWeight:900,marginTop:3,fontFamily:"'Orbitron',monospace",animation:"glwG 2s infinite"}}>étoiles {getSeason()?.stars||100}</div></div>
            <div style={{fontSize:20,fontWeight:900,color:C.red,fontFamily:"'Orbitron',monospace",textShadow:`0 0 14px ${C.red}`,animation:"pls 1.5s infinite"}}>VS</div>
            <div style={{flex:1,textAlign:"center"}}><div style={{animation:"flt 3.5s .5s ease-in-out infinite"}}><StarSVG type={opp.t||"Rigel"} color={opp.isAI?C.purple:C.blue} size={34}/></div><div style={{fontSize:10,color:opp.isAI?C.purple:C.blue,fontWeight:700,marginTop:5,letterSpacing:2,fontFamily:"'Orbitron',monospace"}}>{opp.isAI?"🤖 "+opp.name:opp.name}</div><div style={{fontSize:9,color:C.dim,fontWeight:700,marginTop:3,fontFamily:"'Orbitron',monospace"}}>{opp.isAI?opp.rank:"⭐"+opp.stars}</div></div>
          </div>
          {/* Statistiques de l'adversaire (visibles avant le duel) — humains uniquement */}
          {!opp.isAI&&(()=>{
            const st = opp.id ? getPlayerStats(opp.id) : (opp.stats||null);
            const flag = st?.flag || countryFlag(opp.country||"XX");
            const cName = st?.countryName || countryName(opp.country||"XX");
            return(
              <div style={{width:"100%",background:"rgba(10,18,40,.7)",border:`1px solid rgba(74,158,255,.16)`,borderRadius:12,padding:"11px 13px",animation:"zIn .6s ease"}}>
                <div style={{display:"flex",alignItems:"center",gap:7,marginBottom:9}}>
                  <span style={{fontSize:15}}>{flag}</span>
                  <span style={{fontSize:9,color:C.white,fontWeight:700,letterSpacing:1,fontFamily:"'Orbitron',monospace",flex:1}}>{opp.name}</span>
                  <span style={{fontSize:8,color:C.dim}}>{cName}</span>
                </div>
                <div style={{display:"flex",gap:8}}>
                  <div style={{flex:1,textAlign:"center",background:"rgba(74,158,255,.07)",borderRadius:8,padding:"7px 4px"}}>
                    <div style={{fontSize:7,color:C.dim,letterSpacing:1,marginBottom:3}}>{tUI("RANG NATIONAL",lang)}</div>
                    <div style={{fontSize:13,color:C.cyan,fontWeight:900,fontFamily:"'Orbitron',monospace"}}>{st?("#"+st.nationalRank):"—"}</div>
                  </div>
                  <div style={{flex:1,textAlign:"center",background:"rgba(240,192,64,.07)",borderRadius:8,padding:"7px 4px"}}>
                    <div style={{fontSize:7,color:C.dim,letterSpacing:1,marginBottom:3}}>{tUI("RANG MONDIAL",lang)}</div>
                    <div style={{fontSize:13,color:C.gold,fontWeight:900,fontFamily:"'Orbitron',monospace"}}>{st?("#"+st.worldRank):"—"}</div>
                  </div>
                  <div style={{flex:1,textAlign:"center",background:"rgba(0,255,136,.07)",borderRadius:8,padding:"7px 4px"}}>
                    <div style={{fontSize:7,color:C.dim,letterSpacing:1,marginBottom:3}}>{tUI("% VICTOIRES",lang)}</div>
                    <div style={{fontSize:13,color:C.green,fontWeight:900,fontFamily:"'Orbitron',monospace"}}>{st?(st.winPct+"%"):"—"}</div>
                  </div>
                </div>
              </div>
            );
          })()}
          <div style={{width:"100%",background:"rgba(240,192,64,.05)",border:`1px solid ${C.gold}22`,borderRadius:10,padding:12,textAlign:"center"}}>
            <div style={{fontSize:20,color:C.gold,fontWeight:900,fontFamily:"'Orbitron',monospace",animation:"glwG 2s infinite"}}>{tUI("Mise",lang)} : ⭐{opp.isAI?stake:stake*2}</div>
            <div style={{fontSize:8,color:C.dim,marginTop:2}}>{opp.isAI?tUI("ENTRAÎNEMENT",lang):("Salle: "+roomId)}</div>
          </div>
          <button onClick={startGame} className="btn-c" style={{width:"100%",padding:"13px",background:`linear-gradient(135deg,${C.blue},${C.cyan})`,borderRadius:12,color:C.void,fontSize:12,fontWeight:900,letterSpacing:3,boxShadow:`0 0 22px ${C.blue}52`,fontFamily:"'Orbitron',monospace",animation:"pls 2s ease-in-out infinite"}}>{tUI("ENGAGER LA BATAILLE",lang)}</button>
        </div>
      )}
    </div>
  );
};

// ── Étapes du tutoriel (pédagogie progressive) ──
const TUTORIAL_STEPS = [
  { title:"BIENVENUE DANS DOSCO",
    text:"DOSCO oppose deux familles d'étoiles sur le DOSCOCIEL, un plateau cosmique de 43 cases. Votre objectif : dominer l'adversaire par la stratégie. Apprenons les bases en 2 minutes.",
    highlight:null },
  { title:"LE PLATEAU DOSCOCIEL",
    text:"Le plateau compte 7 colonnes (A à G) et 9 rangées. Les Blancs partent du bas et avancent vers le haut ; les Bleus partent du haut et descendent. Les Bleus jouent toujours en premier.",
    highlight:null },
  { title:"DÉPLACER UNE ÉTOILE",
    text:"Chaque étoile se déplace d'UNE case selon sa morphologie propre. Touchez une étoile pour voir ses déplacements possibles surlignés, puis touchez une case libre pour bouger. Essayez maintenant : déplacez l'étoile bleue surlignée !",
    highlight:"B7", interactive:true },
  { title:"LES 14 MORPHOLOGIES",
    text:"Chaque étoile a un schéma de mouvement unique. Sirus se déplace dans les 8 directions. Acrux avance en triangle. Deneb file en ligne droite. Maîtriser ces schémas est la clé de la victoire.",
    highlight:null },
  { title:"LA CAPTURE EST OBLIGATOIRE",
    text:"Si l'une de vos étoiles peut en capturer une adverse, vous DEVEZ le faire. Capturer, c'est déplacer votre étoile sur une case occupée par l'ennemi. Pensez toujours aux captures avant de jouer.",
    highlight:null },
  { title:"DEUX VOIES VERS LA VICTOIRE",
    text:"Gagnez de deux façons : l'ÉLIMINATION (capturer toutes les étoiles adverses) ou l'INFILTRATION (atteindre le camp adverse — D1 pour les Bleus, D9 pour les Blancs).",
    highlight:null },
  { title:"À VOUS DE JOUER !",
    text:"Vous connaissez l'essentiel. Affrontez l'ordinateur sur 7 niveaux de difficulté, défiez un ami en local, ou mesurez-vous au monde en ligne. Que la bataille des étoiles commence !",
    action:"finish" },
];

const TutorialScreen=({onNav,lang="fr"})=>{
  const[step,setStep]=useState(0);
  const[animIn,setAnimIn]=useState(true);
  const[boardState]=useState({
    D1:{color:"W",type:"Sirus"}, B3:{color:"W",type:"Deneb"}, F3:{color:"W",type:"Alhena"},
    D9:{color:"B",type:"Rigel"}, B7:{color:"B",type:"Acrux"}, F7:{color:"B",type:"Spica"},
  });
  const cur = TUTORIAL_STEPS[step];
  const progress = ((step+1)/TUTORIAL_STEPS.length)*100;
  // État interactif : sélection + déplacement réel d'une étoile pendant le tuto
  const[liveBoard,setLiveBoard]=useState(null);
  const[tutoSel,setTutoSel]=useState(null);
  const[tutoDone,setTutoDone]=useState(false);
  // Initialiser le plateau interactif à l'étape interactive
  useEffect(()=>{
    if(cur&&cur.interactive){ setLiveBoard({...boardState}); setTutoSel(null); setTutoDone(false); }
  },[step]);

  const goNext = ()=>{
    setAnimIn(false);
    setTimeout(()=>{
      setStep(s=>Math.min(s+1,TUTORIAL_STEPS.length-1));
      setAnimIn(true);
    },250);
  };
  const finish=()=>{markTutorialSeen();try{audio.sfxVictory();}catch(e){};try{MusicPlayer.play("victory",false);}catch(e){}onNav("home");};

  // Plateau complet du DOSCOCIEL (toutes les cases visibles)
  const MINI_LAYOUT=[
    [null,null,null,"D1",null,null,null],
    [null,null,"C2","D2","E2",null,null],
    ["A3","B3","C3","D3","E3","F3","G3"],
    ["A4","B4","C4","D4","E4","F4","G4"],
    ["A5","B5","C5","D5","E5","F5","G5"],
    ["A6","B6","C6","D6","E6","F6","G6"],
    ["A7","B7","C7","D7","E7","F7","G7"],
    [null,null,"C8","D8","E8",null,null],
    [null,null,null,"D9",null,null,null],
  ];
  const CELL=33;

  return(
    <div style={{width:"100%",height:"100%",background:`linear-gradient(180deg,#060d1e,${C.void})`,
      display:"flex",flexDirection:"column",overflow:"hidden",fontFamily:"'Exo 2',sans-serif"}}>
      <Starfield count={50}/><Nebulas/>
      {/* Header */}
      <div style={{padding:"12px 14px 8px",display:"flex",alignItems:"center",gap:10,zIndex:2}}>
        <button onClick={()=>{try{audio.sfxClick();}catch(e){}onNav("home");}} style={{background:"rgba(74,158,255,.1)",
          border:`1px solid ${C.blue}38`,borderRadius:8,padding:"5px 10px",color:C.blue,cursor:"pointer",fontSize:15}}>‹</button>
        <div style={{fontSize:10,color:C.white,fontWeight:900,letterSpacing:3,fontFamily:"'Orbitron',monospace"}}>{tUI("TUTORIEL",lang)}</div>
        <div style={{marginLeft:"auto",fontSize:8.5,color:C.dim}}>{step+1}/{TUTORIAL_STEPS.length}</div>
      </div>

      {/* Barre de progression */}
      <div style={{margin:"0 14px 12px",height:3,background:"rgba(74,158,255,.12)",borderRadius:2,zIndex:2}}>
        <div style={{height:"100%",width:`${progress}%`,background:`linear-gradient(90deg,${C.blue},${C.cyan})`,
          borderRadius:2,transition:"width .4s ease",boxShadow:`0 0 6px ${C.cyan}`}}/>
      </div>

      {/* Contenu animé */}
      <div style={{flex:1,overflowY:"auto",padding:"0 16px 16px",zIndex:2,
        opacity:animIn?1:0,transform:animIn?"translateY(0)":"translateY(12px)",transition:"all .25s ease"}}>

        {/* Icône étape */}
        <div style={{textAlign:"center",marginBottom:12}}>
          <div style={{
            width:64,height:64,borderRadius:"50%",margin:"0 auto",
            background:`linear-gradient(135deg,${C.blue}28,${C.cyan}14)`,
            border:`2px solid ${C.blue}50`,
            display:"flex",alignItems:"center",justifyContent:"center",
            fontSize:28,animation:"pls 2s ease-in-out infinite",
          }}>
            {["🌌","⭐","➡️","🔮","💥","🏆","🚀"][step]}
          </div>
        </div>

        {/* Titre */}
        <div style={{textAlign:"center",marginBottom:10}}>
          <div style={{fontSize:14,fontWeight:900,color:C.white,letterSpacing:2,
            fontFamily:"'Orbitron',monospace",textShadow:`0 0 16px ${C.blue}40`}}>{cur.title}</div>
        </div>

        {/* Mini plateau démonstratif + interactif */}
        {step<=2&&(
          <div style={{display:"flex",flexDirection:"column",alignItems:"center",marginBottom:14}}>
            <div style={{padding:8,borderRadius:12,
              background:THEME_BOARD_BG[getBoardTheme()]||"radial-gradient(ellipse at center,rgba(28,48,90,.5),rgba(10,18,40,.7))",
              border:"1px solid rgba(130,195,255,.25)"}}>
              {(() => {
                const activeBoard = (cur.interactive && liveBoard) ? liveBoard : boardState;
                // Cases atteignables si une étoile est sélectionnée (étape interactive)
                let reachable = [];
                if(cur.interactive && tutoSel && activeBoard[tutoSel]){
                  try { const m = getMoves(tutoSel, activeBoard); reachable = [...m.moves, ...m.captures]; } catch(e){}
                }
                return [...MINI_LAYOUT].reverse().map((row,ri)=>(
                  <div key={ri} style={{display:"flex",gap:3,marginBottom:3}}>
                    {row.map((coord,ci)=>{
                      if(!coord) return <div key={ci} style={{width:CELL,height:CELL}}/>;
                      const star=activeBoard[coord];
                      const isHighlight=cur.highlight===coord && !tutoSel && !tutoDone;
                      const isSel = cur.interactive && tutoSel===coord;
                      const isReach = reachable.includes(coord);
                      let bg="rgba(32,52,95,.92)",brd="rgba(130,195,255,.5)",cshadow="none";
                      if(coord==="D1"){bg="rgba(30,70,210,.45)";brd=C.blue;cshadow=`inset 0 0 16px ${C.blue}40`;}
                      if(coord==="D9"){bg="rgba(200,220,255,.28)";brd=C.white;cshadow="inset 0 0 16px rgba(255,255,255,.25)";}
                      if(isHighlight){bg="rgba(0,229,255,.25)";brd=C.cyan;cshadow=`0 0 10px ${C.cyan}`;}
                      if(isReach){bg="rgba(0,229,255,.18)";brd=C.cyan;}
                      if(isSel){bg="rgba(0,229,255,.32)";brd=C.cyan;cshadow=`0 0 12px ${C.cyan}`;}
                      const clickable = cur.interactive && !tutoDone && (
                        (!tutoSel && star && star.color==="B") || (tutoSel && isReach)
                      );
                      const onCell = ()=>{
                        if(!clickable) return;
                        try{audio.sfxClick();}catch(e){}
                        if(!tutoSel){ setTutoSel(coord); return; }
                        // Déplacer
                        if(isReach){
                          const nb={...liveBoard}; nb[coord]={...nb[tutoSel]}; delete nb[tutoSel];
                          setLiveBoard(nb); setTutoSel(null); setTutoDone(true);
                          try{audio.sfxMove&&audio.sfxMove();}catch(e){}
                        }
                      };
                      return(
                        <div key={coord} onClick={onCell} style={{width:CELL,height:CELL,background:bg,
                          border:`1.5px solid ${brd}`,borderRadius:4,
                          display:"flex",alignItems:"center",justifyContent:"center",
                          cursor:clickable?"pointer":"default",
                          animation:(isHighlight||isReach)?"pls 1s infinite":"none",
                          boxShadow:cshadow}}>
                          {star&&<StarSVG type={star.type} color={star.color==="W"?getEquippedSkinColor(C.white,true):C.blue} size={20} glow={isHighlight||isSel} flipped={true}/>}
                        </div>
                      );
                    })}
                  </div>
                ));
              })()}
            </div>
            {/* Retour interactif étape 2 */}
            {cur.interactive && (
              <div style={{marginTop:10,fontSize:9.5,fontWeight:700,letterSpacing:1,
                color:tutoDone?C.green:(tutoSel?C.cyan:C.gold),fontFamily:"'Orbitron',monospace",
                textAlign:"center",transition:"color .3s"}}>
                {tutoDone?"✓ PARFAIT ! Vous avez déplacé une étoile.":(tutoSel?"Touchez une case surlignée pour vous déplacer":"👆 Touchez l'étoile bleue surlignée")}
              </div>
            )}
          </div>
        )}

        {/* Visuel morphologie */}
        {step===3&&(
          <div style={{display:"flex",gap:8,justifyContent:"center",marginBottom:14,flexWrap:"wrap"}}>
            {[["Sirus","8 dir.",C.white],["Acrux","3av+1G+1D+1ar",C.blue],["Deneb","3av+3ar",C.white]].map(([t,d,c],i)=>(
              <div key={i} style={{textAlign:"center",padding:"10px",background:"rgba(10,18,35,.85)",
                border:`1px solid rgba(74,158,255,.15)`,borderRadius:10,minWidth:90}}>
                <div style={{animation:"flt 3s ease-in-out infinite"}}>
                  <StarSVG type={t} color={c} size={32}/>
                </div>
                <div style={{fontSize:8.5,color:c,fontWeight:700,marginTop:6,fontFamily:"'Orbitron',monospace"}}>{t}</div>
                <div style={{fontSize:7,color:C.dim,marginTop:2}}>{d}</div>
              </div>
            ))}
          </div>
        )}

        {/* Visuel victoire */}
        {step===5&&(
          <div style={{display:"flex",flexDirection:"column",gap:7,marginBottom:14}}>
            {[{icon:"💥",c:C.red,t:"ÉLIMINATION",d:"Capturez toutes les étoiles adverses"},
  
              {icon:"🌌",c:C.cyan,t:"INFILTRATION",d:"Atteignez D1 ou D9 — camp adverse"},
            ].map((v,i)=>(
              <div key={i} style={{display:"flex",alignItems:"center",gap:12,padding:"10px 14px",
                background:`${v.c}0d`,border:`1px solid ${v.c}28`,borderRadius:10}}>
                <span style={{fontSize:22}}>{v.icon}</span>
                <div>
                  <div style={{fontSize:10,fontWeight:700,color:v.c,letterSpacing:2,fontFamily:"'Orbitron',monospace"}}>{v.t}</div>
                  <div style={{fontSize:9,color:C.dim,marginTop:2}}>{v.d}</div>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Visuel prêt */}
        {step===6&&(
          <div style={{textAlign:"center",marginBottom:14}}>
            <div style={{animation:"rotS 4s linear infinite",display:"inline-block",marginBottom:10}}>
              <StarSVG type="Sirus" color={C.gold} size={60} anim/>
            </div>
            <div style={{display:"flex",gap:8,justifyContent:"center",marginTop:8}}>
              {["🌱 Novice","⭐ Gardien","🔥 Maître","💀 Supernova"].map((d,i)=>(
                <div key={i} style={{fontSize:8,color:C.dim,padding:"4px 8px",background:"rgba(74,158,255,.08)",
                  border:`1px solid rgba(74,158,255,.15)`,borderRadius:6}}>{d}</div>
              ))}
            </div>
          </div>
        )}

        {/* Texte explicatif */}
        <div style={{background:"rgba(10,18,35,.85)",border:`1px solid rgba(74,158,255,.14)`,
          borderRadius:12,padding:"14px 16px",marginBottom:16}}>
          <div style={{fontSize:12,lineHeight:1.8,color:C.white,opacity:.9,
            fontFamily:"'Exo 2',sans-serif",fontWeight:300}}>{cur.text}</div>
        </div>

        {/* Bouton (verrouillé tant que l'étape interactive n'est pas réussie) */}
        {(() => {
          const locked = cur.interactive && !tutoDone;
          return (
            <button onClick={()=>{ if(locked)return; cur.action==="finish"?finish():goNext(); }}
              className="btn-c" disabled={locked}
              style={{width:"100%",padding:"14px",
                background:locked
                  ?"rgba(40,48,65,.5)"
                  :(cur.action==="finish"
                    ?`linear-gradient(135deg,${C.gold},${C.orange})`
                    :`linear-gradient(135deg,${C.blue},${C.cyan})`),
                borderRadius:12,color:locked?C.dim:C.void,fontSize:12,fontWeight:900,
                letterSpacing:3,fontFamily:"'Orbitron',monospace",cursor:locked?"not-allowed":"pointer",
                boxShadow:locked?"none":`0 0 20px ${cur.action==="finish"?C.gold:C.blue}45`}}>
              {locked?"↑ DÉPLACEZ UNE ÉTOILE":(cur.action==="finish"?"✦ JOUER MAINTENANT":"SUIVANT →")}
            </button>
          );
        })()}

        {/* Skip */}
        {step<TUTORIAL_STEPS.length-1&&(
          <button onClick={()=>{markTutorialSeen();try{audio.sfxClick();}catch(e){}onNav("home");}} style={{
            width:"100%",marginTop:8,padding:"8px",background:"transparent",
            border:"none",color:C.dim,fontSize:9,cursor:"pointer",letterSpacing:2,
            fontFamily:"'Orbitron',monospace"}}>Passer le tutoriel</button>
        )}
      </div>
    </div>
  );
};

// ════════════════════════════════════════════════════════
// 🎬 REPLAY VIEWER — Revoir ses parties
// ════════════════════════════════════════════════════════
const ReplayScreen=({onNav,lang="fr"})=>{
  const[playing,setPlaying]=useState(false);
  const[moveIdx,setMoveIdx]=useState(0);
  const[speed,setSpeed]=useState(1);

  // Simulation d'une partie sauvegardée
  const DEMO_MOVES=[
    {from:"B7",to:"B6",color:"B",type:"Acrux",capture:null},
    {from:"G3",to:"G4",color:"W",type:"Merak",capture:null},
    {from:"B6",to:"B5",color:"B",type:"Acrux",capture:null},
    {from:"F3",to:"F4",color:"W",type:"Alhena",capture:null},
    {from:"B5",to:"C4",color:"B",type:"Acrux",capture:null},
    {from:"F4",to:"E5",color:"W",type:"Alhena",capture:null},
    {from:"C4",to:"D3",color:"B",type:"Acrux",capture:"W"},
    {from:"B3",to:"C3",color:"W",type:"Deneb",capture:null},
    {from:"D3",to:"D2",color:"B",type:"Acrux",capture:null},
    {from:"D1",to:"E2",color:"W",type:"Sirus",capture:null},
  ];

  const replayMoves=DEMO_MOVES.slice(0,moveIdx);

  useEffect(()=>{
    if(!playing) return;
    if(moveIdx>=DEMO_MOVES.length){setPlaying(false);return;}
    const t=setTimeout(()=>setMoveIdx(i=>i+1),1000/speed);
    return()=>clearTimeout(t);
  },[playing,moveIdx,speed]);

  return(
    <div style={{width:"100%",height:"100%",background:`linear-gradient(180deg,#060d1e,${C.void})`,
      display:"flex",flexDirection:"column",overflow:"hidden",fontFamily:"'Exo 2',sans-serif"}}>
      <Starfield count={40}/><Nebulas/>
      <div style={{padding:"12px 14px 8px",display:"flex",alignItems:"center",gap:10,zIndex:2}}>
        <button onClick={()=>{try{audio.sfxClick();}catch(e){}onNav("home");}} style={{background:"rgba(74,158,255,.1)",
          border:`1px solid ${C.blue}38`,borderRadius:8,padding:"5px 10px",color:C.blue,cursor:"pointer",fontSize:15}}>‹</button>
        <div style={{fontSize:10,color:C.white,fontWeight:900,letterSpacing:3,fontFamily:"'Orbitron',monospace"}}>{tUI("REPLAY",lang)}</div>
      </div>

      {/* Parties sauvegardées */}
      <div style={{padding:"0 14px 10px",zIndex:2}}>
        <div style={{fontSize:7.5,color:C.dim,letterSpacing:3,marginBottom:8,fontFamily:"'Orbitron',monospace"}}>{tUI("PARTIES RÉCENTES",lang)}</div>
        {[
          {opp:"NEBULA_X",result:"win",date:"Aujourd'hui",moves:24,pts:"+15"},
          {opp:"IA Maître",result:"loss",date:"Hier",moves:18,pts:"-8"},
          {opp:"STARFALL",result:"win",date:"Il y a 2j",moves:31,pts:"+15"},
        ].map((p,i)=>(
          <div key={i} onClick={()=>{try{audio.sfxClick();}catch(e){}setMoveIdx(0);setPlaying(false);}}
            style={{display:"flex",alignItems:"center",gap:10,padding:"9px 12px",marginBottom:6,
              background:i===0?"rgba(74,158,255,.12)":"rgba(10,18,35,.82)",
              border:`1px solid ${i===0?C.blue:"rgba(74,158,255,.1)"}`,borderRadius:9,cursor:"pointer"}}>
            <div style={{width:32,height:32,borderRadius:"50%",
              background:p.result==="win"?"rgba(0,255,136,.15)":"rgba(255,68,102,.15)",
              display:"flex",alignItems:"center",justifyContent:"center",fontSize:16}}>
              {p.result==="win"?"🏆":"💔"}
            </div>
            <div style={{flex:1}}>
              <div style={{fontSize:10,color:C.white,fontWeight:700}}>vs {p.opp}</div>
              <div style={{fontSize:7.5,color:C.dim,marginTop:1}}>{p.date} · {p.moves} coups</div>
            </div>
            <div style={{fontSize:11,fontWeight:700,color:p.result==="win"?C.green:C.red}}>{p.pts}</div>
          </div>
        ))}
      </div>

      {/* Viewer */}
      <div style={{flex:1,overflowY:"auto",padding:"0 14px 14px",zIndex:2}}>
        <div style={{fontSize:7.5,color:C.dim,letterSpacing:3,marginBottom:8,fontFamily:"'Orbitron',monospace"}}>
          LECTURE · Coup {moveIdx}/{DEMO_MOVES.length}
        </div>

        {/* Timeline */}
        <div style={{height:4,background:"rgba(74,158,255,.12)",borderRadius:2,marginBottom:12,position:"relative",cursor:"pointer"}}
          onClick={e=>{
            const rect=e.currentTarget.getBoundingClientRect();
            const pct=(e.clientX-rect.left)/rect.width;
            setMoveIdx(Math.round(pct*DEMO_MOVES.length));setPlaying(false);
          }}>
          <div style={{height:"100%",width:`${(moveIdx/DEMO_MOVES.length)*100}%`,
            background:`linear-gradient(90deg,${C.blue},${C.cyan})`,borderRadius:2,transition:"width .2s"}}/>
          <div style={{position:"absolute",top:-5,left:`${(moveIdx/DEMO_MOVES.length)*100}%`,
            transform:"translateX(-50%)",width:14,height:14,borderRadius:"50%",
            background:C.cyan,boxShadow:`0 0 8px ${C.cyan}`,transition:"left .2s"}}/>
        </div>

        {/* Contrôles */}
        <div style={{display:"flex",gap:8,justifyContent:"center",alignItems:"center",marginBottom:14}}>
          <button onClick={()=>{setMoveIdx(0);setPlaying(false);}} style={{padding:"6px 12px",
            background:"rgba(74,158,255,.1)",border:`1px solid ${C.blue}38`,borderRadius:8,
            color:C.blue,cursor:"pointer",fontSize:14}}>⏮</button>
          <button onClick={()=>setMoveIdx(i=>Math.max(0,i-1))} style={{padding:"6px 12px",
            background:"rgba(74,158,255,.1)",border:`1px solid ${C.blue}38`,borderRadius:8,
            color:C.blue,cursor:"pointer",fontSize:14}}>⏪</button>
          <button onClick={()=>setPlaying(p=>!p)} style={{padding:"8px 20px",
            background:playing?`rgba(255,68,102,.2)`:`linear-gradient(135deg,${C.blue},${C.cyan})`,
            border:`1px solid ${playing?C.red:C.cyan}`,borderRadius:10,
            color:playing?C.red:C.void,cursor:"pointer",fontSize:14,fontWeight:900}}>
            {playing?"⏸":"▶"}
          </button>
          <button onClick={()=>setMoveIdx(i=>Math.min(DEMO_MOVES.length,i+1))} style={{padding:"6px 12px",
            background:"rgba(74,158,255,.1)",border:`1px solid ${C.blue}38`,borderRadius:8,
            color:C.blue,cursor:"pointer",fontSize:14}}>⏩</button>
          <button onClick={()=>setMoveIdx(DEMO_MOVES.length)} style={{padding:"6px 12px",
            background:"rgba(74,158,255,.1)",border:`1px solid ${C.blue}38`,borderRadius:8,
            color:C.blue,cursor:"pointer",fontSize:14}}>⏭</button>
        </div>

        {/* Vitesse */}
        <div style={{display:"flex",gap:6,justifyContent:"center",marginBottom:14}}>
          <span style={{fontSize:8.5,color:C.dim,alignSelf:"center"}}>Vitesse:</span>
          {[0.5,1,2,3].map(s=>(
            <button key={s} onClick={()=>setSpeed(s)} style={{padding:"4px 10px",
              background:speed===s?"rgba(74,158,255,.2)":"rgba(10,18,35,.8)",
              border:`1px solid ${speed===s?C.blue:C.dim+"28"}`,borderRadius:6,
              color:speed===s?C.blue:C.dim,fontSize:9,cursor:"pointer",
              fontFamily:"'Orbitron',monospace",fontWeight:700}}>{s}x</button>
          ))}
        </div>

        {/* Log des coups */}
        <div style={{background:"rgba(4,6,18,.88)",border:`1px solid rgba(74,158,255,.1)`,
          borderRadius:8,padding:"8px 10px",maxHeight:140,overflowY:"auto"}}>
          {replayMoves.map((m,i)=>(
            <div key={i} style={{display:"flex",alignItems:"center",gap:8,padding:"3px 0",
              borderBottom:i<replayMoves.length-1?`1px solid rgba(74,158,255,.06)`:"none",
              animation:"sIn .2s ease",opacity:i===replayMoves.length-1?1:.65}}>
              <span style={{fontSize:7.5,color:C.dim,minWidth:20,fontFamily:"'Orbitron',monospace"}}>#{i+1}</span>
              <StarSVG type={m.type} color={m.color==="W"?C.white:C.blue} size={14} glow={false}/>
              <span style={{fontSize:9,color:m.color==="W"?C.white:C.blue,flex:1}}>
                {m.type}: {m.from}→{m.to}
                {m.capture&&<span style={{color:C.red}}> 💥capture</span>}
              </span>
            </div>
          ))}
          {replayMoves.length===0&&<div style={{fontSize:9,color:C.dim,textAlign:"center",padding:"10px 0"}}>Appuyez sur ▶ pour lancer</div>}
        </div>
      </div>
    </div>
  );
};

// ════════════════════════════════════════════════════════
// 🏟 TOURNOIS — Brackets & Ligues
// ════════════════════════════════════════════════════════
const TournamentScreen=({onNav,user,lang="fr"})=>{
  const[tab,setTab]=useState("weekly");
  const arena=getArena();
  // Inscription persistée à la semaine en cours
  const weekId=(typeof isoWeekId==="function")?isoWeekId():"wk";
  // Auto-inscription : on est toujours inscrit dès la connexion (voir DOSCOApp useEffect)
  const[joined,setJoined]=useState(()=>{try{return localStorage.getItem("dosco_tourn_join_v1")===weekId;}catch{return false;}});
  const[leagueJoined,setLeagueJoined]=useState(()=>{try{const d=JSON.parse(localStorage.getItem("dosco_league_join_v1")||"null");return !!d;}catch{return false;}});
  const[specialJoined,setSpecialJoined]=useState(()=>{try{const d=JSON.parse(localStorage.getItem("dosco_special_join_v1")||"null");return !!d;}catch{return false;}});
  // Forcer la synchro avec localStorage (en cas d'inscription auto faite dans DOSCOApp)
  useEffect(()=>{
    try{setJoined(localStorage.getItem("dosco_tourn_join_v1")===weekId);}catch(e){}
    try{setLeagueJoined(!!JSON.parse(localStorage.getItem("dosco_league_join_v1")||"null"));}catch(e){}
    try{setSpecialJoined(!!JSON.parse(localStorage.getItem("dosco_special_join_v1")||"null"));}catch(e){}
  },[weekId]);
  const join=()=>{
    try{localStorage.setItem("dosco_tourn_join_v1",weekId);}catch(e){}
    setJoined(true);try{audio.sfxConnect();}catch(e){}
    try{notifSystem.add({type:"tournament",title:"✦ Inscrit au Tournoi !",body:"Bonne chance ! ★500 en jeu.",ts:Date.now()});}catch(e){}
  };
  // Bracket à 8 : TOUS les joueurs inscrits (buildLeaderboard), triés par pts
  const allRegistered=(()=>{
    try{
      const lb=buildLeaderboard();
      // Garder seulement ceux inscrits au tournoi de la semaine
      const wk=(typeof isoWeekId==="function")?isoWeekId():"wk";
      // En l'absence de flag côté serveur, on prend les 8 meilleurs connus
      return lb.sort((a,b)=>b.pts-a.pts).slice(0,8);
    }catch(e){return [];}
  })();
  const slots=(()=>{
    const list=allRegistered.map(p=>({name:p.name,me:p.me,id:p.id,pts:p.pts}));
    while(list.length<8) list.push({name:"—",empty:true});
    return list;
  })();
  const QF=[[slots[0],slots[1]],[slots[2],slots[3]],[slots[4],slots[5]],[slots[6],slots[7]]];
  const timeLeft=timeUntilReset?timeUntilReset():"—";
  const needed=0; // Plus besoin d'ajouter manuellement

  return(
    <div style={{width:"100%",height:"100%",background:`linear-gradient(180deg,#060d1e,${C.void})`,
      display:"flex",flexDirection:"column",overflow:"hidden",fontFamily:"'Exo 2',sans-serif"}}>
      <Starfield count={55}/><Nebulas/>
      <div style={{padding:"12px 14px 8px",display:"flex",alignItems:"center",gap:10,zIndex:2}}>
        <button onClick={()=>{try{audio.sfxClick();}catch(e){}onNav("home");}} style={{background:"rgba(74,158,255,.1)",
          border:`1px solid ${C.blue}38`,borderRadius:8,padding:"5px 10px",color:C.blue,cursor:"pointer",fontSize:15}}>‹</button>
        <div style={{fontSize:10,color:C.white,fontWeight:900,letterSpacing:3,fontFamily:"'Orbitron',monospace"}}>{tUI("TOURNOIS",lang)}</div>
        <div style={{marginLeft:"auto",display:"flex",alignItems:"center",gap:5}}>
          <div style={{width:6,height:6,borderRadius:"50%",background:joined?C.green:C.dim,animation:joined?"pls 1s infinite":"none"}}/>
          <span style={{fontSize:7.5,color:joined?C.green:C.dim,letterSpacing:2}}>{joined?"INSCRIT":"OUVERT"}</span>
        </div>
      </div>

      {/* Tabs */}
      <div style={{display:"flex",margin:"0 14px 10px",gap:6,zIndex:2}}>
        {[["weekly","🏆 HEBDO",joined],["leagues","⚡ LIGUES",leagueJoined],["special","✨ SPÉCIAL",specialJoined]].map(([v,l,isJoined])=>(
          <button key={v} onClick={()=>{try{audio.sfxClick();}catch(e){}setTab(v);}} style={{flex:1,padding:"6px",
            borderRadius:8,cursor:"pointer",position:"relative",
            background:tab===v?"rgba(240,192,64,.18)":"rgba(10,18,35,.72)",
            border:`1px solid ${tab===v?C.gold:C.dim+"28"}`,
            color:tab===v?C.gold:C.dim,fontSize:8,fontWeight:700,letterSpacing:1.5,
            fontFamily:"'Orbitron',monospace"}}>
            {l}
            {isJoined&&<span style={{position:"absolute",top:3,right:5,width:6,height:6,
              borderRadius:"50%",background:C.green,boxShadow:`0 0 6px ${C.green}`,animation:"pls 1.5s infinite"}}/>}
          </button>
        ))}
      </div>

      <div style={{flex:1,overflowY:"auto",padding:"0 14px 14px",zIndex:2}}>
        {tab==="weekly"&&(
          <>
            {/* Infos tournoi */}
            <div style={{background:`linear-gradient(135deg,rgba(240,192,64,.12),rgba(240,192,64,.04))`,
              border:`1px solid ${C.gold}30`,borderRadius:12,padding:"12px 14px",marginBottom:14}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
                <div style={{fontSize:11,fontWeight:900,color:C.gold,fontFamily:"'Orbitron',monospace",letterSpacing:2}}>{tUI("TOURNOI STELLAIRE HEBDO",lang)}</div>
                <div style={{fontSize:8.5,color:C.dim}}>8 {tUI("joueurs",lang)}</div>
              </div>
              <div style={{display:"flex",gap:16,marginBottom:10}}>
                <div style={{textAlign:"center"}}>
                  <div style={{fontSize:9,color:C.dim,marginBottom:2}}>{tUI("Clôture",lang)}</div>
                  <div style={{fontSize:11,color:C.red,fontWeight:700,fontFamily:"'Orbitron',monospace"}}>{timeLeft}</div>
                </div>
                <div style={{textAlign:"center"}}>
                  <div style={{fontSize:9,color:C.dim,marginBottom:2}}>{tUI("Prix",lang)}</div>
                  <div style={{fontSize:11,color:C.gold,fontWeight:700,fontFamily:"'Orbitron',monospace"}}>★ 500</div>
                </div>
                <div style={{textAlign:"center"}}>
                  <div style={{fontSize:9,color:C.dim,marginBottom:2}}>{tUI("Statut",lang)}</div>
                  <div style={{fontSize:11,color:joined?C.green:C.dim,fontWeight:700,fontFamily:"'Orbitron',monospace"}}>{joined?tUI("INSCRIT",lang):"—"}</div>
                </div>
              </div>
              {!joined?(
                <button onClick={join} className="btn-c" style={{width:"100%",padding:"11px",borderRadius:10,
                  background:`linear-gradient(135deg,${C.gold},${C.orange})`,border:"none",color:C.void,
                  fontSize:11,fontWeight:900,letterSpacing:2,cursor:"pointer",fontFamily:"'Orbitron',monospace",
                  boxShadow:`0 0 16px ${C.gold}40`}}>🏆 {tUI("PARTICIPER",lang)}</button>
              ):(
                <div style={{fontSize:8.5,color:C.green,textAlign:"center",letterSpacing:1,fontFamily:"'Orbitron',monospace"}}>✓ {tUI("Vous êtes inscrit au tournoi de la semaine.",lang)}</div>
              )}

            </div>

            {/* Bracket réel basé sur la constellation */}
            <div style={{fontSize:7.5,color:C.dim,letterSpacing:3,marginBottom:10,fontFamily:"'Orbitron',monospace"}}>{tUI("BRACKET",lang)}</div>
            <div style={{display:"flex",gap:8,overflowX:"auto",paddingBottom:8}}>
              {[{label:tUI("QUARTS",lang),matches:QF},{label:tUI("DEMIS",lang),matches:[["?","?"],["?","?"]]},{label:tUI("FINALE",lang),matches:[["?","?"]]}].map((round,ri)=>(
                <div key={ri} style={{minWidth:120,flexShrink:0}}>
                  <div style={{fontSize:7,color:C.dim,letterSpacing:2,marginBottom:8,fontFamily:"'Orbitron',monospace",textAlign:"center"}}>{round.label}</div>
                  <div style={{display:"flex",flexDirection:"column",gap:ri===2?60:ri===1?30:0,justifyContent:"space-around",height:220}}>
                    {round.matches.map((m,mi)=>{
                      const p1=ri===0?m[0]:{name:m[0]},p2=ri===0?m[1]:{name:m[1]};
                      const isMine=ri===0&&(p1.me||p2.me);
                      const canPlay=joined&&isMine&&!p1.empty&&!p2.empty;
                      return(
                        <div key={mi} style={{background:isMine?"rgba(74,158,255,.12)":"rgba(10,18,35,.85)",
                          border:`1px solid ${isMine?C.blue:"rgba(74,158,255,.12)"}`,borderRadius:8,padding:"6px 8px",
                          boxShadow:isMine?`0 0 8px ${C.blue}20`:"none"}}>
                          {[p1,p2].map((p,pi)=>(
                            <div key={pi} style={{display:"flex",alignItems:"center",gap:5,padding:"3px 0",
                              borderBottom:pi===0?`1px solid rgba(74,158,255,.1)`:"none",opacity:p.empty?0.4:1}}>
                              <div style={{width:5,height:5,borderRadius:"50%",flexShrink:0,background:"rgba(74,158,255,.3)"}}/>
                              <span style={{fontSize:7.5,color:p.me?C.cyan:p.empty?C.dim:C.white,fontWeight:p.me?700:400,letterSpacing:.5,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis",maxWidth:65}}>{p.name||"?"}</span>
                              {!p.empty&&p.pts!==undefined&&<span style={{fontSize:6.5,color:C.gold,marginLeft:"auto",flexShrink:0}}>★{p.pts}</span>}
                            </div>
                          ))}
                          {canPlay&&(
                            <button onClick={()=>{try{audio.sfxClick();audio.sfxBattleStart();}catch(e){}onNav("online");}}
                              style={{width:"100%",marginTop:5,padding:"4px",background:`linear-gradient(135deg,${C.blue},${C.cyan})`,
                                border:"none",borderRadius:4,color:C.void,fontSize:7,fontWeight:900,cursor:"pointer",letterSpacing:1,fontFamily:"'Orbitron',monospace"}}>
                              ▶ {tUI("JOUER",lang)}
                            </button>
                          )}
                        </div>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>
          </>
        )}


        {tab==="leagues"&&(()=>{
          const s=getSeason();
          const myPts=s.pts||0;
          const LEAGUES=[
            {name:"Ligue Naine Blanche",color:C.white,min:0,max:499,icon:"⚪",players:1240,reward:"★50"},
            {name:"Ligue Naine Bleue",color:C.blue,min:500,max:999,icon:"🔵",players:876,reward:"★150"},
            {name:"Ligue Géant Rouge",color:"#ff6030",min:1000,max:1999,icon:"🔴",players:432,reward:"★300"},
            {name:"Ligue Supernova",color:"#ffd700",min:2000,max:4999,icon:"⭐",players:89,reward:"★750"},
            {name:"Ligue Trou Noir",color:C.purple,min:5000,max:null,icon:"⚫",players:12,reward:"★2000"},
          ];
          const currentIdx=LEAGUES.reduce((ci,l,i)=>myPts>=l.min&&(l.max===null||myPts<=l.max)?i:ci,0);
          return(
            <div>
              <div style={{fontSize:7.5,color:C.dim,letterSpacing:3,marginBottom:10,fontFamily:"'Orbitron',monospace"}}>{tUI("LIGUES STELLAIRES",lang)}</div>
              {leagueJoined&&(
                <div style={{display:"flex",alignItems:"center",gap:8,padding:"8px 12px",
                  background:"rgba(0,255,136,.06)",border:`1px solid ${C.green}30`,
                  borderRadius:10,marginBottom:10}}>
                  <span style={{width:7,height:7,borderRadius:"50%",background:C.green,
                    display:"inline-block",animation:"pls 1.2s infinite"}}/>
                  <span style={{fontSize:8.5,color:C.green,fontWeight:700,letterSpacing:1,
                    fontFamily:"'Orbitron',monospace"}}>{tUI("INSCRIT",lang)} — {LEAGUES[currentIdx].name}</span>
                </div>
              )}
              {LEAGUES.map((l,i)=>{
                const isCurrent=i===currentIdx;
                const nextLeague=LEAGUES[i+1];
                const ptsInLeague=myPts-l.min;
                const leagueSpan=(l.max??l.min+5000)-l.min;
                const pct=isCurrent?Math.min(100,Math.round(ptsInLeague/leagueSpan*100)):0;
                return(
                  <div key={i} style={{padding:"12px 14px",marginBottom:8,
                    background:isCurrent?`${l.color}12`:"rgba(10,18,35,.82)",
                    border:`1.5px solid ${isCurrent?l.color:l.color+"25"}`,borderRadius:12,
                    animation:`sUp .3s ease ${i*.06}s both`,
                    boxShadow:isCurrent?`0 0 14px ${l.color}28`:"none"}}>
                    <div style={{display:"flex",alignItems:"center",gap:10}}>
                      <span style={{fontSize:24}}>{l.icon}</span>
                      <div style={{flex:1}}>
                        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                          <div style={{fontSize:11,fontWeight:700,color:l.color,
                            fontFamily:"'Orbitron',monospace",letterSpacing:1}}>{l.name}</div>
                          {isCurrent&&<span style={{fontSize:7.5,color:C.green,fontWeight:700,
                            letterSpacing:1,fontFamily:"'Orbitron',monospace"}}>{tUI("VOTRE LIGUE",lang)}</span>}
                        </div>
                        <div style={{fontSize:8.5,color:C.dim,marginTop:2}}>
                          {l.min}–{l.max||"∞"} pts · {l.players} joueurs · Prix: <span style={{color:C.gold,fontWeight:700}}>{l.reward}</span>
                        </div>
                      </div>
                    </div>
                    {isCurrent&&(
                      <div style={{marginTop:8}}>
                        <div style={{display:"flex",justifyContent:"space-between",marginBottom:4}}>
                          <span style={{fontSize:7.5,color:C.dim}}>{myPts} pts</span>
                          {nextLeague&&<span style={{fontSize:7.5,color:l.color,fontWeight:700}}>
                            {nextLeague.min-myPts} pts pour {nextLeague.name}
                          </span>}
                        </div>
                        <div style={{height:4,background:`${l.color}20`,borderRadius:2}}>
                          <div style={{height:"100%",width:`${pct}%`,background:l.color,borderRadius:2,
                            transition:"width .6s ease",boxShadow:`0 0 8px ${l.color}`}}/>
                        </div>
                        <div style={{fontSize:7.5,color:C.dim,marginTop:3,textAlign:"right"}}>{pct}%</div>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          );
        })()}


        {tab==="special"&&(
          <div>
            <div style={{fontSize:7.5,color:C.dim,letterSpacing:3,marginBottom:10,fontFamily:"'Orbitron',monospace"}}>{tUI("ÉVÉNEMENTS SPÉCIAUX",lang)}</div>
            {[
              {name:"Nuit des Étoiles",icon:"🌙",desc:"Mode blitz — 5 min max",reward:"★1000 + Skin Lunaire",active:true,ends:"3j 8h"},
              {name:"Tournoi Solo",icon:"🎯",desc:"Solo round-robin 16 joueurs",reward:"★500",active:false,ends:"Bientôt"},
              {name:"Coupe DOSCO",icon:"🏆",desc:"Championnat mensuel",reward:"Titre Légendaire + ★5000",active:false,ends:"15 jours"},
            ].map((e,i)=>(
              <div key={i} style={{padding:"14px",marginBottom:10,
                background:e.active?"rgba(0,229,255,.06)":"rgba(10,18,35,.82)",
                border:`1.5px solid ${e.active?C.cyan:C.dim+"20"}`,borderRadius:12,
                opacity:e.active?1:0.65,animation:`sUp .35s ease ${i*.07}s both`}}>
                <div style={{display:"flex",alignItems:"flex-start",gap:12}}>
                  <span style={{fontSize:26,animation:e.active?"flt 3s ease-in-out infinite":"none"}}>{e.icon}</span>
                  <div style={{flex:1}}>
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:4}}>
                      <div style={{fontSize:11,fontWeight:700,color:e.active?C.cyan:C.white,
                        fontFamily:"'Orbitron',monospace",letterSpacing:1.5}}>{e.name}</div>
                      {e.active&&<span style={{fontSize:7.5,color:C.red,animation:"pls 1s infinite",letterSpacing:1}}>● LIVE</span>}
                    </div>
                    <div style={{fontSize:9,color:C.dim,marginBottom:6}}>{e.desc}</div>
                    <div style={{fontSize:8.5,color:C.gold,marginBottom:6}}>🎁 {e.reward}</div>
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                      <span style={{fontSize:8,color:C.dim}}>Fin dans: <span style={{color:e.active?C.red:C.dim,fontWeight:700}}>{e.ends}</span></span>
                      {e.active&&(()=>{
                        const spKey="dosco_special_join_v1";
                        let isJoined=false;
                        try{const d=JSON.parse(localStorage.getItem(spKey)||"null");isJoined=d&&d.id===e.id;}catch(err){}
                        return isJoined?(
                          <span style={{fontSize:7.5,color:C.green,fontWeight:700,letterSpacing:1,
                            fontFamily:"'Orbitron',monospace",display:"flex",alignItems:"center",gap:4}}>
                            <span style={{width:6,height:6,borderRadius:"50%",background:C.green,
                              display:"inline-block",animation:"pls 1.2s infinite"}}/>
                            {tUI("INSCRIT",lang)}
                          </span>
                        ):(
                          <button onClick={()=>{
                            try{audio.sfxConnect();}catch(err){}
                            try{
                              localStorage.setItem(spKey,JSON.stringify({id:e.id,ts:Date.now()}));
                              setSpecialJoined(true);
                              notifSystem&&notifSystem.add&&notifSystem.add({type:"special",
                                title:"Inscrit : "+e.name,
                                body:"Bonne chance ! "+e.reward+" à gagner.",ts:Date.now()});
                            }catch(err){}
                          }} className="btn-c"
                            style={{padding:"5px 12px",background:`linear-gradient(135deg,${C.cyan},${C.blue})`,
                              borderRadius:7,color:C.void,fontSize:8,fontWeight:900,letterSpacing:1.5,
                              fontFamily:"'Orbitron',monospace"}}>{tUI("PARTICIPER",lang)}</button>
                        );
                      })()}
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

// ════════════════════════════════════════════════════════
// 🎨 PERSONNALISATION — Skins & Thèmes
